INSERT OR REPLACE INTO `financial_insights` (`id`, `ticker`, `year`, `report_type`, `related_party_risk`, `debt_risk`, `inventory_risk`, `governance_risk_score`, `overall_analysis`) VALUES
('BID_2017_parent', 'BID', 2017, 'parent', 'Các giao dịch với cơ quan quản lý Nhà nước và các công ty con có giá trị lớn, chủ yếu là tiền gửi và vay vốn. Chưa thấy dấu hiệu bất thường hay rút ruột vốn. Các giao dịch này phù hợp với đặc thù của một ngân hàng thương mại nhà nước.', 'Nợ phải trả chiếm tỷ trọng lớn (hơn 96% tổng nguồn vốn), tập trung vào tiền gửi của khách hàng (71%). Nợ vay từ NHNN và phát hành giấy tờ có giá cũng ở mức cao. Áp lực trả nợ ngắn hạn lớn, cần theo dõi sát diễn biến lãi suất và thanh khoản.', 'Ngân hàng không có hàng tồn kho vật chất. Rủi ro chính liên quan đến tài sản có rủi ro tín dụng (cho vay khách hàng) và chứng khoán đầu tư. Tỷ lệ nợ xấu nội bảng ở mức 2,89% (theo thuyết minh số 11), đòi hỏi trích lập dự phòng lớn (hơn 10.400 tỷ đồng).', 3, 'BIDV là ngân hàng thương mại nhà nước lớn với mạng lưới rộng, hệ số an toàn vốn (CAR) đáp ứng quy định. Tuy nhiên, áp lực nợ ngắn hạn cao và chi phí dự phòng rủi ro tín dụng tăng mạnh là các yếu tố rủi ro. Cơ cấu cổ đông rõ ràng với đa số vốn Nhà nước và sự tham gia của các tổ chức nước ngoài (SMFG). Ý kiến kiểm toán sạch. Triển vọng ổn định nhưng cần cải thiện hiệu quả quản lý rủi ro tín dụng.'),
('BID_2016_consolidated', 'BID', 2016, 'consolidated', 'Các giao dịch với bên liên quan chủ yếu là với cơ quan quản lý Nhà nước và các công ty liên doanh/liên kết, tập trung vào nghiệp vụ tiền gửi và cho vay. Giá trị giao dịch lớn nhưng phản ánh mối quan hệ kinh doanh bình thường của ngân hàng với các chủ thể này. Không thấy dấu hiệu bất thường hay chuyển giá.', 'Nợ phải trả chiếm tỷ trọng rất cao trong tổng nguồn vốn (95.6%), đặc thù của ngành ngân hàng. Áp lực thanh toán ngắn hạn lớn do phần lớn tiền gửi của khách hàng và TCTD là không kỳ hạn hoặc ngắn hạn. Tuy nhiên, ngân hàng duy trì tỷ lệ dự phòng và thanh khoản ở mức an toàn theo quy định.', 'Ngân hàng không có hàng tồn kho vật lý. Khoản mục chi phí xây dựng cơ bản dở dang liên quan đến đầu tư tài sản cố định, giá trị không lớn so với tổng tài sản và không có trích lập dự phòng, rủi ro thấp.', 5, 'BIDV là ngân hàng thương mại nhà nước lớn, có mạng lưới rộng và tăng trưởng tín dụng mạnh trong năm 2016. Lợi nhuận ổn định nhưng nợ phải trả rất lớn so với vốn chủ sở hữu, đặc trưng ngành. Cơ cấu cổ đông rõ ràng với vốn nhà nước chi phối. Hoạt động kinh doanh đa dạng nhưng tập trung vào tín dụng truyền thống. Cần theo dõi sát tỷ lệ nợ xấu có xu hướng tăng và quản lý rủi ro thanh khoản trong bối cảnh tăng trưởng nhanh.'),
('BID_2019_parent', 'BID', 2019, 'parent', 'Giao dịch với các bên liên quan chủ yếu là hoạt động ngân hàng thông thường: tiền gửi, cho vay, vay vốn. Cơ quan quản lý Nhà nước là chủ sở hữu lớn nhất (80.99% vốn điều lệ) và cũng là bên cho vay, gửi tiền lớn. Các giao dịch với cổ đông chiến lược KEB Hana Bank quy mô nhỏ. Không phát hiện dấu hiệu bất thường rõ ràng, nhưng cần lưu ý sự tập trung giao dịch với cơ quan quản lý Nhà nước.', 'Nợ phải trả lớn (1,378,962,181 triệu VND), chủ yếu từ tiền gửi khách hàng (1,094,708,437 triệu VND) chiếm tỷ trọng cao. Nợ vay từ Chính phủ/NHNN và phát hành giấy tờ có giá cũng ở mức đáng kể. Tỷ lệ nợ/Vốn chủ sở hữu khoảng 18.98 lần, đặc trưng cho ngân hàng thương mại. Áp lực trả nợ ngắn hạn lớn nhưng được hỗ trợ bởi mạng lưới huy động vốn rộng rãi.', 'Ngân hàng không có hàng tồn kho vật lý như doanh nghiệp sản xuất. Chi phí xây dựng cơ bản dở dang (2,171,050 triệu VND) chủ yếu liên quan đến đầu tư cơ sở hạ tầng ngân hàng, không phải dự án bất động sản thương mại. Rủi ro đọng vốn thấp.', 4, 'BIDV là ngân hàng thương mại Nhà nước lớn nhất Việt Nam với mạng lưới rộng khắp. Ý kiến kiểm toán chấp nhận toàn phần, không có vấn đề về hoạt động liên tục. Cơ cấu tài sản nợ ổn định với nguồn vốn huy động chủ yếu từ tiền gửi khách hàng. Tuy nhiên, tỷ lệ nợ xấu (1.66% theo nhóm 3-5) vẫn cần được kiểm soát. Ban lãnh đạo nhất quán, công tác quản trị rủi ro được thiết lập theo mô hình 3 tuyến bảo vệ. Triển vọng đầu tư ổn định do quy mô lớn và vị thế thị trường.'),
('BID_2016_parent', 'BID', 2016, 'parent', 'Ngân hàng có quan hệ giao dịch rộng rãi với các cơ quan quản lý Nhà nước (NHNN, Kho bạc, Bộ Tài chính) và hệ sinh thái công ty con/liên doanh/liên kết. Các giao dịch chủ yếu bao gồm tiền gửi, cho vay và các cam kết tín dụng, phản ánh bản chất hoạt động của một ngân hàng thương mại lớn có vốn Nhà nước. Tuy nhiên, quy mô các giao dịch này là rất lớn (hàng trăm nghìn tỷ đồng), đòi hỏi sự giám sát chặt chẽ để đảm bảo tính minh bạch và tránh xung đột lợi ích.', 'Tổng nợ phải trả lên tới 954.870 tỷ VNĐ, gấp 22,8 lần vốn chủ sở hữu, phản ánh đòn bẩy tài chính rất cao đặc trưng của ngành ngân hàng. Nguồn vốn huy động chủ yếu từ tiền gửi của khách hàng (chiếm 75,8%). Ngân hàng cũng phát hành nợ lớn qua chứng chỉ tiền gửi và trái phiếu. Áp lực về chi phí lãi vay là đáng kể khi tổng thu nhập lãi thuần đạt 22.609 tỷ nhưng chi phí dự phòng tín dụng lên tới 8.883 tỷ. Tuy nhiên, tài sản thế chấp được báo cáo có giá trị lớn (gần 946.178 tỷ) phần nào giảm thiểu rủi ro.', 'Đối với ngân hàng, ''hàng tồn kho'' tương đương với các khoản cho vay và chứng khoán đầu tư. Ngân hàng có tỷ lệ nợ xấu (nhóm 3-5) trên tổng dư nợ cho vay là 1,87%, ở mức trung bình trong ngành. Dự phòng rủi ro tín dụng cụ thể đạt 4.292 tỷ VNĐ. Phần lớn tài sản là các khoản cho vay khách hàng có tính thanh khoản thấp hơn tiền mặt và chứng khoán. Việc phân bổ danh mục cho vay theo ngành (bán buôn, công nghiệp chế biến, xây dựng...) cho thấy sự phân tán tương đối, nhưng vẫn cần theo dõi sát diễn biến kinh tế vĩ mô.', 5, 'BIDV là ngân hàng thương mại Nhà nước lớn với mạng lưới rộng, tổng tài sản gần 1 triệu tỷ đồng. Sức khỏe tài chính thể hiện qua: Tăng trưởng tín dụng mạnh (18,9%), lợi nhuận sau thuế đạt 6.072 tỷ, tỷ lệ an toàn vốn đảm bảo. Tuy nhiên, rủi ro lớn nằm ở đòn bẩy tài chính cao, áp lực nợ xấu và dự phòng, cũng như sự phức tạp trong quản lý hệ sinh thái công ty con/liên doanh. Kiểm toán viên Deloitte đã đưa ra ý kiến chấp nhận toàn phần, nhưng nhà đầu tư cần lưu ý đến quy mô khổng lồ của các giao dịch với bên liên quan và mức độ tập trung vào hoạt động truyền thống.'),
('BID_2015_consolidated', 'BID', 2015, 'consolidated', 'Giao dịch với bên liên quan bao gồm Cơ quan quản lý Nhà nước, các công ty liên doanh và liên kết với giá trị lớn, chủ yếu là tiền gửi, vay và đầu tư. Có chuyển nhượng vốn tại VID Public cho đối tác nước ngoài. Lỗ lũy kế từ MHB khi sáp nhập cũng được ghi nhận. Giao dịch thuộc hoạt động ngân hàng thông thường nhưng cần giám sát chặt chẽ.', 'Nợ vay lớn, chủ yếu đến từ tiền gửi của khách hàng (564,583,061 triệu VNĐ) và phát hành giấy tờ có giá (65,542,240 triệu VNĐ). Áp lực thanh toán ngắn hạn cao theo phân tích thời gian đáo hạn. Tuy nhiên, ngân hàng duy trì tài sản thanh khoản cao. Tài sản thế chấp chủ yếu là bất động sản và động sản.', 'Ngân hàng không có hàng tồn kho truyền thống. Chi phí xây dựng cơ bản dở dang (1,927,546 triệu VNĐ) là đầu tư vào cơ sở hạ tầng ngân hàng, không phải hàng hóa kinh doanh. Rủi ro đọng vốn thấp.', 5, 'BIDV là ngân hàng lớn với mạng lưới rộng, tăng trưởng mạnh về quy mô sau sáp nhập MHB. Lợi nhuận tăng trưởng tốt (6,298,081 triệu VNĐ lợi nhuận thuần). Tuy nhiên, nợ xấu tăng (tỷ lệ nợ xấu 1.68%) và trích lập dự phòng lớn. Ngân hàng đang trong quá trình triển khai Basel II/III để nâng cao quản trị rủi ro. Triển vọng trung hạn tích cực nhưng cần theo dõi sát diễn biến nợ xấu và hiệu quả sáp nhập.'),
('BID_2015_parent', 'BID', 2015, 'parent', 'Có nhiều giao dịch với bên liên quan bao gồm cơ quan quản lý Nhà nước, các công ty con, liên doanh, liên kết. Các giao dịch chủ yếu là tiền gửi, cho vay, mua bán trái phiếu BIDV và thanh toán nội bộ. Giá trị giao dịch lớn nhưng thuộc hoạt động ngân hàng thông thường. Tuy nhiên, cần theo dõi rủi ro tập trung tín dụng và thanh khoản khi giao dịch nhiều với nhóm bên liên quan.', 'Nợ phải trả chiếm tỷ lệ rất cao trên tổng tài sản (tỷ lệ nợ/VCSH ~20 lần). Nợ vay chủ yếu từ Ngân hàng Nhà nước, phát hành giấy tờ có giá và tiền gửi khách hàng. Áp lực trả nợ ngắn hạn lớn do phần lớn nợ là ngắn hạn. Lãi suất vay không được thuyết minh chi tiết trong báo cáo này. Cần đánh giá khả năng đáp ứng các tỷ lệ an toàn vốn và thanh khoản theo quy định của NHNN.', 'Không có hàng tồn kho vật lý truyền thống. Chi phí xây dựng cơ bản dở dang (1,927 tỷ VNĐ) là khoản đầu tư cho cơ sở hạ tầng, chiếm tỷ trọng nhỏ trên tổng tài sản. Rủi ro đọng vốn thấp.', 4, 'BIDV là ngân hàng thương mại Nhà nước lớn, có mạng lưới rộng khắp. Báo cáo tài chính được kiểm toán chấp nhận toàn phần. Tuy nhiên, cơ cấu tài sản nợ mất cân đối với tỷ lệ nợ/VCSH cao, áp lực thanh khoản ngắn hạn lớn. Hoạt động kinh doanh chính (cho vay, huy động vốn) tăng trưởng mạnh nhưng chất lượng tín dụng cần được theo dõi (tỷ lệ nợ xấu ~1.61%). Dự phòng rủi ro tín dụng ở mức trung bình (tỷ lệ dự phòng/nợ xấu ~74%). Ngân hàng đang trong quá trình triển khai Basel II, quản trị rủi ro đang được cải thiện.'),
('ACB_2025_consolidated', 'ACB', 2025, 'consolidated', 'Giao dịch với các bên liên quan chủ yếu là thù lao ban lãnh đạo (HĐQT: 39,517 triệu VND, BKS: 10,451 triệu VND, BTGĐ: 94,359 triệu VND trong năm 2025) và các nghiệp vụ cho vay/tiền gửi/giấy tờ có giá với bên liên quan khác có quy mô tương đối nhỏ. Số dư cho vay bên liên quan cuối năm 399,801 triệu VND, tiền gửi của bên liên quan 1,130,927 triệu VND - chiếm tỷ trọng rất nhỏ trên tổng tài sản 1,025,850 tỷ VND. Thu nhập lãi từ cho vay bên liên quan 23,267 triệu VND và phí trả cho bên liên quan 26,508 triệu VND. Chưa phát hiện dấu hiệu bất thường hay chuyển giá đáng ngờ. Rủi ro bên liên quan ở mức thấp.', 'Tổng nợ phải trả đạt 931,330 tỷ VND, tăng 19.3% so với năm trước. Nợ vay tập trung vào tiền gửi khách hàng (585,180 tỷ VND - chiếm 62.8%), phát hành giấy tờ có giá (133,294 tỷ VND - trái phiếu và chứng chỉ tiền gửi kỳ hạn đa dạng từ dưới 1 năm đến 10 năm), và vay/tiền gửi TCTD khác (155,000 tỷ VND). Lãi suất vay TCTD từ 3.95%-8.60%/năm, lãi suất tiền gửi khách hàng từ 0%-9.50%/năm (VND). Tỷ lệ nợ/Vốn chủ sở hữu là 9.85 lần - đặc trưng cho ngành ngân hàng. Tài sản thế chấp cho các khoản vay bao gồm chứng khoán Chính phủ, tiền gửi có kỳ hạn tại TCTD khác và chứng khoán kinh doanh. Áp lực trả nợ ngắn hạn ở mức quản lý được nhờ hệ số thanh khoản tốt.', 'Là ngân hàng thương mại, ACB không có hàng tồn kho theo nghĩa truyền thống. Các khoản xây dựng cơ bản dở dang (806,530 triệu VND, giảm từ 740,684 triệu) chủ yếu là đầu tư mua sắm, xây dựng trụ sở và văn phòng. Trong năm, đã chuyển 235,497 triệu sang TSCĐ hữu hình, 122,430 triệu sang TSCĐ vô hình và 87,382 triệu sang bất động sản đầu tư, cho thấy tiến độ triển khai dự án đúng kế hoạch. Rủi ro đọng vốn thấp do chủ yếu phục vụ hoạt động kinh doanh cốt lõi của ngân hàng.', 4, 'Ngân hàng TMCP Á Châu (ACB) có kết quả kinh doanh năm 2025 với lợi nhuận trước thuế 19,539 tỷ VND (giảm 7% so với năm trước do chi phí dự phòng rủi ro tín dụng tăng mạnh 108% lên 3,335 tỷ VND). Thu nhập lãi thuần đạt 26,906 tỷ VND, giảm 3.2% do chi phí lãi tăng nhanh hơn thu nhập lãi (chi phí lãi +37.8% vs thu nhập lãi +15.4%), phản ánh môi trường lãi suất cạnh tranh. Chất lượng tín dụng cải thiện đáng kể: nợ xấu (nhóm 3-4-5) giảm từ 9,650 triệu xuống 6,671 triệu VND, tỷ lệ nợ xấu giảm từ 1.66% xuống 0.97%. Dự phòng bao phủ nợ xấu đạt 114.3%. Tỷ lệ CASA đạt 22.3%, NIM đạt 2.75%. Tổng tài sản tăng 18.7% lên 1,025,850 tỷ VND, vốn chủ sở hữu đạt 94,520 tỷ VND. Hoạt động ngân hàng lõi ổn định, hệ thống quản trị minh bạch với ý kiến kiểm toán chấp nhận toàn phần từ KPMG, cơ cấu cổ đông rõ ràng. Triển vọng trung hạn tích cực nhờ nền tảng tài chính vững chắc và mạng lưới rộng khắp.'),
('ACB_2025_parent', 'ACB', 2025, 'parent', 'Ngân hàng có các giao dịch đáng kể với công ty con (ACBS - Chứng khoán ACB, ACBA - Quản lý nợ, ACBL - Cho thuê tài chính) bao gồm cho vay 2.464.915 triệu VND, nhận tiền gửi 3.020.754 triệu VND, phát hành giấy tờ có giá 30.333 triệu VND và góp vốn 4.500.000 triệu VND. Ngoài ra, các bên liên quan (ban lãnh đạo, người thân) có khoản cho vay 399.604 triệu VND và tiền gửi 1.130.927 triệu VND. Các giao dịch này chủ yếu phục vụ hoạt động kinh doanh cốt lõi (cho vay, nhận tiền gửi, phát hành giấy tờ có giá) và chưa phát hiện dấu hiệu rút ruột hay chuyển giá bất thường. Thù lao ban lãnh đạo ở mức hợp lý (HĐQT: 39.517 triệu VND, Ban KST: 10.451 triệu VND, Ban TGĐ: 94.359 triệu VND).', 'Nợ phải trả tập trung vào tiền gửi khách hàng (587.874.763 triệu VND - 64,6% tổng nợ), phát hành giấy tờ có giá (133.122.924 triệu VND - 14,6%), tiền gửi và vay TCTD khác (131.528.577 triệu VND - 14,5%). Áp lực trả nợ ngắn hạn lớn do phần lớn tiền gửi khách hàng có kỳ hạn dưới 12 tháng. Nợ vay NHNN tăng mạnh từ 7.954.853 triệu VND lên 32.976.139 triệu VND, được đảm bảo bằng chứng khoán Chính phủ. Tỷ lệ nợ/vốn chủ sở hữu đạt 9,99 lần (909.444.203/91.005.607) - mức cao đặc thù ngân hàng thương mại. Lãi suất phát hành giấy tờ có giá dao động từ 4,80%/năm đến 8,50%/năm tùy kỳ hạn.', 'Ngân hàng không có hàng tồn kho theo nghĩa truyền thống. Xây dựng cơ bản dở dang đạt 777.987 triệu VND (tăng 38.317 triệu VND so với đầu năm), chủ yếu là chi phí mua sắm, xây dựng trụ sở văn phòng (615.999 triệu VND). Trong năm đã chuyển 235.497 triệu VND sang TSCĐ hữu hình và 116.055 triệu VND sang TSCĐ vô hình, cho thấy tiến độ triển khai dự án ổn định. Tuy nhiên, rủi ro tài sản tín dụng đáng quan ngại hơn với nợ xấu nhóm 3-4-5 đạt 6.606.186 triệu VND (0,99% dư nợ cho vay), tỷ lệ dự phòng cụ thể so với nợ xấu đạt 82,1%.', 3, 'Ngân hàng ACB có tình hình tài chính lành mạnh với tổng tài sản 1.000.449.810 triệu VND, tăng 18,2% so với năm trước. Lợi nhuận sau thuế đạt 14.519.368 triệu VND (giảm 9,7% do tăng trích lập dự phòng rủi ro tín dụng). Chất lượng tín dụng tốt với nợ xấu (nhóm 3-5) chỉ chiếm 0,99% dư nợ cho vay, thấp hơn nhiều so với mức trung bình ngành. Tỷ lệ dự phòng/tổng nợ xấu đạt 82,1% - mức an toàn. Kiểm toán viên KPMG đưa ra ý kiến chấp nhận toàn phần, không nhấn mạnh vấn đề hoạt động liên tục. Ban lãnh đạo ổn định với Chủ tịch Trần Hùng Huy và Tổng Giám đốc Từ Tiến Phát. Tuy nhiên, nợ ngắn hạn chiếm tỷ trọng lớn đặt áp lực quản lý thanh khoản liên tục.'),
('ACB_2024_consolidated', 'ACB', 2024, 'consolidated', 'Các giao dịch với bên liên quan (cho vay 365.541 triệu VND, tiền gửi 781.589 triệu VND) có quy mô nhỏ so với tổng tài sản 864.005.703 triệu VND (< 0,15%). Các giao dịch này bao gồm cho vay và nhận tiền gửi từ nhân sự quản lý chủ chốt và người thân, doanh nghiệp liên quan. Thù lao ban lãnh đạo được công khai minh bạch (HĐQT 39.605 triệu VND, Ban Tổng Giám đốc 73.483 triệu VND trong năm 2024). Không phát hiện dấu hiệu bất thường hay chuyển giá trong giao dịch với bên liên quan. Tuy nhiên, cần lưu ý tổng dư nợ cho vay bên liên quan tăng từ 280.330 triệu VND lên 365.541 triệu VND (tăng 30,4%).', 'Tổng nợ phải trả 780.544.025 triệu VND, tỷ lệ nợ/VCSH đạt 9,35 lần - đặc thù cao của ngân hàng thương mại. Nợ ngắn hạn chiếm phần lớn chủ yếu từ tiền gửi khách hàng (537.304.578 triệu VND). Nợ vay từ NHNN tăng mạnh từ 88 triệu VND lên 7.954.853 triệu VND do vay cầm cố giấy tờ có giá. Phát hành giấy tờ có giá tăng gần gấp đôi từ 52.410.014 lên 101.650.446 triệu VND, phản ánh chiến lược đa dạng hóa nguồn vốn. Lãi suất tiền gửi khách hàng dao động 0-10%/năm, lãi suất phát hành giấy tờ có giá 4,10-8,50%/năm. Chi phí lãi giảm từ 27.387.226 xuống 23.108.047 triệu VND cho thấy quản lý chi phí vốn hiệu quả. Dư nợ vay các TCTD khác được đảm bảo bằng tiền gửi có kỳ hạn (20.265.500 triệu VND), chứng khoán đầu tư (3.165.407 triệu VND) và TSCĐ (29.010 triệu VND).', 'Ngân hàng không có hàng tồn kho theo nghĩa thông thường. Xây dựng cơ bản dở dang trị giá 740.684 triệu VND (chủ yếu mua sắm, xây dựng trụ sở văn phòng) đã giảm đáng kể so với đầu năm (1.174.974 triệu VND), với phần lớn chi phí đã được chuyển giao sang TSCĐ (305.764 triệu VND hữu hình + 674.338 triệu VND vô hình). Tiến độ triển khai dự án xây dựng ổn định, không có dấu hiệu đình trệ hay đọng vốn kéo dài. Rủi ro đọng vốn ở mức thấp.', 3, 'Ngân hàng TMCP Á Châu (ACB) có kết quả kinh doanh năm 2024 tích cực với lợi nhuận trước thuế 21.005.871 triệu VND (tăng 4,7% so với năm trước) và lợi nhuận sau thuế 16.789.768 triệu VND (tăng 4,6%). Tổng tài sản đạt 864.005.703 triệu VND, tăng 20,2% so với năm trước. Thu nhập lãi thuần 27.794.702 triệu VND tăng 11,4% trong bối cảnh chi phí lãi giảm 15,6%, cho thấy biên lợi nhuận cải thiện. Tỷ lệ nợ xấu (nhóm 3-5) ở mức 1,49% trên tổng dư nợ cho vay, thuộc nhóm kiểm soát tốt. Dự phòng bao phủ nợ xấu đạt khoảng 78%. Tỷ lệ an toàn vốn đảm bảo với vốn điều lệ 44.666.579 triệu VND, VCSH 83.461.678 triệu VND. Hệ thống quản trị rủi ro được xây dựng bài bản theo Basel III với mô hình ba tuyến bảo vệ. Kiểm toán độc lập KPMG đưa ra ý kiến chấp nhận toàn phần. Triển vọng đầu tư trung hạn khả quan.'),
('ACB_2024_parent', 'ACB', 2024, 'parent', 'Ngân hàng có quan hệ giao dịch với 4 công ty con (ACBS - Chứng khoán, ACBA - Quản lý nợ, ACBL - Cho thuê tài chính, ACBC - Quản lý quỹ). Các khoản cho vay công ty con đạt 1.065.853 triệu VND và tiền gửi của công ty con là 2.131.412 triệu VND. Góp vốn vào công ty con đạt 7.505.000 triệu VND, trong đó ACBS chiếm 7.000.000 triệu VND. Các giao dịch chủ yếu mang tính nghiệp vụ ngân hàng - chứng khoán thông thường. Thù lao Hội đồng Quản trị năm 2024 là 39.605 triệu VND, Ban Tổng Giám đốc 73.483 triệu VND. Chưa thấy dấu hiệu bất thường hay rút vốn bất hợp lý.', 'Tổng nợ phải trả 765.378.508 triệu VND so với vốn chủ sở hữu 81.052.897 triệu VND (tỷ lệ nợ/VCSH ~9.4 lần), đặc trưng cho mô hình ngân hàng thương mại. Nợ vay chủ yếu từ tiền gửi khách hàng (539.139.747 triệu VND), phát hành giấy tờ có giá (101.648.155 triệu VND) và tiền gửi TCTD khác (91.621.806 triệu VND). Vay NHNN phát sinh mới 7.948.357 triệu VND. Nợ có tài sản bảo đảm gồm chứng khoán Chính phủ và tiền gửi có kỳ hạn tại TCTD khác. Cơ cấu nợ tập trung vào ngắn hạn, áp lực trả nợ lớn nhưng được bù đắp bởi tài sản lưu động cao.', 'Ngân hàng không có hàng tồn kho theo nghĩa truyền thống. Xây dựng cơ bản dở dang 739.670 triệu VND chủ yếu là dự án xây dựng trụ sở/văn phòng, giảm so với đầu năm do đã chuyển giao một phần sang TSCĐ. Giá trị nhỏ so với tổng tài sản, rủi ro đọng vốn thấp.', 3, 'Ngân hàng TMCP Á Châu (ACB) có tình hình tài chính lành mạnh với tổng tài sản 846.431 tỷ VND, lợi nhuận sau thuế 16.085 tỷ VND. Tỷ lệ nợ xấu (nhóm 3-5) chỉ 1.47% trên tổng dư nợ cho vay, mức thấp trong ngành. Dự phòng rủi ro tín dụng đạt 6.587 tỷ VND, tỷ lệ bao phủ nợ xấu ~76%. NIM đạt ~3.45%, thu nhập dịch vụ tăng trưởng tốt. Kiểm toán viên KPMG đưa ra ý kiến chấp nhận toàn phần, không có vấn đề về going concern. Ban lãnh đạo nhất quán, cơ cấu cổ đông minh bạch. Triển vọng đầu tư trung hạn tích cực.');
INSERT OR REPLACE INTO `financial_insights` (`id`, `ticker`, `year`, `report_type`, `related_party_risk`, `debt_risk`, `inventory_risk`, `governance_risk_score`, `overall_analysis`) VALUES
('ACB_2023_consolidated', 'ACB', 2023, 'consolidated', 'Giao dịch với các bên liên quan chủ yếu là nhân sự quản lý chủ chốt và người thân với quy mô tương đối lớn (cho vay 280 tỷ, tiền gửi 725 tỷ). Các giao dịch này được thực hiện theo quy định nội bộ nhưng cần theo dõi chặt chẽ để tránh xung đột lợi ích.', 'Nợ vay tập trung chủ yếu tại các tổ chức tín dụng khác và phát hành giấy tờ có giá. Tỷ lệ nợ/VCSH ở mức 9,1 lần (647.838/70.955), áp lực trả nợ lớn. Nợ vay phát hành giấy tờ có giá chiếm tỷ trọng lớn với lãi suất từ 3,09% - 9,50%/năm.', 'Dự án xây dựng dở dang 1.174 tỷ VND chủ yếu là xây dựng trụ sở văn phòng, tiến độ triển khai ổn định. Bất động sản đầu tư 177 tỷ VND chờ tăng giá, không có dự phòng giảm giá.', 5, 'Ngân hàng ACB có kết quả kinh doanh tăng trưởng tốt với lợi nhuận trước thuế 20.068 tỷ VND, tăng 17,3% so với năm trước. Dư nợ cho vay khách hàng tăng 18,5% đạt 487.601 tỷ VND. Tuy nhiên, tỷ lệ nợ xấu tăng từ 0,83% lên 1,21%, nợ nhóm 5 tăng mạnh 80%. Ngân hàng thực hiện tốt việc trích lập dự phòng rủi ro tín dụng. Cơ cấu vốn chủ sở hữu 70.955 tỷ VND, vốn điều lệ 38.840 tỷ VND. Ngân hàng được kiểm toán bởi KPMG với ý kiến chấp nhận toàn phần, không có vấn đề về hoạt động liên tục.'),
('ACB_2022_consolidated', 'ACB', 2022, 'consolidated', 'Giao dịch với các bên liên quan ở mức độ vừa phải và minh bạch. Dư nợ cho vay bên liên quan cuối năm 2022 là 217.361 triệu VND (tăng từ 98.580 triệu VND năm 2021), tiền gửi của bên liên quan là 812.726 triệu VND (giảm từ 1.084.890 triệu VND). Thu nhập lãi từ cho vay bên liên quan chỉ 10.485 triệu VND. Thù lao trả cho HĐQT, Ban Kiểm soát và Ban Tổng Giám đốc ở mức hợp lý (tổng 101.495 triệu VND). Chưa phát hiện dấu hiệu rút vốn hay chuyển giá bất thường.', 'Ngân hàng có cơ cấu huy động vốn đa dạng với tổng nợ phải trả 549.436.522 triệu VND, chiếm 90,4% tổng nguồn vốn. Tiền gửi của khách hàng là nguồn vốn chủ lực (413.952.789 triệu VND, chiếm 75,3% nợ phải trả). Ngân hàng đã phát hành trái phiếu trị giá 44.304.367 triệu VND với đa dạng kỳ hạn (1-10 năm). Tỷ lệ nợ/vốn chủ sở hữu là 9,4 lần - đặc thù của ngân hàng thương mại. Nợ vay NHNN chỉ 505.876 triệu VND (vay cầm cố giấy tờ có giá). Áp lực thanh toán ngắn hạn ở mức kiểm soát tốt với tỷ lệ vốn ngắn hạn cho vay trung dài hạn tuân thủ quy định NHNN.', 'Ngân hàng không có hàng tồn kho theo nghĩa truyền thống. Chi phí xây dựng cơ bản dở dang 584.626 triệu VND (chủ yếu cho dự án trụ sở văn phòng) không phải là tài sản tạo rủi ro đọng vốn lớn so với tổng tài sản 607.875.185 triệu VND. Xây dựng cơ bản dở dang tăng từ 479.547 triệu VND lên 584.626 triệu VND trong năm nhưng đã có chuyển sang TSCĐ 122.896 triệu VND, cho thấy dự án đang được triển khai đúng tiến độ.', 3, 'ACB là một trong những ngân hàng thương mại cổ phần hàng đầu tại Việt Nam với tổng tài sản hợp nhất 607.875.185 triệu VND (tăng 15,2% so với năm trước). Lợi nhuận sau thuế đạt 13.688.193 triệu VND (tăng 42,5%), EPS đạt 4.008 VND/cổ phiếu. Chất lượng tín dụng ở mức tốt với nợ nhóm 3-4-5 chỉ chiếm 0,74% tổng dư nợ. Dự phòng rủi ro tín dụng đạt 4.849.736 triệu VND, bao phủ 159,3% nợ xấu. Thu nhập lãi thuần đạt 23.533.529 triệu VND (tăng 24,2%). Kiểm toán viên KPMG đưa ra ý kiến chấp nhận toàn phần, không có vấn đề về hoạt động liên tục. Cơ cấu quản trị rõ ràng với sự thay đổi nhân sự cấp cao trong năm 2022 nhưng vẫn đảm bảo tính liên tục. Triển vọng đầu tư tích cực.'),
('ACB_2022_parent', 'ACB', 2022, 'parent', 'Các giao dịch với bên liên quan chủ yếu là cho vay và tiền gửi với công ty con và nhân sự quản lý, quy mô lớn nhưng thuộc hoạt động kinh doanh thông thường. Chưa thấy dấu hiệu bất thường như chuyển giá hay rút ruột.', 'Nợ vay chủ yếu từ tiền gửi khách hàng và phát hành giấy tờ có giá. Áp lực thanh khoản ngắn hạn cao do tỷ lệ nợ ngắn hạn lớn. Lãi suất vay ở mức hợp lý, tài sản thế chấp chủ yếu là chứng khoán đầu tư và tiền gửi có kỳ hạn.', 'Ngân hàng không có hàng tồn kho truyền thống. Các khoản đầu tư chứng khoán có thanh khoản tốt và xây dựng cơ bản dở dang có tiến độ ổn định, rủi ro đọng vốn thấp.', 4, 'Ngân hàng có tình hình tài chính ổn định, tăng trưởng tín dụng mạnh, lợi nhuận cao. Tuy nhiên, cần theo dõi rủi ro thanh khoản do phụ thuộc vào tiền gửi ngắn hạn và chất lượng tài sản với tỷ lệ nợ xấu thấp. Quản trị minh bạch và ý kiến kiểm toán chấp nhận toàn phần.'),
('ACB_2021_consolidated', 'ACB', 2021, 'consolidated', 'Giao dịch với các bên liên quan bao gồm cho vay, nhận tiền gửi và phát hành giấy tờ có giá cho nhân sự quản lý chủ chốt và người liên quan. Số dư cho vay các bên liên quan cuối năm đạt 98,580 triệu VND, tiền gửi từ bên liên quan đạt 1,084,890 triệu VND. Ngân hàng có 4 công ty con sở hữu 100% (ACBS, ACBA, ACBL, ACBC). Thu nhập của Ban Tổng Giám đốc 57,943 triệu VND, thù lao HĐQT 20,708 triệu VND, Ban Kiểm soát 6,756 triệu VND. Khoản phải thu từ nhóm sáu công ty liên quan đến nguyên Chủ tịch/Thành viên HĐQT là 131,905 triệu VND đã được trích lập dự phòng đầy đủ. Nhìn chung, giao dịch bên liên quan ở quy mô kiểm soát được, chưa phát hiện dấu hiệu bất thường nghiêm trọng.', 'Tổng nợ phải trả đạt 482,869,035 triệu VND trên tổng tài sản 527,769,944 triệu VND, tỷ lệ nợ/VCSH khoảng 10.75 lần (đặc thù ngân hàng). Nợ vay từ TCTD khác chiếm 54,394 tỷ VND với tài sản thế chấp là chứng khoán Chính phủ và tiền gửi có kỳ hạn. Phát hành giấy tờ có giá 30,548 tỷ VND với lãi suất dao động 3.10%-8.50%/năm theo kỳ hạn 1-10 năm. Vốn nhận từ JBIC với lãi suất ưu đãi 3.83%-3.91%/năm (VND) và 1.91%/năm (ngoại tệ). Nợ xấu (nhóm 3-5) chiếm 0.77% dư nợ cho vay, tỷ lệ dự phòng/nợ xấu đạt 209%. Áp lực thanh toán ngắn hạn cần được giám sát khi tiền gửi khách hàng tập trung ở kỳ hạn ngắn.', 'Do là ngân hàng thương mại, ACB không có hàng tồn kho truyền thống. Các tài sản chính bao gồm: xây dựng cơ bản dở dang 479,547 triệu VND (chủ yếu là trụ sở, văn phòng) và bất động sản đầu tư 216,027 triệu VND (nắm giữ chờ tăng giá). Quy mô các khoản mục này rất nhỏ so với tổng tài sản, rủi ro đọng vốn thấp. Dự phòng cho tài sản khác đã giảm đáng kể từ 956,821 triệu VND xuống 179,961 triệu VND.', 4, 'Ngân hàng ACB có kết quả kinh doanh năm 2021 tăng trưởng mạnh với lợi nhuận sau thuế 9,603 tỷ VND (tăng 25% so với năm 2020), thu nhập lãi thuần 18,945 tỷ VND. Tỷ lệ nợ xấu nội bảng 0.77% ở mức kiểm soát tốt, dự phòng rủi ro tín dụng tăng mạnh lên 5,862 tỷ VND (gấp đôi năm trước) phản ánh chính sách thận trọng. Tuy nhiên, nợ xấu nhóm 5 tăng từ 1,217 lên 1,379 tỷ VND cho thấy một số áp lực tín dụng. CASA ở mức ~24.8%, NIM ~3.9% - các chỉ số hoạt động ngân hàng ở mức khá. Cơ cấu cổ đông rõ ràng, ban lãnh đạo ổn định, ý kiến kiểm toán chấp nhận toàn phần. Triển vọng tích cực trong ngắn hạn nhờ nền tảng tài chính vững chắc.'),
('ACB_2021_parent', 'ACB', 2021, 'parent', 'Giao dịch với các bên liên quan bao gồm cho vay công ty con (551,400 triệu VND) và cho vay các thành viên Ban lãnh đạo/người thân (94,415 triệu VND). Tiền gửi từ công ty con là 628,168 triệu VND, tiền gửi từ bên liên quan khác là 1,084,890 triệu VND. Có khoản phải thu từ công ty con 185,000 triệu VND. Khoản phải thu từ nhóm sáu công ty liên quan đến nguyên Chủ tịch/Thành viên HĐQT với số tiền 131,905 triệu VND đã được trích lập dự phòng đầy đủ. Tổng thể, giao dịch bên liên quan nằm trong phạm vi hoạt động kinh doanh thông thường của ngân hàng, chưa phát hiện dấu hiệu bất thường lớn.', 'Cơ cấu nợ chủ yếu từ tiền gửi khách hàng (380,401,038 triệu VND), phát hành giấy tờ có giá (30,024,128 triệu VND) và tiền gửi/vay TCTD khác (52,387,400 triệu VND). Tỷ lệ nợ/Vốn chủ sở hữu khoảng 11 lần, đặc trưng cho mô hình ngân hàng. Nợ phát hành trái phiếu chủ yếu kỳ hạn 3 năm với lãi suất từ 3.10%/năm đến 7.10%/năm. Nợ xấu (nhóm 3-5) tăng từ 1,830,028 triệu VND (2020) lên 2,773,220 triệu VND (2021), tỷ lệ nợ xấu tăng từ 0.6% lên 0.8% trên tổng dư nợ cho vay. Áp lực thanh khoản ngắn hạn ở mức kiểm soát được.', 'Ngân hàng không có hàng tồn kho vật chất theo nghĩa truyền thống. Tài sản cố định hữu hình và vô hình có giá trị tổng cộng 3,716,901 triệu VND. Xây dựng cơ bản dở dang 476,993 triệu VND chủ yếu cho mục đích mua sắm, xây dựng trụ sở văn phòng. Dự án xây dựng đang được triển khai và chưa có dấu hiệu đình trệ hay tích tụ chi phí kéo dài.', 5, 'Ngân hàng ACB có nền tảng tài chính lành mạnh với tổng tài sản 523,604,606 triệu VND, tăng trưởng 18.5% so với năm trước. Thu nhập lãi thuần đạt 18,612,896 triệu VND, tăng 29.7%. Lợi nhuận sau thuế 9,096,278 triệu VND, tăng 21.4%. Tuy nhiên, nợ xấu có xu hướng tăng nhẹ, đặc biệt nợ nhóm 3-5 tăng 51.6%. Chi phí dự phòng rủi ro tín dụng tăng mạnh từ 949,770 triệu VND lên 3,320,001 triệu VND. Kiểm toán viên PwC đưa ra ý kiến chấp nhận toàn phần. Ngân hàng cần theo dõi chặt chẽ xu hướng nợ xấu và thực hiện trích lập dự phòng bổ sung theo quy định.'),
('ACB_2020_consolidated', 'ACB', 2020, 'consolidated', 'Giao dịch với các bên liên quan chủ yếu là giao dịch tiền gửi, cho vay và phí dịch vụ trong khuôn khổ hoạt động ngân hàng thông thường. Các khoản cho vay cho các bên liên quan có tài sản bảo đảm và dự phòng đầy đủ. Khoản phải thu từ một số công ty liên quan lịch sử đã được trích lập dự phòng 100%. Nhìn chung, rủi ro từ giao dịch với bên liên quan ở mức kiểm soát được.', 'Cơ cấu nợ chủ yếu là tiền gửi của khách hàng (hơn 353 nghìn tỷ VND) và phát hành giấy tờ có giá (hơn 22 nghìn tỷ VND). Áp lực trả nợ ngắn hạn lớn do phần lớn tiền gửi có kỳ hạn ngắn. Tuy nhiên, ngân hàng có bộ đệm thanh khoản lớn với tiền gửi tại NHNN và tiền mặt. Nợ vay từ các TCTD khác tăng mạnh trong năm 2020 để đáp ứng nhu cầu tăng trưởng tín dụng.', 'Ngân hàng không có hàng tồn kho truyền thống. Các khoản đầu tư bất động sản và xây dựng dở dang có giá trị tương đối nhỏ so với tổng tài sản. Dự án xây dựng dở dang đang trong quá trình triển khai, chưa có dấu hiệu đình trệ. Rủi ro tài sản cố định thấp.', 3, 'Ngân hàng ACB có nền tảng tài chính vững chắc với tăng trưởng lợi nhuận mạnh mẽ (26.5%) trong năm 2020. Dù đại dịch Covid-19, chất lượng tài sản vẫn được kiểm soát tốt với tỷ lệ nợ xấu (Nhóm 3-5) ở mức 0.71% trên tổng dư nợ tín dụng. Ngân hàng có hệ thống quản trị và kiểm soát nội bộ chặt chẽ theo mô hình ba tuyến bảo vệ, được kiểm toán bởi PwC và phát hành báo cáo kiểm toán không ngoại trừ. Triển vọng tăng trưởng khả quan nhờ mạng lưới rộng, hệ sinh thái sản phẩm đa dạng và nền tảng công nghệ.'),
('ACB_2020_parent', 'ACB', 2020, 'parent', 'Ngân hàng có giao dịch với các công ty con (ACBS, ACBA, ACBL, ACBC), công ty liên doanh (ACB-SJC) và công ty liên kết (ACBD). Dư nợ cho vay công ty con 732.833 triệu VND, cho vay bên liên quan khác 45.660 triệu VND. Có khoản phải thu từ nhóm sáu công ty liên quan đến cá nhân nguyên Chủ tịch/HĐQT với số tiền 131.905 triệu VND đã được trích lập dự phòng 100%. Tổng phí trả cho công ty liên kết ACBD là 271.868 triệu VND (chiếm tỷ trọng đáng kể trong chi phí dịch vụ). Các giao dịch chủ yếu mang tính chất hoạt động bình thường trong mô hình ngân hàng có công ty con, tuy nhiên cần theo dõi chặt chẽ khoản phải thu đã trích lập 100% dự phòng từ nhóm sáu công ty liên quan.', 'Tổng nợ phải trả 407.171 tỷ VND, tỷ lệ nợ/VCSH khoảng 11,7 lần - đặc trưng cho ngành ngân hàng. Tiền gửi khách hàng chiếm 86,8% tổng nợ phải trả (353.323 tỷ VND), tạo áp lực chi phí lãi lớn với lãi suất tiền gửi dao động 0-8,3%/năm. Nợ phát hành giấy tờ có giá 21.607 tỷ VND với lãi suất 6-8,55%/năm. Vay các TCTD khác 7.411 tỷ VND chủ yếu là vay chiết khấu, tái chiết khấu được đảm bảo bằng chứng khoán Chính phủ. Nợ vay từ JBIC chỉ 116,7 tỷ VND với lãi suất ưu đãi. Ngân hàng duy trì trạng thái thanh khoản dương đáng kể ở các kỳ hạn trên 3 tháng.', 'Là ngân hàng thương mại, ACB không có hàng tồn kho truyền thống. Xây dựng cơ bản dở dang 143.638 triệu VND chủ yếu là dự án trụ sở và văn phòng làm việc, quy mô nhỏ so với tổng tài sản (0,03%), tiến độ triển khai bình thường, không có dấu hiệu đình trệ hay tích tụ chi phí kéo dài.', 3, 'ACB là ngân hàng có chất lượng tài sản tốt với tỷ lệ nợ xấu (Nhóm 3-5) chỉ 0,72% trên tổng dư nợ cho vay. Lợi nhuận sau thuế đạt 7.493 tỷ VND (tăng 26,6% so với năm trước). NIM đạt khoảng 3,49% - ở mức tốt trong ngành. Tỷ lệ bao phủ nợ xấu cao (dự phòng/NPL ≈ 975%), cho thấy khả năng hấp thụ rủi ro tín dụng rất mạnh. Ý kiến kiểm toán chấp nhận toàn phần từ PwC, không có vấn đề về hoạt động liên tục. Cơ cấu cổ đông minh bạch, ban lãnh đạo nhất quán. Tuy nhiên, cần lưu ý quy mô giao dịch với bên liên quan lớn (cho vay và phí dịch vụ) và một khoản phải thu đã trích lập 100% dự phòng từ nhóm công ty liên quan đến nguyên lãnh đạo.'),
('ACB_2018_parent', 'ACB', 2018, 'parent', 'Ngân hàng có mạng lưới giao dịch rộng với các công ty con (ACBS, ACBA, ACBL), công ty liên doanh (ACB-SJC) và công ty liên kết (ACBD). Khoản cho vay công ty con tại 31.12.2018 là 404.512 triệu VND và cho vay các bên liên quan khác là 188.814 triệu VND. Đặc biệt, có khoản phải thu 135.005 triệu VND từ hai công ty trong Nhóm sáu công ty liên quan đến nguyên Chủ tịch HĐQT, đã được trích lập dự phòng toàn bộ. Ngân hàng đã thu hồi 481.313 triệu VND nợ xấu từ nhóm này trong năm 2018. Thù lao Ban Tổng Giám đốc tăng mạnh từ 25.924 triệu VND (2017) lên 49.502 triệu VND (2018). Nhìn chung, giao dịch bên liên quan có quy mô đáng kể nhưng được tiết lộ công khai và dự phòng đầy đủ.', 'Ngân hàng có cơ cấu nợ đa dạng: nợ ngắn hạn chiếm tỷ trọng lớn với tiền gửi khách hàng 270.472.983 triệu VND là nguồn vốn cốt lõi. Nợ dài hạn bao gồm phát hành trái phiếu 7.416.918 triệu VND và vay JBIC 160.093 triệu VND. Nợ Chính phủ và NHNN 3.074.100 triệu VND là khoản mới phát sinh năm 2018. Tổng nợ phải trả/Vốn chủ sở hữu = 307.886.976/20.674.058 = 14,89 lần - tỷ lệ cao đặc thù ngành ngân hàng. Lãi suất trái phiếu trong khoảng 6,00%-8,80%. Tiền gửi khách hàng VND ngắn hạn (<12 tháng) chiếm tỷ trọng lớn với lãi suất 0%-7,70%. Áp lực thanh toán ngắn hạn đáng kể nhưng được bù đắp bởi mạng lưới huy động vốn rộng lớn (358 chi nhánh).', 'Ngân hàng không có hàng tồn kho theo nghĩa truyền thống. Tài sản chính là các khoản cho vay khách hàng 227.759.122 triệu VND với tỷ lệ nợ xấu (Nhóm 3-5) là 2,13% (1.639.094 triệu VND/227.759.122 triệu VND). Dự phòng rủi ro tín dụng 2.420.211 triệu VND (dự phòng cụ thể 734.321 triệu VND + dự phòng chung 1.685.890 triệu VND). Xây dựng cơ bản dở dang 499.343 triệu VND chủ yếu cho trụ sở văn phòng - rủi ro thấp. Có khoản tiền gửi có kỳ hạn 400.000 triệu VND tại một ngân hàng đã bị NHNN mua lại bắt buộc, đã được trích lập dự phòng 140.392 triệu VND và thu hồi theo lộ trình đến 30/9/2020.', 5, 'ACB là ngân hàng thương mại cổ phần lớn với tổng tài sản 328.561.034 triệu VND, mạng lưới 358 chi nhánh/phòng giao dịch. Năm 2018 ghi nhận lợi nhuận sau thuế 5.124.316 triệu VND, tăng 145% so với năm 2017 (2.089.051 triệu VND), phản ánh sự phục hồi mạnh mẽ sau giai đoạn tái cơ cấu. Vốn điều lệ tăng từ 10.273.239 triệu VND lên 12.885.877 triệu VND. Tuy nhiên, vẫn tồn tại một số rủi ro: (1) Khoản phải thu từ Nhóm sáu công ty liên quan đến nguyên Chủ tịch HĐQT tuy đã được dự phòng nhưng cho thấy lịch sử tín dụng phức tạp; (2) Khoản tiền gửi 400.000 triệu VND tại ngân hàng bị mua lại bắt buộc vẫn đang chờ thu hồi; (3) Tỷ lệ nợ/VCSH cao đặc thù ngành. Kiểm toán viên PwC đã đưa ra ý kiến chấp nhận toàn phần. Triển vọng đầu tư trung hạn tích cực nhờ nền tảng kinh doanh vững mạnh và lợi nhuận tăng trưởng mạnh.'),
('ACB_2018_consolidated', 'ACB', 2018, 'consolidated', 'Các giao dịch với bên liên quan bao gồm: (1) Cho vay 188.814 triệu VND cho các bên liên quan khác (thành viên HĐQT, Ban TGĐ, Ban KS và người thân); (2) Khoản phải thu 135.005 triệu VND từ Nhóm sáu công ty liên quan đến nguyên Chủ tịch/nguyên thành viên HĐQT (đã trích lập dự phòng 100%); (3) Thu nhập lãi 5.601 triệu VND từ cho vay bên liên quan; (4) Phí trả cho ACBS (công ty con) 225.631 triệu VND. Nhóm sáu công ty có lịch sử nợ xấu lớn - trong năm 2018 đã thu hồi 481.313 triệu VND nợ xấu sau khi đã xử lý bằng dự phòng. Số dư phải thu từ nhóm này giảm mạnh từ 616.318 triệu VND (2017) xuống 135.005 triệu VND (2018), cho thấy tiến triển tích cực trong thu hồi nợ. Tuy nhiên, giao dịch với bên liên quan vẫn tồn tại quy mô đáng kể.', 'Tổng nợ phải trả đạt 308.315 tỷ VND, trong đó tiền gửi khách hàng chiếm 269.999 tỷ VND (87,6%) - đây là nguồn vốn huy động chính, ổn định và chi phí thấp. Nợ ngắn hạn chiếm tỷ trọng lớn bao gồm nợ NHNN 3.074 tỷ VND, tiền gửi TCTD khác 17.174 tỷ VND, vay TCTD khác 3.545 tỷ VND. Trái phiếu phát hành 8.291 tỷ VND bao gồm cả kỳ hạn ngắn và dài hạn. Tỷ lệ nợ/VCSH là 14,67 lần (308.315/21.018) phản ánh đặc thù hoạt động ngân hàng. Nợ xấu (nhóm 3-5) trong cho vay khách hàng là 1.675 tỷ VND (tỷ lệ nợ xấu khoảng 0,73%), ở mức kiểm soát được. Áp lực lãi suất là đáng kể khi chi phí lãi đạt 13.652 tỷ VND trong năm 2018.', 'Là ngân hàng thương mại, ACB không có hàng tồn kho truyền thống. Tuy nhiên, xây dựng cơ bản dở dang trị giá 499.343 triệu VND (chủ yếu là trụ sở/văn phòng) đã giảm từ 667.965 triệu VND, cho thấy dự án đang được triển khai tích cực và không có dấu hiệu đình trệ. Tài sản gán nợ đang chờ xử lý (bất động sản) trị giá 44.292 triệu VND giảm từ 66.907 triệu VND, phản ánh xử lý tích cực.', 5, 'ACB là một trong những ngân hàng TMCP lớn tại Việt Nam với tổng tài sản 329.333 tỷ VND. Năm 2018 ghi nhận kết quả kinh doanh tăng trưởng mạnh: lợi nhuận trước thuế 6.389 tỷ VND (tăng 140,5% so với 2017), thu nhập lãi thuần 10.363 tỷ VND (tăng 22,5%), tỷ lệ nợ xấu kiểm soát ở mức 0,73%. Kiểm toán viên PwC đưa ra ý kiến chấp nhận toàn phần, không có vấn đề về hoạt động liên tục. Cấu trúc vốn chủ sở hữu lành mạnh với vốn điều lệ 12.886 tỷ VND. Các rủi ro chính bao gồm: (1) Các khoản phải thu từ Nhóm sáu công ty liên quan đến nguyên lãnh đạo đã được trích lập dự phòng đầy đủ và đang trong quá trình thu hồi; (2) Giao dịch với bên liên quan quy mô vừa phải, được trình bày đầy đủ; (3) Cơ quan quản lý đã mua bắt buộc một ngân hàng thương mại mà ACB có khoản tiền gửi 400 tỷ VND quá hạn, khoản này đã được trích lập dự phòng 140.392 triệu VND. Nhìn chung, ngân hàng có nền tảng tài chính vững mạnh, quản trị rủi ro tốt và triển vọng tăng trưởng khả quan.'),
('ACB_2019_consolidated', 'ACB', 2019, 'consolidated', 'Ngân hàng có giao dịch đáng kể với các công ty con (ACBS, ACBA, ACBL, ACBC) và các bên liên quan (ban lãnh đạo, cổ đông lớn). Tổng phí trả cho công ty con đạt 252 tỷ VND, chiếm tỷ trọng lớn trong chi phí. Các khoản vay và tiền gửi với bên liên quan khác cũng ở mức cao (hơn 30 tỷ VND). Tuy nhiên, các giao dịch này thuộc hoạt động nghiệp vụ thông thường của ngân hàng và đã được công bố minh bạch trong báo cáo tài chính, chưa phát hiện dấu hiệu chuyển giá bất thường hay rút ruột.', 'Cơ cấu nợ của Ngân hàng phụ thuộc lớn vào nguồn tiền gửi khách hàng (gần 308 nghìn tỷ VND), đây là nguồn vốn ngắn hạn, đòi hỏi tính thanh khoản cao. Ngân hàng đã phát hành trái phiếu dài hạn với tổng giá trị hơn 20 nghìn tỷ VND để cơ cấu lại nguồn vốn. Tỷ lệ nợ/Vốn chủ sở hữu ở mức cao (khoảng 12.8 lần), đặc thù của ngành ngân hàng. Áp lực thanh toán lãi vay phát sinh từ phát hành giấy tờ có giá (lãi suất từ 6-9%/năm) và lãi tiền gửi khách hàng. Ngân hàng duy trì mức dự trữ bắt buộc tại NHNN và quản lý thanh khoản theo quy định.', 'Ngân hàng không có hàng tồn kho vật chất. Tuy nhiên, có khoản xây dựng cơ bản dở dang hơn 104 tỷ VND, chủ yếu cho dự án trụ sở/văn phòng. Đây là tài sản cố định trong quá trình đầu tư, rủi ro đọng vốn thấp do thuộc kế hoạch mở rộng hạ tầng hoạt động của Ngân hàng. Ngân hàng không có rủi ro hàng tồn kho như doanh nghiệp sản xuất hay bất động sản.', 3, 'Ngân hàng Thương mại Cổ phần Á Châu (ACB) có cấu trúc tài chính lành mạnh, tăng trưởng tổng tài sản 16% so với năm trước. Lợi nhuận trước thuế đạt 7,516 tỷ VND, tăng 18%. Công tác quản trị rủi ro được triển khai bài bản theo mô hình ba tuyến bảo vệ. Ý kiến kiểm toán là chấp nhận toàn phần. Các giao dịch với bên liên quan được công khai, minh bạch. Tuy nhiên, cần theo dõi áp lực cạnh tranh huy động vốn và biến động lãi suất thị trường. Triển vọng đầu tư trung hạn khả quan.');
INSERT OR REPLACE INTO `financial_insights` (`id`, `ticker`, `year`, `report_type`, `related_party_risk`, `debt_risk`, `inventory_risk`, `governance_risk_score`, `overall_analysis`) VALUES
('ACB_2019_parent', 'ACB', 2019, 'parent', 'Các giao dịch với bên liên quan bao gồm cho vay và nhận tiền gửi từ các công ty con (ACBS, ACBA, ACBL) và công ty liên doanh/liên kết (ACB-SJC, ACBD), với giá trị giao dịch trong năm ở mức hợp lý so với quy mô tổng tài sản. Đáng lưu ý là khoản phải thu 131.905 triệu VND từ nhóm sáu công ty liên quan đến nguyên lãnh đạo đã được trích lập dự phòng 100%, cho thấy rủi ro thu hồi rất thấp. Phí trả cho công ty liên kết ACBD (dịch vụ bảo vệ) lên tới 250.407 triệu VND trong năm, chiếm tỷ trọng đáng kể. Nhìn chung, giao dịch bên liên quan được kiểm soát tốt, chưa phát hiện dấu hiệu chuyển giá hay rút vốn bất thường.', 'Tổng nợ phải trả là 355.556 tỷ VND, chủ yếu là tiền gửi khách hàng (308.494 tỷ VND) chiếm 86,8% tổng nợ. Nợ vay phát hành giấy tờ có giá tăng mạnh từ 7.417 tỷ lên 20.330 tỷ VND, phản ánh việc đa dạng hóa nguồn vốn. Vốn chủ sở hữu đạt 27.329 tỷ VND, tỷ lệ nợ/VCSH khoảng 13 lần (đặc thù ngân hàng). Lãi suất phát hành giấy tờ có giá từ 6,00% - 8,80%/năm. Áp lực trả nợ ngắn hạn tập trung vào tiền gửi không kỳ hạn và tiền gửi ngắn hạn của khách hàng, song ngân hàng duy trì tỷ lệ tiền và tương đương tiền/VCSH ở mức an toàn (35.678 tỷ VND). Nợ xấu (nhóm 3-5) giảm từ 2.09% xuống 0,54% cho thấy chất lượng tín dụng cải thiện rõ rệt.', 'Ngân hàng không có hàng tồn kho theo nghĩa truyền thống. Xây dựng cơ bản dở dang giảm mạnh từ 499.343 triệu VND xuống còn 104.225 triệu VND do đã hoàn thành chuyển giao sang TSCĐ. Dự án mua sắm xây dựng trụ sở, văn phòng làm việc đang trong tiến độ hoàn thiện, rủi ro đọng vốn thấp.', 3, 'ACB có kết quả kinh doanh năm 2019 tích cực với lợi nhuận trước thuế 7.390 tỷ VND (tăng 16,3% so với năm 2018), lợi nhuận sau thuế 5.918 tỷ VND. Tỷ lệ nợ xấu giảm mạnh từ 2,09% xuống 0,54% phản ánh công tác quản trị tín dụng hiệu quả. CASA ở mức 18,44% cho thấy cơ cấu huy động còn room cải thiện. Kiểm toán viên PwC đưa ra ý kiến chấp nhận toàn phần, không có vấn đề về khả năng hoạt động liên tục. Cấu trúc vốn được tăng cường qua phát hành cổ phiếu và trái phiếu. Tuy nhiên, hệ số dự phòng rủi ro tín dụng/NPL ở mức 1,66 lần còn mỏng, và một số khoản phải thu liên quan đến nguyên lãnh đạo đã phải trích lập 100% dự phòng cần được theo dõi sát. Triển vọng đầu tư trung hạn tích cực nhờ nền tảng tài chính vững mạnh và thương hiệu ngân hàng bán lẻ uy tín.'),
('ACB_2017_parent', 'ACB', 2017, 'parent', 'Giao dịch với bên liên quan chủ yếu bao gồm lãi từ tiền gửi và cho vay công ty con, phí dịch vụ và thù lao quản lý. Giá trị giao dịch không lớn bất thường so với quy mô tài sản ngân hàng, chưa thấy dấu hiệu rút ruột hay chuyển giá.', 'Nợ vay chủ yếu từ tiền gửi của khách hàng với lãi suất ổn định. Tỷ lệ nợ xấu thấp (0.70%), dự phòng trích lập đầy đủ với tỷ lệ bao phủ 127%. Áp lực thanh toán ngắn hạn quản lý tốt.', 'Hàng tồn kho không áp dụng; tài sản xây dựng dở dang là đầu tư vào trụ sở văn phòng, tiến độ xây dựng đúng kế hoạch, rủi ro đọng vốn thấp.', 3, 'Ngân hàng Á Châu có kết quả kinh doanh tăng trưởng mạnh năm 2017 với lợi nhuận trước thuế tăng 62.8%. Cấu trúc tài chính lành mạnh, tỷ lệ nợ xấu thấp, dự phòng đầy đủ. Ban lãnh đạo nhất quán và công tác quản trị rủi ro tốt. Triển vọng đầu tư trung hạn khả quan.'),
('ACB_2016_consolidated', 'ACB', 2016, 'consolidated', 'Giao dịch với bên liên quan phức tạp, đặc biệt với Nhóm sâu công ty, với các khoản phải thu và cho vay lớn, đã trích lập dự phòng nhưng vẫn tiềm ẩn rủi ro.', 'Nợ vay chủ yếu từ tiền gửi khách hàng và phát hành trái phiếu, tỷ lệ nợ trên vốn chủ sở hữu cao nhưng phù hợp với ngành ngân hàng. Áp lực thanh toán ngắn hạn tồn tại nhưng được quản lý.', 'Hàng tồn kho chủ yếu là chi phí xây dựng dở dang và bất động sản đầu tư, rủi ro đọng vốn thấp do giá trị không quá lớn.', 6, 'Ngân hàng có tình hình tài chính ổn định, tăng trưởng tín dụng mạnh, nhưng tiềm ẩn rủi ro từ danh mục tín dụng phức tạp và giao dịch bên liên quan. Công tác quản trị rủi ro được chú trọng.'),
('ACB_2016_parent', 'ACB', 2016, 'parent', 'ACB có nhiều giao dịch với bên liên quan bao gồm 4 công ty con (ACBS, ACBA, ACBL, ACBC), 1 công ty liên kết (ACBD), 1 công ty liên doanh (ACB-SJC) và nhóm sáu công ty liên quan đến nguyên Chủ tịch HĐQT. Khoản cho vay công ty con ACBS đạt 461.926 triệu VND với tiền gửi ngược lại 436.655 triệu VND. Đáng lo ngại nhất là nhóm sáu công ty với tổng dư nợ cho vay 1.427.566 triệu VND, trái phiếu 1.837.319 triệu VND và phải thu 648.500 triệu VND, tổng cộng 3.913.385 triệu VND. Các khoản nợ này được phân loại vào Nhóm 2 - Nợ cần chú ý với dự phòng cụ thể lên đến 2.383.376 triệu VND. Đây là rủi ro lớn nhất liên quan đến quản trị doanh nghiệp, tuy nhiên NHNN đã phê duyệt lộ trình thu hồi nợ rõ ràng (kết thúc năm 2017).', 'Tổng nợ phải trả 219.299.205 triệu VND so với vốn chủ sở hữu 13.760.691 triệu VND, tỷ lệ nợ/VCSH khoảng 15,94 lần - mức cao nhưng đặc thù ngân hàng. Nợ lớn nhất là tiền gửi khách hàng 207.347.013 triệu VND (chiếm 94,5% tổng nợ). Ngân hàng đã phát hành trái phiếu 6.054.000 triệu VND với lãi suất cao (8,50% - 13,25%/năm). Tiền gửi có kỳ hạn tại Ngân hàng B (125.000 triệu VND) đang trong quá trình xử lý cấn trừ bất động sản; tiền gửi tại Ngân hàng C (400.000 triệu VND) đã quá hạn, phân loại Nhóm 5 với dự phòng 165.630 triệu VND. Nợ Chính phủ và NHNNVN đã được giảm từ 5.178.981 triệu VND (2015) về 0 triệu VND (2016). Áp lực thanh khoản ngắn hạn tồn tại do phần lớn tài sản là cho vay trung dài hạn nhưng nguồn vốn chủ yếu ngắn hạn.', 'Là ngân hàng thương mại, ACB không có hàng tồn kho truyền thống. Tài sản cố định chủ yếu là trụ sở làm việc (1.785.361 triệu VND), thiết bị văn phòng (334.734 triệu VND) và phần mềm máy tính (191.733 triệu VND). Chi phí xây dựng cơ bản dở dang 459.862 triệu VND cho dự án xây dựng trụ sở/văn phòng đang trong tiến độ thi công. Tài sản gán nợ chờ xử lý là bất động sản trị giá 102.579 triệu VND. Rủi ro thấp vì đây là tài sản hữu hình phục vụ hoạt động kinh doanh cốt lõi của ngân hàng.', 6, 'Ngân hàng ACB có tình hình tài chính tương đối lành mạnh với nợ xấu (Nhóm 3-5) chỉ chiếm 0,87% tổng dư nợ cho vay. Lợi nhuận sau thuế đạt 1.307.992 triệu VND, tăng 29,2% so với năm trước, cho thấy hiệu quả kinh doanh cải thiện. Tuy nhiên, rủi ro lớn nhất đến từ nhóm sáu công ty liên quan đến nguyên Chủ tịch HĐQT với tổng dư nợ 3.913.385 triệu VND và dự phòng đã trích lập 2.383.376 triệu VND. NHNN đã phê duyệt lộ trình cơ cấu lại giai đoạn 2015-2018 và điều chỉnh rút ngắn lộ trình thu hồi nợ. Dòng tiền hoạt động kinh doanh âm 578.860 triệu VND do cho vay khách hàng tăng mạnh 27.913.910 triệu VND. Tổng tài sản đạt 233.059.896 triệu VND, tăng 15,7% so với năm trước. Ngân hàng cần tiếp tục theo dõi chặt chẽ lộ trình thu hồi nợ của nhóm sáu công ty và quản lý rủi ro thanh khoản trong ngắn hạn.'),
('ACB_2015_parent', 'ACB', 2015, 'parent', 'Rủi ro bên liên quan ở mức CAO. Ngân hàng có mức độ tập trung tín dụng lớn vào Nhóm sáu công ty liên quan đến nguyên Chủ tịch/Thành viên HĐQT với tổng dư nợ cho vay 1.866.081 triệu VND, trái phiếu 2.734.353 triệu VND và phải thu 1.166.857 triệu VND. Ngân hàng đã phải ký thỏa thuận với NHNNVN theo Công văn 10005 về lộ trình thu hồi nợ đến năm 2018 và tiếp tục phân loại vào Nhóm 2 với trích lập dự phòng bổ sung 751.000 triệu VND cho trái phiếu. Ngoài ra, cho vay và phải thu từ các bên liên quan khác (ban lãnh đạo, gia đình, doanh nghiệp liên quan) cũng chiếm quy mô đáng kể với khoản vay 416.227 triệu VND, đầu tư trái phiếu 1.000.000 triệu VND và phải thu 156.091 triệu VND. Tổng giá trị tài sản bảo đảm ước tính cho Nhóm sáu công ty là 4.732.137 triệu VND (bao gồm cổ phiếu, vốn góp và thư bảo lãnh).', 'Rủi ro nợ vay ở mức TRUNG BÌNH-CAO. Tổng nợ phải trả 188.879.114 triệu VND, gấp 15,1 lần vốn chủ sở hữu 12.502.699 triệu VND. Nguồn vốn chủ yếu dựa vào tiền gửi khách hàng (175.395.002 triệu VND, chiếm 92,9% tổng nợ). Ngân hàng phải tăng vay NHNNVN 5.178.981 triệu VND năm 2015 (so với 0 năm 2014), cho thấy áp lực thanh khoản ngắn hạn. Trái phiếu phát hành 3.000.000 triệu VND với lãi suất cố định 13,25%/năm tạo gánh nặng chi phí lãi vay đáng kể. Đáng lưu ý, tiền gửi khách hàng chịu lãi suất lên đến 11%/năm (kỳ hạn 1-5 năm) trong khi lãi suất cho vay biến động lớn (5,2%-24%/năm), biên lãi suất bị thu hẹp. Tuy nhiên, nợ vay từ TCTD khác giảm mạnh từ 5.997.390 triệu VND xuống còn 2.360.415 triệu VND.', 'Rủi ro hàng tồn kho/dự án ở mức THẤP. Chi phí xây dựng cơ bản dở dang chỉ 630.543 triệu VND (0,31% tổng tài sản), chủ yếu là xây dựng trụ sở văn phòng làm việc. Giá trị này nhỏ so với quy mô tài sản ngân hàng. Không có dự án xây dựng bất động sản lớn hay dự án dở dang kéo dài nhiều năm. Không có trích lập dự phòng cho các khoản mục này.', 5, 'Ngân hàng TMCP Á Châu (ACB) năm 2015 đạt lợi nhuận sau thuế 1.012.086 triệu VND, tăng 9,7% so với năm 2014, với ROA khoảng 0,53% và NIM 2,96%. Điểm mạnh: (1) Hoạt động kinh doanh cốt lõi tăng trưởng tốt với thu nhập lãi thuần 5.637.115 triệu VND (tăng 25,7%); (2) Tỷ lệ CASA cao 93,7% cho thấy ưu thế nguồn vốn giá rẻ; (3) Tỷ lệ nợ xấu (Nhóm 3+4+5) chỉ 1,29% - ở mức kiểm soát được; (4) Lợi nhuận hoạt động trước dự phòng đạt 2.135.421 triệu VND. Điểm rủi ro: (1) Dư nợ lớn với Nhóm sáu công ty (~5,8 nghìn tỷ VND) đòi hỏi giám sát chặt chẽ và lộ trình thu hồi dài hạn đến 2018; (2) Phải tăng vay NHNNVN 5.178.981 triệu VND, phản ánh áp lực thanh khoản; (3) Trái phiếu lãi suất 13,25%/năm tạo chi phí cố định cao; (4) Kiểm toán viên nhấn mạnh Công văn 10005 về cơ cấu lại. Ban lãnh đạo đã chủ động xử lý nợ xấu qua bán nợ cho VAMC (2.611.488 triệu VND đã bán) và cơ cấu lại theo chỉ đạo của NHNNVN. Triển vọng trung hạn: Ngân hàng đang trong quá trình tái cơ cấu theo đề án của NHNNVN, hoạt động kinh doanh cốt lõi phục hồi tốt nhưng vẫn cần thời gian để xử lý dứt điểm tồn đọng liên quan đến nhóm sáu công ty.'),
('ACB_2015_consolidated', 'ACB', 2015, 'consolidated', 'Giao dịch với các công ty liên doanh, liên kết và bên liên quan khác có tổng giá trị lớn, bao gồm tiền gửi, cho vay và đầu tư trái phiếu. Điều này có thể gây rủi ro về chất lượng tín dụng và xung đột lợi ích, tuy nhiên các giao dịch dường như nằm trong hoạt động kinh doanh thông thường của ngân hàng và được kiểm soát bởi chính sách nội bộ.', 'Nợ vay chủ yếu từ tiền gửi của khách hàng và vay từ các tổ chức tín dụng với tỷ lệ nợ trên vốn chủ sở hữu cao. Áp lực thanh toán ngắn hạn có thể do nợ ngắn hạn lớn, nhưng ngân hàng đã trích lập dự phòng rủi ro tín dụng đầy đủ. Nợ xấu chiếm khoảng 1.32% tổng cho vay, tập trung vào một số nhóm nợ đặc biệt.', 'Hàng tồn kho chủ yếu là chi phí xây dựng cơ bản dở dang cho trụ sở làm việc, với giá trị 642,523 triệu VNĐ. Rủi ro đọng vốn thấp do tiến độ triển khai ổn định và không có dự phòng giảm giá.', 5, 'Ngân hàng Á Châu có kết quả kinh doanh tăng trưởng với lợi nhuận sau thuế 1,028,232 triệu VNĐ. Cơ cấu vốn mạnh với vốn chủ sở hữu 12,787,542 triệu VNĐ. Tuy nhiên, nợ xấu vẫn còn đáng kể, đặc biệt là khoản vay cho Nhóm sáu công ty. Ngân hàng có hệ thống quản lý rủi ro toàn diện và tuân thủ các quy định. Triển vọng đầu tư phụ thuộc vào việc xử lý nợ xấu và duy trì hiệu quả hoạt động.'),
('VMS_2024_consolidated', 'VMS', 2024, 'consolidated', 'Giao dịch với bên liên quan tập trung chủ yếu vào các công ty con của Tổng Công ty Hàng hải Việt Nam (VIMC). Tổng doanh thu từ bên liên quan đạt 23.5 tỷ đồng (chiếm 11% doanh thu thuần), mua hàng từ bên liên quan 1.09 tỷ đồng. Các giao dịch này thuộc hoạt động kinh doanh dịch vụ logistics, cảng biển - ngành nghề cốt lõi. Tuy nhiên, khoản phải thu từ Công ty Cổ phần Vận tải Container Đông Đô - Cảng Hải Phòng (công ty liên quan) có giá trị 1.66 tỷ đồng đã được trích lập dự phòng toàn bộ, cho thấy tín hiệu thu hồi kém. Nhìn chung, giao dịch bên liên quan có quy mô hợp lý, phục vụ hoạt động sản xuất kinh doanh chính, chưa phát hiện dấu hiệu bất thường rõ ràng.', 'Công ty không có nợ vay ngân hàng hay trái phiếu. Nợ phải trả chủ yếu là: phải trả người bán ngắn hạn 7.7 tỷ đồng; thuế và các khoản phải nộp 3.1 tỷ đồng; phải trả người lao động 4.3 tỷ đồng; nhận ký quỹ/ký cược dài hạn 7.3 tỷ đồng; và đặc biệt khoản nợ lớn nhất là phải trả CBCNV góp vốn dự án Bắc Rạch Chiếc - Phước Bình 44 tỷ đồng (dài hạn) cộng lãi tiền gửi 12.6 tỷ đồng. Tổng nợ phải trả 87.7 tỷ đồng so với tổng tài sản 239.3 tỷ đồng, tỷ lệ nợ/VCSH = 0.58 lần. Áp lực trả nợ ngắn hạn ở mức trung bình, nhưng khoản nợ dài hạn liên quan đến dự án bất động sản đình trệ tạo rủi ro trả nợ nếu dự án không được triển khai.', 'Hàng tồn kho có giá trị nhỏ (3 tỷ đồng) không trích lập dự phòng, chủ yếu là hàng hóa, nguyên vật liệu và hàng đang vận chuyển, rủi ro thấp. Tuy nhiên, chi phí xây dựng cơ bản dở dang lên đến 50.7 tỷ đồng (21% tổng tài sản) bao gồm 3 dự án bất động sản lớn đều đang gặp vướng mắc pháp lý nghiêm trọng: dự án Bắc Rạch Chiếc - Phước Bình và Phước Long A bị tạm dừng do thanh kiểm tra của cơ quan Nhà nước, chưa được phê duyệt quy hoạch, chưa có giấy chứng nhận quyền sử dụng đất. Dự án ICD Phước Long đang tìm đối tác hợp tác mới. Các dự án này đã đầu tư nhiều năm nhưng chưa tạo ra doanh thu, chi phí tập hợp ngày càng tăng mà không có dự phòng giảm giá, tiềm ẩn rủi ro đọng vốn và suy giảm giá trị đầu tư rất lớn.', 6, 'Công ty Cổ phần Phát triển Hàng hải có hoạt động kinh doanh cốt lõi trong lĩnh vực dịch vụ logistics, cảng biển và kinh doanh bất động sản. Năm 2024, doanh thu thuần đạt 213.8 tỷ đồng, tăng 31% so với năm trước; lợi nhuận sau thuế 15.4 tỷ đồng, tăng 6%. Biên lợi nhuận gộp đạt 12.5%. Công ty không có nợ vay ngân hàng, thanh khoản tốt với tiền và tương đương tiền 27.2 tỷ đồng. Tuy nhiên, điểm đáng lo ngại lớn nhất là các dự án bất động sản (Bắc Rạch Chiếc - Phước Bình, Phước Long A) với tổng chi phí đầu tư dở dang 50.7 tỷ đồng đang bị cơ quan Nhà nước thanh kiểm tra, tạm dừng triển khai do vướng mắc pháp lý kéo dài nhiều năm, tranh chấp đất đai, chưa được phê duyệt quy hoạch. Dự phòng phải thu khó đòi tăng mạnh từ 4.3 tỷ lên 7.9 tỷ đồng. Kiểm toán viên đã nhấn mạnh các vấn đề này nhưng không ảnh hưởng đến ý kiến chấp nhận toàn phần. Triển vọng phụ thuộc lớn vào khả năng giải quyết vướng mắc pháp lý của các dự án bất động sản và duy trì hoạt động kinh doanh dịch vụ cốt lõi.'),
('VMS_2023_consolidated', 'VMS', 2023, 'consolidated', 'Công ty có nhiều giao dịch mua bán với các công ty cùng Tập đoàn Hàng hải Việt Nam. Giá trị giao dịch bán hàng lớn nhất là với Công ty TNHH Cảng Quốc tế Cái Mép (~9.76 tỷ VND). Giao dịch mua hàng lớn nhất là với Công ty Cổ phần Đại lý Hàng hải Việt Nam (~0.92 tỷ VND). Các giao dịch này thuộc hoạt động cốt lõi và được công khai, chưa thấy dấu hiệu chuyển giá hay rút vốn bất thường. Tuy nhiên, cơ cấu giao dịch tập trung vào nội bộ tập đoàn.', 'Nợ vay ngân hàng không được ghi nhận riêng biệt. Các khoản nợ dài hạn chủ yếu là phải trả khác cho CBCNV góp vốn dự án (~44 tỷ VND) và tiền cọc hợp tác đầu tư (~2.23 tỷ VND). Nợ ngắn hạn gồm phải trả người bán, thuế và các khoản khác. Áp lực trả nợ tập trung vào nghĩa vụ với CBCNV và các khoản đặt cọc liên quan đến dự án bất động sản. Không có lãi vay ngân hàng phát sinh trong năm.', 'Hàng tồn kho giá trị nhỏ (~2.17 tỷ VND), chủ yếu là hàng hóa và nguyên vật liệu, không có dự phòng giảm giá. Rủi ro lớn nằm ở Chi phí xây dựng cơ bản dở dang (50.2 tỷ VND), tập trung vào 3 dự án bất động sản lớn tại TP.HCM. Hai dự án (Bắc Rạch Chiếc) đang bị thanh kiểm tra, tranh chấp đất và tạm dừng triển khai, có nguy cơ đọng vốn dài hạn và giá trị thu hồi không đảm bảo. Dự án ICD Phước Long cũng đang tìm kiếm đối tác mới.', 6, 'Doanh nghiệp có cơ cấu tài sản lớn (234.3 tỷ VND) nhưng lợi nhuận hoạt động kinh doanh cốt lõi không cao, phần lớn lợi nhuận trước thuế đến từ thu nhập khác (bán tài sản, giảm tiền thuê đất). Các dự án đầu tư bất động sản lớn chiếm tỷ trọng cao trong tài sản nhưng đang gặp vướng mắc pháp lý, thanh tra và tranh chấp, tạo ra rủi ro lớn về khả năng thu hồi vốn. Ban lãnh đạo có sự thay đổi lớn trong năm. Công ty mẹ là Tổng Công ty Hàng hải Việt Nam - CTCP. Điểm đáng chú ý là ý kiến kiểm toán có nhấn mạnh về các dự án thanh kiểm tra và nợ tiềm tàng, nhưng vẫn là ý kiến chấp nhận toàn phần.'),
('VMS_2025_consolidated', 'VMS', 2025, 'consolidated', 'Doanh thu từ các bên liên quan chiếm tỷ trọng lớn (khoảng 32% tổng doanh thu năm 2025), tập trung vào các công ty con và công ty mẹ trong cùng Tập đoàn Hàng hải Việt Nam. Giao dịch mua hàng từ bên liên quan cũng đáng kể. Hoạt động giao dịch chủ yếu là bán hàng và cung cấp dịch vụ logistics, vận tải thuộc ngành nghề cốt lõi, chưa thấy dấu hiệu chuyển giá bất thường, nhưng sự phụ thuộc vào tập đoàn là khá cao.', 'Công ty không có nợ vay ngân hàng hay trái phiếu. Các khoản nợ phải trả chủ yếu là phải trả người bán và các khoản phải trả khác (góp vốn CBCNV, ký quỹ). Áp lực trả nợ ngắn hạn và dài hạn thấp, không chịu chi phí lãi vay.', 'Hàng tồn kho có giá trị nhỏ (khoảng 1,98 tỷ đồng) và không trích lập dự phòng. Các dự án bất động sản (Bắc Rạch Chiếc - Phước Bình, Phước Long A) có giá trị đầu tư lớn (gần 49 tỷ đồng) nhưng đang gặp vướng mắc pháp lý, bị thanh kiểm tra và có tranh chấp đất đai, dẫn đến nguy cơ đọng vốn kéo dài. Công ty đã trích lập dự phòng phải thu liên quan đến dự án.', 5, 'Công ty có kết quả kinh doanh tăng trưởng mạnh về doanh thu nhưng lợi nhuận sau thuế giảm nhẹ do chi phí quản lý tăng. Cơ cấu tài sản chủ yếu là các dự án bất động sản đang triển khai nhưng gặp nhiều vướng mắc pháp lý và tranh chấp. Nợ phải trả không có nợ vay, dòng tiền hoạt động kinh doanh dương. Rủi ro chính tập trung vào tiến độ và khả năng thu hồi vốn từ các dự án bất động sản. Ý kiến kiểm toán là chấp nhận toàn phần nhưng có nhấn mạnh về các dự án và nợ tiềm tàng. Triển vọng phụ thuộc lớn vào việc giải quyết pháp lý các dự án.'),
('VMS_2021_consolidated', 'VMS', 2021, 'consolidated', 'Công ty có giao dịch mua bán lớn với các công ty cùng Tổng Công ty Hàng hải Việt Nam (công ty mẹ), tập trung vào dịch vụ container và cảng biển. Tổng doanh thu từ bên liên quan năm 2021 là 24,48 tỷ VNĐ, giảm so với năm trước. Các giao dịch này thuộc hoạt động kinh doanh cốt lõi, tuy nhiên sự phụ thuộc vào nhóm công ty mẹ có thể tạo ra rủi ro tập trung khách hàng.', 'Nợ phải trả tổng cộng là 101,78 tỷ VNĐ, chiếm 40,6% tổng tài sản. Trong đó nợ ngắn hạn 46,59 tỷ VNĐ và nợ dài hạn 55,18 tỷ VNĐ (chủ yếu là phải trả dài hạn khác liên quan đến dự án). Công ty không có vay ngân hàng, nợ chủ yếu phát sinh từ hoạt động kinh doanh và cam kết dự án. Áp lực trả nợ ngắn hạn ở mức trung bình, nhưng nợ dài hạn lớn liên quan đến các dự án bất động sản đang bị đình trệ có thể ảnh hưởng đến dòng tiền.', 'Hàng tồn kho bao gồm 3 dự án xây dựng dở dang với tổng giá trị 49,79 tỷ VNĐ, không trích lập dự phòng. Hai dự án lớn (Bắc Rạch Chiếc - Phước Bình và Phước Long A) đang bị thanh kiểm tra bởi cơ quan nhà nước và tạm dừng triển khai, dẫn đến rủi ro đọng vốn cao. Dự án ICD Phước Long vẫn trong giai đoạn pháp lý. Đây là rủi ro lớn nhất của công ty.', 6, 'Công ty có kết quả kinh doanh ổn định với lợi nhuận sau thuế 10,79 tỷ VNĐ năm 2021. Tuy nhiên, sức khỏe tài chính bị ảnh hưởng nghiêm trọng bởi các dự án bất động sản đang bị đình trệ và thanh kiểm tra, chiếm tỷ trọng lớn trong tài sản. Ban lãnh đạo có thay đổi trong năm. Ý kiến kiểm toán chấp nhận toàn phần nhưng nhấn mạnh vấn đề dự án. Rủi ro quản trị ở mức cao do phụ thuộc lớn vào dự án bất động sản pháp lý phức tạp và giao dịch với bên liên quan.');
INSERT OR REPLACE INTO `financial_insights` (`id`, `ticker`, `year`, `report_type`, `related_party_risk`, `debt_risk`, `inventory_risk`, `governance_risk_score`, `overall_analysis`) VALUES
('VMS_2022_consolidated', 'VMS', 2022, 'consolidated', 'Công ty có nhiều giao dịch với các bên liên quan là công ty cùng công ty mẹ (Tổng Công ty Hàng hải Việt Nam). Doanh thu từ bên liên quan đạt 20,16 tỷ đồng (chiếm khoảng 9,5% tổng doanh thu), mua hàng từ bên liên quan đạt 2,3 tỷ đồng. Các giao dịch này thuộc hoạt động kinh doanh thông thường nhưng cần theo dõi để đảm bảo tính minh bạch và giá thị trường.', 'Công ty không có khoản vay ngân hàng mà chủ yếu nợ phải trả khác, trong đó nợ dài hạn 55,85 tỷ đồng chủ yếu bao gồm khoản CBCNV góp vốn vào dự án Bắc Rạch Chiếc - Phước Bình (43,98 tỷ đồng). Nợ ngắn hạn 34,46 tỷ đồng bao gồm tiền cọc hợp tác đầu tư với Công ty TNHH Đầu tư Xuất nhập khẩu Ngọc Việt (20 tỷ đồng) và các khoản phải trả khác. Tỷ lệ nợ/vốn chủ sở hữu là 0,61 lần, mức chấp nhận được. Tuy nhiên, áp lực thanh toán ngắn hạn tập trung vào khoản tiền cọc dự án.', 'Hàng tồn kho thông thường chỉ 843,8 triệu đồng, không có dự phòng giảm giá. Rủi ro lớn tập trung vào chi phí xây dựng cơ bản dở dang (50,17 tỷ đồng) với 3 dự án bất động sản đang gặp vướng mắc pháp lý nghiêm trọng: dự án ICD Phước Long chưa được duyệt quy hoạch, dự án Bắc Rạch Chiếc - Phước Bình và Phước Long A đang bị thanh kiểm tra, có tranh chấp đất và tạm dừng triển khai. Các dự án này có nguy cơ đọng vốn kéo dài và có thể phải trích lập dự phòng.', 6, 'Công ty có cấu trúc tài sản lớn với nhiều dự án bất động sản đang triển khai nhưng gặp vướng mắc pháp lý nghiêm trọng, tiềm ẩn rủi ro lớn về đọng vốn và phải trích lập dự phòng. Ban lãnh đạo có sự thay đổi lớn trong năm 2022 (miễn nhiệm nhiều thành viên cũ, bổ nhiệm mới). Hoạt động kinh doanh cốt lõi (dịch vụ logistics, cho thuê kho bãi) vẫn tạo ra lợi nhuận ổn định (LNST 9,77 tỷ đồng). Tuy nhiên, rủi ro pháp lý của các dự án bất động sản là mối lo ngại chính, có thể ảnh hưởng nghiêm trọng đến tài chính và hoạt động của Công ty trong tương lai.'),
('VMS_2018_consolidated', 'VMS', 2018, 'consolidated', 'Giao dịch với các công ty cùng Tổng Công ty Hàng Hải Việt Nam có quy mô lớn, đặc biệt doanh thu bán hàng với Công ty TNHH Khai thác Container Việt Nam chiếm tỷ trọng cao. Các giao dịch này thuộc hoạt động kinh doanh thông thường trong ngành hàng hải, chưa thấy dấu hiệu chuyển giá hay rút vốn bất thường.', 'Doanh nghiệp không có các khoản vay ngân hàng hay trái phiếu phát hành; nợ chủ yếu là phải trả người bán và các khoản phải trả khác với giá trị vừa phải. Tỷ lệ nợ trên tổng tài sản thấp, áp lực thanh toán ngắn hạn không đáng kể.', 'Hàng tồn kho bao gồm công cụ dụng cụ và hàng hóa có giá trị nhỏ, không có dự phòng giảm giá. Tuy nhiên, hàng hóa có thể chịu rủi ro obsolescence do đặc thù ngành thương mại dịch vụ.', 3, 'Công ty có cấu trúc tài chính lành mạnh với nợ thấp và dòng tiền ổn định. Tuy nhiên, kết quả kinh doanh năm 2018 ghi nhận lỗ ròng do giá vốn tăng cao và chi phí quản lý lớn. Ban lãnh đạo có biến động (miễn nhiệm, bổ nhiệm) nhưng không gây xáo trộn lớn. Triển vọng phụ thuộc vào hiệu quả hoạt động kinh doanh cốt lõi và quản lý chi phí.'),
('VMS_2019_consolidated', 'VMS', 2019, 'consolidated', 'Giao dịch mua bán với Công ty TNHH Khai thác Container Việt Nam (cùng Tổng Công ty) có giá trị rất lớn: mua vào 23,68 tỷ đồng và bán ra 8,91 tỷ đồng, chiếm tỷ trọng đáng kể trong doanh thu và giá vốn. Phải thu từ bên liên quan 4,13 tỷ, phải trả 9,45 tỷ. Giao dịch thuộc hoạt động cốt lõi logistics nhưng quy mô lớn so với tổng doanh thu 237,86 tỷ, cần lưu ý rủi ro chuyển giá hoặc ưu đãi không minh bạch trong nội bộ tập đoàn. Ngoài ra, khoản đặt cọc 20 tỷ từ Công ty Ngọc Việt (không phải bên liên quan chính thức) cho hợp tác dự án Bắc Rạch Chiếc được hạch toán vừa ở đầu tư tài chính vừa ở phải trả, cho thấy cơ chế tài chính dự án phức tạp.', 'Công ty không có nợ vay ngân hàng hay trái phiếu phát hành. Toàn bộ nghĩa vụ nợ 109,26 tỷ đồng bao gồm phải trả người bán ngắn hạn (20,78 tỷ) và phải trả khác. Đáng chú ý nhất là khoản tiền đặt cọc dự án của CBCNV tại Chi nhánh Hồ Chí Minh lên tới 43,98 tỷ đồng (dài hạn) và lãi phát sinh 9,25 tỷ đồng – đây là nghĩa vụ bất thường, có thể liên quan đến huy động vốn nội bộ cho dự án bất động sản. Tỷ lệ nợ/vốn chủ sở hữu là 0,74 lần, ở mức hợp lý nhưng chất lượng nợ không cao khi phần lớn là nghĩa vụ dự án và đặt cọc, không phải nợ thương mại thông thường.', 'Hàng tồn kho thông thường chỉ 2,51 tỷ đồng, quy mô nhỏ và không trích lập dự phòng. Tuy nhiên, rủi ro lớn nhất nằm ở Chi phí xây dựng cơ bản dở dang lên tới 48,69 tỷ đồng, chiếm 19% tổng tài sản, tập trung vào hai dự án bất động sản Bắc Rạch Chiếc tại Quận 9 TP.HCM. Các dự án này đã tồn tại nhiều năm (số dư đầu năm đã là 48,29 tỷ) với tốc độ giải ngân rất chậm. Đặc biệt, TM VIII.05 cho thấy dự án đang vướng tranh chấp đất phức tạp với Công ty Vĩnh Lộc và nghĩa vụ hoán đổi đất với SACA chưa hoàn tất. Rủi ro dự án đình trệ, chậm tiến độ và tiềm ẩn nghĩa vụ tài chính phát sinh là rất cao.', 6, 'Công ty Cổ phần Phát triển Hàng hải là công ty con (51%) của Tổng Công ty Hàng Hải Việt Nam – doanh nghiệp nhà nước. Hoạt động kinh doanh chính gồm dịch vụ logistics, vận tải biển và kinh doanh bất động sản. Doanh thu thuần năm 2019 đạt 237,86 tỷ đồng, lợi nhuận sau thuế 6,37 tỷ đồng, tăng so với năm trước. Công ty không có nợ vay tài chính chính thức, dòng tiền kinh doanh dương 1,83 tỷ. Tuy nhiên, tồn tại nhiều rủi ro: (1) Dự án bất động sản Bắc Rạch Chiếc chiếm 48,69 tỷ đồng vốn đầu tư nhưng dậm chân tại chỗ nhiều năm do tranh chấp pháp lý đất đai; (2) Khoản đầu tư vào Công ty TNHH Sửa chữa Tàu biển Vinalines bị trích lập dự phòng 22,4 tỷ (66,7% giá trị gốc), cho thấy tổn thất lớn; (3) Nợ phải trả dài hạn 53,39 tỷ chủ yếu là tiền đặt cọc dự án của CBCNV – cơ chế tài chính bất thường; (4) Ban lãnh đạo thay đổi Tổng Giám đốc và Kế toán trưởng trong năm. Ý kiến kiểm toán chấp nhận toàn phần nhưng rủi ro tài chính tập trung vào tiến độ và pháp lý các dự án bất động sản.'),
('VMS_2017_consolidated', 'VMS', 2017, 'consolidated', 'Công ty có nhiều giao dịch với bên liên quan, bao gồm công ty mẹ và các công ty liên kết, với giá trị lớn. Các khoản phải thu từ bên liên quan không có đảm bảo, không tính lãi và có thời hạn ngắn (30-60 ngày), tiềm ẩn rủi ro chiếm dụng vốn hoặc giao dịch không công bằng.', 'Nợ vay chủ yếu là khoản góp vốn của nhân viên cho dự án bất động sản và các khoản phải trả khác. Dự án Bắc Rạch Chiếc đang bị đình trệ, có thể ảnh hưởng đến khả năng trả nợ. Tỷ lệ nợ trên vốn chủ sở hữu khoảng 0.7 lần, ở mức trung bình. Có khoản lãi phải trả với lãi suất 5,2-5,3% mỗi năm.', 'Hàng tồn kho có giá trị thấp và không có dự phòng giảm giá. Tuy nhiên, các dự án xây dựng dở dang có giá trị lớn (khoảng 42 tỷ VND) và đang bị đình trệ, có nguy cơ đọng vốn và cần trích lập dự phòng.', 6, 'Doanh nghiệp có hoạt động kinh doanh đa dạng nhưng gặp khó khăn với dự án bất động sản bị đình trệ và tranh chấp đất đai. Tình hình tài chính trung bình với nợ phải trả lớn và hàng tồn kho có rủi ro. Doanh thu và lợi nhuận biến động, cần theo dõi tiến độ giải quyết tranh chấp và khả năng thanh toán nợ.'),
('VMS_2015_consolidated', 'VMS', 2015, 'consolidated', 'Công ty có nhiều giao dịch với công ty mẹ Tổng Công ty Hàng Hải Việt Nam bao gồm chi trả cổ tức, chia lãi hợp đồng hợp tác kinh doanh, nộp thuế TNDN hộ và thanh toán khấu hao tòa nhà. Tổng giá trị giao dịch lớn nhưng chủ yếu là các hoạt động tài chính thông thường giữa công ty con và công ty mẹ. Tuy nhiên, khoản thuế TNDN nộp hộ và bù trừ công nợ có thể làm giảm tính minh bạch.', 'Công ty không có nợ vay ngân hàng hay trái phiếu. Nợ phải trả chủ yếu là phải trả thương mại ngắn hạn và các khoản phải trả dài hạn khác bao gồm ký quỹ, ký cược và vốn góp của CBNV dự án Bắc Rạch Chiếc. Tỷ lệ nợ/VCSH ở mức 0.53 lần, áp lực trả nợ thấp.', 'Hàng tồn kho giảm mạnh do giảm nguyên liệu và hàng hóa. Dự án bất động sản (Bắc Rạch Chiếc) có giá trị lớn, đang trong quá trình triển khai, tuy nhiên có tranh chấp đất đai với Công ty TNHH Vĩnh Lộc tại quận 9, TP. Hồ Chí Minh. Dự án Bãi Container Đình Vũ có quy mô nhỏ. Không trích lập dự phòng giảm giá cho dự án.', 4, 'Công ty Cổ phần Phát triển Hàng Hải có kết quả kinh doanh giảm so với năm trước (doanh thu thuần giảm, lợi nhuận sau thuế giảm). Công ty không có nợ vay, tỷ lệ nợ thấp. Hàng tồn kho giảm mạnh. Dự án bất động sản Bắc Rạch Chiếc có tranh chấp đất đai tiềm ẩn rủi ro. Cổ đông nhà nước chi phối. Kiểm toán ý kiến chấp nhận toàn phần.'),
('VMK_2024_consolidated', 'VMK', 2024, 'consolidated', 'Công ty có mối quan hệ bên liên quan phức tạp thông qua Chủ tịch HĐQT Trần Quốc Tuấn - người đồng thời là Tổng giám đốc tại Công ty Cổ phần Zone Việt, Công ty Cổ phần Tập đoàn VGO và Công ty Cổ phần Quốc Bảo Vạn Ninh. Tuy nhiên, báo cáo không công bố giao dịch cụ thể nào với các công ty này. Có khoản vay cá nhân ngắn hạn 2,3 tỷ VND nhưng không rõ đối tượng cho vay và lãi suất. Hội đồng quản trị và Ban Kiểm soát không nhận thù lao/thu nhập, chỉ có Ban Tổng giám đốc nhận lương.', 'Tổng nợ phải trả 41,8 tỷ VND, tỷ lệ nợ/vốn chủ sở hữu 0,86 lần ở mức hợp lý. Chi phí lãi vay năm 2024 là 1,77 tỷ VND. Nợ vay chủ yếu từ hai ngân hàng lớn (MB Bank và Vietcombank) phục vụ đầu tư dự án điện mặt trời và mua biệt thự. Nguyên giá TSCĐ dùng để thế chấp là 40,99 tỷ VND. Công ty đã trả nợ gốc 8,01 tỷ VND trong năm và vay mới 2,3 tỷ VND. Áp lực trả nợ trung hạn vẫn đáng kể với 19,94 tỷ VND nợ dài hạn.', 'Hàng tồn kho 2,78 tỷ VND toàn bộ là chi phí sản xuất kinh doanh dở dang (gỗ 2,67 tỷ và trồng rừng 109 triệu), chưa trích lập dự phòng giảm giá. Dự án biệt thự A4-06A tại Khu đô thị Xanh Villas trị giá 20,86 tỷ VND là bất động sản đầu tư, đã nhận bàn giao từ 11/2022 nhưng chưa xác định giá trị hợp lý do chưa có đơn vị tư vấn. Dự án biệt thự nhà vườn vẫn đang trong quá trình hoàn thiện với hợp đồng 8,75 tỷ VND.', 5, 'Công ty Cổ phần Vimarko hoạt động trong lĩnh vực sản xuất điện mặt trời áp mái và kinh doanh vật liệu xây dựng. Năm 2024, doanh thu đạt 54,08 tỷ VND, lợi nhuận sau thuế 5,99 tỷ VND (tăng 61% so với năm trước). Kiểm toán viên UHY đưa ra ý kiến chấp nhận toàn phần. Công ty được miễn thuế TNDN 4 năm đầu từ dự án điện mặt trời. Cấu trúc tài chính tương đối lành mạnh với nợ/vốn 0,86 lần. Tuy nhiên, Chủ tịch HĐQT có mối quan hệ với nhiều công ty khác, và bất động sản đầu tư chưa được định giá hợp lý. Công ty đang lên kế hoạch phát hành thêm 3,115 triệu cổ phiếu với mệnh giá 31,15 tỷ VND để tăng vốn.'),
('VMG_2024_consolidated', 'VMG', 2024, 'consolidated', 'Rủi ro cao. Công ty có mạng lưới giao dịch phức tạp với nhiều bên liên quan là các công ty cùng chịu chi phối bởi Hội đồng Quản trị hoặc Ban Kiểm soát. Tổng giá trị mua hàng từ các bên liên quan lên tới 373.6 tỷ VND và bán hàng 235.3 tỷ VND trong năm 2024. Có các khoản cho vay cá nhân lớn (5 tỷ VND cho ông Đặng Trần Hồng Quân) và nhận vay từ cá nhân (38.8 tỷ VND từ ông Nguyễn Thanh Tùng) với lãi suất cao 15-15.5%/năm mà không có tài sản đảm bảo. Điều này tiềm ẩn rủi ro về tính công bằng của giá cả giao dịch và an toàn vốn.', 'Rủi ro rất cao. Cơ cấu nợ mất cân đối nghiêm trọng với nợ ngắn hạn (84.2 tỷ VND) vượt xa tài sản ngắn hạn (78.5 tỷ VND). Tổng nợ phải trả (128.0 tỷ VND) gấp gần 10 lần vốn chủ sở hữu (13.3 tỷ VND). Gánh nặng lãi vay lớn (chi phí lãi vay 8.7 tỷ VND trong năm 2024), chiếm tỷ trọng cao trong kết quả kinh doanh. Các khoản vay cá nhân chiếm tỷ trọng lớn và không có tài sản đảm bảo, tạo áp lực trả nợ và rủi ro đột ngột.', 'Rủi ro trung bình. Hàng tồn kho chủ yếu là hàng hóa (LPG) có tính thanh khoản cao, không có dự phòng giảm giá. Dự án xây dựng dở dang (chi phí lập hồ sơ đất Bến Cát) có giá trị tăng từ 423.5 triệu lên 1.024 tỷ VND trong năm, liên quan đến pháp lý đất đai phức tạp, nhưng quy mô còn nhỏ so với tổng tài sản.', 8, 'Tình hình tài chính của Công ty rất đáng lo ngại. Công ty đang hoạt động trong trạng thái thua lỗ lũy kế lớn (-121.3 tỷ VND), dòng tiền kinh doanh dù dương nhưng chủ yếu dựa vào việc tăng nợ phải trả. Cấu trúc tài chính mất an toàn với nợ ngắn hạn vượt tài sản ngắn hạn, tỷ lệ nợ/VCSH cực cao. Kiểm toán viên đã đưa ra ý kiến ngoại trừ và nhấn mạnh về nghi ngờ khả năng hoạt động liên tục. Mạng lưới giao dịch với bên liên quan phức tạp, tiềm ẩn rủi ro quản trị. Triển vọng đầu tư tiêu cực, chỉ phù hợp cho nhà đầu tư chấp nhận rủi ro rất cao.'),
('VMG_2025_consolidated', 'VMG', 2025, 'consolidated', 'Công ty có nhiều giao dịch mua bán LPG và dịch vụ với các bên liên quan, đặc biệt là Công ty Cổ phần Năng lượng Long Yin Long An có khoản phải thu lớn 22,8 tỷ VND. Các khoản phải thu từ Công ty TNHH Đầu tư Minh Quang và Công ty CP Dầu khí và Khoáng sản Quốc tế PASC đã trích lập dự phòng toàn bộ. Mặc dù các giao dịch thuộc hoạt động kinh doanh cốt lõi, nhưng quy mô và mức độ liên quan phức tạp đòi hỏi giám sát chặt chẽ.', 'Rủi ro nợ vay rất cao. Tổng nợ vay 59,17 tỷ VND, nợ ngắn hạn vượt tài sản ngắn hạn 21,5 tỷ VND. Công ty đang chịu lỗ lũy kế 147,4 tỷ VND làm âm vốn chủ sở hữu. Nợ cá nhân chiếm tỷ trọng lớn với lãi suất cao (13%-15,5%/năm). Tài sản đảm bảo chủ yếu là bất động sản nhưng quyền sử dụng đất tại trụ sở chính đang tranh chấp. Áp lực trả nợ và duy trì hoạt động liên tục cực kỳ lớn.', 'Rủi ro hàng tồn kho thấp. Hàng tồn kho giảm mạnh từ 2,8 tỷ xuống 1,4 tỷ VND, chủ yếu là hàng hóa LPG và không trích lập dự phòng. Chi phí xây dựng dở dang chỉ là chi phí pháp lý đất, không có dự án bất động sản lớn hoặc đình trệ.', 7, 'Doanh nghiệp đang trong tình trạng tài chính nghiêm trọng với lỗ lũy kế lớn, âm vốn chủ sở hữu và nợ ngắn hạn vượt quá tài sản ngắn hạn. Kiểm toán viên đã nhấn mạnh nghi ngờ lớn về khả năng hoạt động liên tục. Cơ cấu nợ phức tạp với lãi suất cao từ các khoản vay cá nhân. Ban điều hành đang triển khai kế hoạch tái cơ cấu, nhưng triển vọng phụ thuộc lớn vào khả năng thu hồi nợ và cải thiện kinh doanh. Rủi ro đầu tư rất cao.'),
('VMG_2022_consolidated', 'VMG', 2022, 'consolidated', 'Công ty có giao dịch mua bán lớn với các bên liên quan là Công ty TNHH Thương mại Dầu Khí TPHCM và Công ty Cổ phần Xuất nhập khẩu Năng lượng Tp. Hồ Chí Minh. Tổng giá trị mua bán với các bên này chiếm tỷ trọng đáng kể trong hoạt động kinh doanh. Có các khoản cho vay cá nhân lớn (ông Lương Quốc Nam 3,69 tỷ VND) với lãi suất 8%/năm, thời hạn dài. Các giao dịch này cần được giám sát chặt chẽ để đảm bảo tính minh bạch và công bằng.', 'Nợ vay ngắn hạn rất lớn (60,5 tỷ VND) tập trung tại 4 ngân hàng thương mại, lãi suất dao động từ 9% đến theo thỏa thuận. Tổng nợ vay (ngắn và dài hạn) chiếm tỷ trọng cao trên tổng tài sản. Áp lực trả nợ ngắn hạn rất lớn do nợ ngắn hạn vượt quá tài sản ngắn hạn 44,27 tỷ VND. Có khoản vay cá nhân lớn 8 tỷ VND từ ông Nguyễn Thanh Tùng với lãi suất cao 15%/năm không có tài sản đảm bảo.', 'Hàng tồn kho có giá trị tương đối nhỏ (1,27 tỷ VND) và không trích lập dự phòng. Tuy nhiên, Công ty có khoản xây dựng cơ bản dở dang lớn (7,13 tỷ VND) cho hạ tầng chi nhánh Bến Cát và Gò Dầu. Các dự án này đang trong quá trình triển khai và cần được theo dõi tiến độ để tránh đọng vốn kéo dài.', 8, 'Doanh nghiệp đối mặt với rủi ro tài chính nghiêm trọng. Kiểm toán đưa ra ý kiến ngoại trừ do tài sản tranh chấp và nhấn mạnh mối lo ngại về khả năng hoạt động liên tục. Nợ ngắn hạn vượt quá tài sản ngắn hạn, Công ty lỗ lũy kế lớn (115,4 tỷ VND), dòng tiền hoạt động kinh doanh âm. Giao dịch với bên liên quan lớn, nợ vay cá nhân lãi suất cao. Ban lãnh đạo đã đưa ra kế hoạch xử lý tài sản và tìm kiếm nguồn vốn, nhưng rủi ro vẫn ở mức rất cao. Điểm rủi ro quản trị cao do cấu trúc phức tạp, giao dịch nội bộ lớn và tình hình tài chính bất ổn.'),
('VMG_2021_consolidated', 'VMG', 2021, 'consolidated', 'Rủi ro cao. Công ty có quan hệ giao dịch lớn với Công ty TNHH Thương mại Dầu Khí TPHCM (cùng thành viên quản lý chủ chốt) với tổng giá trị mua hàng hóa hơn 214 tỷ VND và bán hàng/dịch vụ hơn 6,5 tỷ VND. Đáng chú ý, Công ty cho Tổng Giám đốc Lương Quốc Nam vay 3,69 tỷ VND, và Kế toán trưởng Đặng Trần Hồng Quân vay Công ty 1 tỷ VND với lãi suất 20%/năm (cao hơn nhiều so với lãi suất ngân hàng). Ngoài ra, ông Đặng Trần Hồng Quân - Kế toán trưởng đồng thời là người được ủy quyền công bố thông tin - còn có khoản mượn tài sản và phải trả lãi vay cho Công ty. Các giao dịch với cá nhân ban lãnh đạo có tính chất đan xen quyền lợi, đặt ra câu hỏi về tính minh bạch và công bằng.', 'Rủi ro rất cao. Tổng nợ vay 46,59 tỷ VND, trong đó nợ ngắn hạn 38,59 tỷ VND và nợ dài hạn 8 tỷ VND. Tỷ lệ nợ/Vốn chủ sở hữu đạt 2,2 lần, mức rất cao. Nợ ngắn hạn ngân hàng chủ yếu tại 4 ngân hàng thương mại với tài sản đảm bảo là bất động sản của ban lãnh đạo (ông Đặng Trần Hồng Quân, ông Lương Quốc Nam). Các khoản vay cá nhân với lãi suất cao (15-20%/năm) cho thấy Công ty gặp khó khăn trong tiếp cận tín dụng ngân hàng. Nợ ngắn hạn vượt tài sản ngắn hạn 43 tỷ VND tạo áp lực thanh toán nghiêm trọng. Áp lực chi phí lãi vay năm 2021 là 3,45 tỷ VND, chiếm tỷ trọng lớn so với lợi nhuận thuần từ kinh doanh chỉ 579 triệu VND.', 'Rủi ro trung bình. Hàng tồn kho giảm mạnh từ 4,48 tỷ xuống 803 triệu VND, chủ yếu do hàng hóa bán ra. Không có dự phòng giảm giá hàng tồn kho. Các dự án xây dựng cơ bản dở dang (hạ tầng Bến Cát và Gò Dầu) trị giá 4,26 tỷ VND là khoản đầu tư mới trong năm, cần theo dõi tiến độ và khả năng thu hồi vốn. Đáng lo ngại nhất là Quyền sử dụng đất tại 52 Lý Thường Kiệt trị giá 932 triệu VND đang trong tranh chấp pháp lý kéo dài hơn 10 năm, có nguy cơ mất trắng nếu Công ty thua kiện.', 9, 'Công ty Cổ phần Thương mại và Dịch vụ Dầu khí Vũng Tàu (VMG) đang trong tình trạng tài chính rất yếu. Lỗ lũy kế lên đến 113,4 tỷ VND vượt xa vốn điều lệ 96 tỷ VND. Kiểm toán viên CPA VIETNAM đã đưa ra ý kiến ngoại trừ do tranh chấp pháp lý quyền sử dụng đất tại 52 Lý Thường Kiệt và nhấn mạnh về khả năng hoạt động liên tục. Nợ ngắn hạn vượt tài sản ngắn hạn 43 tỷ VND, lưu chuyển tiền thuần âm liên tiếp. Công ty có nợ xấu khổng lồ 39 tỷ VND (chiếm hơn 37% tổng tài sản). Các giao dịch với bên liên quan phức tạp, đặc biệt khoản cho vay Tổng Giám đốc 3,69 tỷ VND và khoản vay từ Kế toán trưởng với lãi suất 20%/năm. Ban lãnh đạo đã thay đổi lớn trong năm (miễn nhiệm Chủ tịch HĐQT và nhiều thành viên HĐQT, Ban Kiểm soát). Công ty phụ thuộc lớn vào Công ty TNHH Thương mại Dầu Khí TPHCM trong hoạt động mua bán hàng hóa. Triển vọng đầu tư rất tiêu cực.');
INSERT OR REPLACE INTO `financial_insights` (`id`, `ticker`, `year`, `report_type`, `related_party_risk`, `debt_risk`, `inventory_risk`, `governance_risk_score`, `overall_analysis`) VALUES
('VMG_2020_consolidated', 'VMG', 2020, 'consolidated', 'Giao dịch với bên liên quan, đặc biệt là Công ty TNHH An Thuận, chiếm tỷ trọng lớn trong doanh thu (80,6 tỷ VND) và công nợ phải thu (14,3 tỷ VND). Các giao dịch mượn hàng, cho mượn hàng và mượn tiền với thành viên quản lý có quy mô lớn. Dù chưa thấy dấu hiệu rút ruột rõ ràng, nhưng tập trung giao dịch cao tạo rủi ro xung đột lợi ích và ảnh hưởng đến tính minh bạch.', 'Nợ vay tổng cộng 41,2 tỷ VND, trong đó nợ ngắn hạn 40,8 tỷ VND vượt tài sản ngắn hạn 30,7 tỷ VND, gây áp lực thanh khoản nghiêm trọng. Khoản lỗ lũy kế 100,5 tỷ VND và nợ ngắn hạn vượt tài sản ngắn hạn dẫn đến nghi ngờ về khả năng hoạt động liên tục. Lãi suất vay ngân hàng từ 10-11%/năm, khoản vay từ chủ tịch 8%/năm, làm tăng chi phí tài chính.', 'Hàng tồn kho có giá trị thấp (4,5 tỷ VND), chủ yếu là hàng hóa thành phẩm và công cụ dụng cụ, không có dự phòng giảm giá. Rủi ro đọng vốn thấp, nhưng doanh nghiệp kinh doanh khí hóa lỏng nên cần theo dõi biến động giá và thanh khoản.', 7, 'Doanh nghiệp gặp khó khăn tài chính nghiêm trọng với ý kiến kiểm toán ngoại trừ, khoản lỗ lũy kế lớn, và nợ ngắn hạn vượt tài sản ngắn hạn. Giao dịch với bên liên quan đáng kể, đặc biệt với Công ty TNHH An Thuận và các thành viên quản lý. Ban lãnh đạo đã thay đổi và bán toàn bộ cổ phiếu sau ngày kết thúc kỳ kế toán, làm tăng rủi ro quản trị. Triển vọng đầu tư tiêu cực trong ngắn hạn, cần theo dõi chặt chẽ khả năng tái cơ cấu nợ và hoạt động kinh doanh.'),
('VMG_2019_consolidated', 'VMG', 2019, 'consolidated', 'Công ty có giao dịch mua bán lớn với Công ty TNHH An Thuận (do Chủ tịch HĐQT Nguyễn Quang Ninh làm giám đốc). Ngoài ra, công ty vay vốn lớn từ chính Chủ tịch HĐQT (hơn 22 tỷ VND) và Kế toán trưởng (2.3 tỷ VND), với lãi suất từ 8-11%/năm, tiềm ẩn rủi ro về xung đột lợi ích và dòng tiền chảy ra ngoài công ty.', 'Nợ vay tăng mạnh, đặc biệt là nợ dài hạn từ cá nhân (Chủ tịch HĐQT) với lãi suất cao 8%/năm. Tỷ lệ nợ thuần/vốn chủ sở hữu tăng từ 0.29 lên 0.56. Công ty cũng thế chấp xe bồn và quyền sử dụng đất cho khoản vay ngân hàng. Áp lực trả nợ và chi phí lãi vay là đáng kể.', 'Hàng tồn kho chủ yếu là hàng hóa (khí hóa lòng) và công cụ dụng cụ, không có dự phòng giảm giá. Tuy nhiên, công ty đã xử lý khoản thiếu hụt tồn kho lớn từ các năm trước (hơn 4.2 tỷ VND) làm giảm lợi nhuận chưa phân phối, cho thấy công tác kiểm soát nội bộ tồn kho từng có vấn đề.', 7, 'Tình hình tài chính của công ty gặp nhiều thách thức: hoạt động kinh doanh cốt lõi thua lỗ, lỗ lũy kế lớn, nợ ngắn hạn vượt tài sản ngắn hạn, dẫn đến nghi ngờ về hoạt động liên tục. Ban lãnh đạo có nhiều giao dịch vay mượn lớn với công ty, gây xung đột lợi ích. Ý kiến kiểm toán ngoại trừ do xử lý thiếu hụt tồn kho quá khứ làm sai lệch kết quả kinh doanh các năm trước.'),
('VMG_2018_consolidated', 'VMG', 2018, 'consolidated', 'Giao dịch với Công ty TNHH An Thuận (vợ Tổng Giám đốc) và Công ty CP Hưng Hà (Tổng Giám đốc đại diện) có giá trị lớn trong mua bán khí hóa lỏng, chiếm tỷ trọng đáng kể trong doanh thu và chi phí. Các khoản vay cá nhân từ Tổng Giám đốc với lãi suất 8%/năm cũng đáng lưu ý. Tuy nhiên, chưa có bằng chứng rõ ràng về chuyển giá hay rút vốn, nhưng rủi ro quản trị do xung đột lợi ích là cao.', 'Nợ vay ngắn hạn lớn, trong đó nợ cá nhân chiếm phần lớn với lãi suất 8%/năm, áp lực trả nợ cao do lỗ lũy kế và nợ ngắn hạn vượt tài sản ngắn hạn. Nợ dài hạn ngân hàng lãi suất 10,5%/năm, thế chấp bằng phương tiện vận tải. Khả năng thanh toán phụ thuộc vào hoạt động kinh doanh và hỗ trợ tài chính, rủi ro vỡ nợ ở mức trung bình đến cao.', 'Hàng tồn kho chủ yếu là hàng hóa và công cụ dụng cụ, trị giá hơn 9 tỷ VND, không trích lập dự phòng. Tuy nhiên, có khoản tài sản thiếu chờ xử lý 5,6 tỷ VND từ hao hụt khí gas từ năm 2011-2017 chưa xử lý, cho thấy vấn đề quản lý tồn kho và rủi ro tổn thất tiềm tàng.', 8, 'Doanh nghiệp hoạt động trong lĩnh vực thương mại dầu khí, có doanh thu tăng nhưng lỗ lũy kế lớn, nợ vay cao và cấu trúc tài chính yếu. Giao dịch với bên liên quan phức tạp, quản trị rủi ro kém. Kiểm toán viên đưa ra ý kiến ngoại trừ và cảnh báo về khả năng hoạt động liên tục. Triển vọng đầu tư tiêu cực, cần theo dõi chặt chẽ.'),
('VMG_2017_consolidated', 'VMG', 2017, 'consolidated', 'Giao dịch mua bán khí hóa lỏng với Công ty TNHH An Thuận có giá trị lớn (mua 77 tỷ, bán 21 tỷ), thuộc hoạt động kinh doanh chính. Tuy nhiên, công ty có vay cá nhân từ Tổng Giám đốc với lãi suất thấp hơn thị trường (8%/năm) so với vay ngân hàng (10,5%/năm), có thể tiềm ẩn rủi ro xung đột lợi ích.', 'Nợ vay tăng mạnh trong năm, đặc biệt vay cá nhân từ Tổng Giám đốc 15,4 tỷ VNĐ với lãi suất 8%/năm. Nợ ngắn hạn vượt tài sản ngắn hạn, áp lực thanh khoản cao. Công ty có lỗ lũy kế lớn, khả năng trả nợ phụ thuộc vào hoạt động kinh doanh.', 'Hàng tồn kho tăng từ 9,2 tỷ lên 12,4 tỷ, trong đó hàng hóa chiếm phần lớn. Có khoản tài sản thiếu chờ xử lý 4,1 tỷ chưa được xử lý, tiềm ẩn rủi ro mất vốn. Không có dự án xây dựng dở dang.', 7, 'Doanh nghiệp gặp khó khăn tài chính nghiêm trọng với lỗ lũy kế lớn, nợ ngắn hạn vượt tài sản ngắn hạn. Ý kiến kiểm toán ngoại trừ về khoản hàng tồn kho thiếu. Tuy nhiên, doanh thu tăng trưởng mạnh trong năm 2017, lợi nhuận gộp cải thiện. Cần theo dõi khả năng tạo tiền từ hoạt động kinh doanh và xử lý các khoản nợ.'),
('VMG_2016_consolidated', 'VMG', 2016, 'consolidated', 'Công ty TNHH An Thuận (Giám đốc là vợ của Tổng Giám đốc Nguyễn Quang Ninh) là đối tác kinh doanh lớn nhất: mua khí hóa lỏng chiếm khoảng 81% giá vốn hàng bán (107,8 tỷ/133 tỷ), bán khí hóa lỏng chiếm 18,7% doanh thu. Phải trả An Thuận chiếm 75% tổng phải trả người bán ngắn hạn (29,84/39,59 tỷ). Khoản phải thu khách hàng chưa nhận được xác nhận lên tới 29,95 tỷ VND. Giao dịch tập trung lớn với bên liên quan thân nhân, kết hợp với công nợ không được xác nhận, đặt ra rủi ro về tính minh bạch và khả năng thu hồi công nợ.', 'Nợ vay ngắn hạn đã được trả hết trong năm (1,294 tỷ VND). Tuy nhiên, Công ty còn 7,89 tỷ VND phải trả dài hạn khác (ký quỹ, ký cược) và 39,59 tỷ VND phải trả người bán ngắn hạn. Nợ ngắn hạn vượt tài sản ngắn hạn 18,61 tỷ VND cho thấy áp lực thanh khoản nghiêm trọng. Các khoản vay cũ có lãi suất rất cao (34,5%/năm từ Đông Á Bank, 1%/tháng từ cá nhân) phản ánh rủi ro tín dụng cao và khó tiếp cận nguồn vốn ưu đãi. Khoản vay cá nhân từ ông Trần Hồng Quân đã quá hạn từ 30/06/2015 nhưng vẫn chưa thanh toán.', 'Hàng tồn kho tăng 32% (từ 6,99 tỷ lên 9,26 tỷ) do tăng hàng hóa kinh doanh. Đặc biệt nghiêm trọng là khoản hàng tồn kho thiếu 4,72 tỷ VND phát sinh từ kiểm kê kho gas lũy kế nhiều năm trước nhưng Công ty chưa xử lý. Nếu ghi nhận vào kết quả kinh doanh, lỗ trước thuế sẽ tăng thêm 4,72 tỷ. Hàng tồn kho chưa trích lập dự phòng giảm giá, trong khi một phần lớn là khí hóa lỏng (LPG) có tính biến động giá và rủi ro hư hỏng, thiếu hụt.', 8, 'Công ty có tình hình tài chính rất yếu: lỗ lũy kế 95,39 tỷ VND (gấp gần 2,5 lần vốn chủ sở hữu 39,16 tỷ), nợ ngắn hạn vượt tài sản ngắn hạn 18,61 tỷ. Kiểm toán đưa ý kiến ngoại trừ do không xác nhận được khoản phải thu/phải trả lớn và hàng tồn kho thiếu 4,72 tỷ chưa xử lý. Ban lãnh đạo do gia đình chi phối (Chủ tịch HĐQT kiêm Tổng Giám đốc, vợ điều hành đối tác lớn nhất). Giao dịch bên liên quan chiếm tỷ trọng rất lớn trong hoạt động mua bán, với công nợ không được xác nhận. Doanh nghiệp đã bị hủy niêm yết từ 2012. Rủi ro đầu tư cực kỳ cao.'),
('VMG_2015_consolidated', 'VMG', 2015, 'consolidated', 'Giao dịch mua bán khí hóa lỏng với Công ty TNHH An Thuận (Giám đốc là vợ của Tổng Giám đốc Nguyễn Quang Ninh) có giá trị rất lớn trong năm: mua vào 90,8 tỷ VND, bán ra 23,5 tỷ VND. Dư nợ phải trả cuối kỳ với An Thuận là 21,5 tỷ VND chiếm tỷ trọng lớn trong tổng nợ phải trả ngắn hạn. Ngoài ra, Công ty có khoản vay cá nhân 1,29 tỷ VND từ ông Đặng Trần Hồng Quân (nguyên Kế toán trưởng) với lãi suất thấp 1%/tháng. Các giao dịch với bên liên quan đặt ra rủi ro về tính minh bạch và công bằng, đặc biệt khi mối quan hệ vợ chồng Tổng Giám đốc chi phối hoạt động mua bán cốt lõi.', 'Tổng nợ ngắn hạn 37,4 tỷ VND vượt xa tài sản ngắn hạn 22,9 tỷ VND tạo áp lực thanh khoản nghiêm trọng. Khoản vay tại DongA Bank chỉ còn 3 triệu VND nhưng đã quá hạn từ năm 2011, chịu rủi ro lãi suất 34.5%/năm nếu không thanh toán đúng cam kết. Khoản vay ông Quân 1,29 tỷ đã quá hạn từ 30/06/2015. Theo ý kiến kiểm toán, có 2,42 tỷ VND lãi vay ngắn hạn chưa được hạch toán đầy đủ. Nợ phải trả dài hạn 8,9 tỷ VND chủ yếu là ký quỹ vỏ bình gas. Tổng nợ phải trả/VCSH ở mức 1,03 lần.', 'Hàng tồn kho tăng 81% từ 3,87 tỷ lên 7,0 tỷ VND, chủ yếu do công cụ dụng cụ tăng vọt 15 lần. Đặc biệt đáng lo ngại là khoản tài sản thiếu chờ xử lý 4,72 tỷ VND là chênh lệch thiếu kiểm kê gas lũy kế nhiều năm chưa được xử lý và chưa trích lập dự phòng. Hàng tồn kho không có dự phòng giảm giá, rủi ro mất vốn cao nếu hàng hóa giảm giá, hư hỏng hoặc lỗi thời.', 8, 'Doanh nghiệp trong tình trạng tài chính rất nghiêm trọng: lỗ lũy kế 89,7 tỷ VND chiếm 93% vốn điều lệ, nợ ngắn hạn vượt tài sản ngắn hạn 14,5 tỷ VND. Hội đồng Quản trị và Ban kiểm soát nhiệm kỳ 2011-2015 chưa được công nhận pháp lý do Tòa Phúc thẩm hủy Nghị quyết ĐHĐCĐ. Người đại diện pháp luật chưa xác định. Kiểm toán đưa ra ý kiến ngoại trừ với 6 vấn đề trọng yếu: người đại diện pháp luật, tài sản thiếu chưa dự phòng, lãi vay chưa hạch toán đầy đủ, quyền sử dụng đất bị thu hồi có tranh chấp, TSCĐVH do thành viên HĐQT đứng tên, khoản phải thu/trả chưa xác nhận. Giao dịch bên liên quan lớn với công ty có quan hệ gia đình Tổng Giám đốc. Ban lãnh đạo tuyên bố có kế hoạch kinh doanh nhưng triển vọng hoạt động liên tục rất rủi ro.'),
('VMD_2025_consolidated', 'VMD', 2025, 'consolidated', 'Có giao dịch với công ty con Vimedimex Bình Dương và đối tác DKSH Việt Nam với tổng giá trị lớn (185 tỷ đồng), yêu cầu đối chiếu và thu hồi, cho thấy rủi ro chiếm dụng vốn hoặc chậm thu hồi từ bên liên quan.', 'Không có thông tin cụ thể về nợ vay trong tài liệu, do đó rủi ro nợ không thể đánh giá chi tiết.', 'Không có thông tin về hàng tồn kho hoặc dự án xây dựng, do đó rủi ro hàng tồn kho không xác định.', 6, 'Báo cáo tài chính giữa niên độ 2025 được soát xét và công bố đính chính do sơ suất in ấn, không ảnh hưởng đến thông tin khác. Tuy nhiên, có giao dịch lớn với bên liên quan cần thu hồi, ám chỉ rủi ro quản trị ở mức trung bình cao. Ý kiến kiểm toán chấp nhận toàn phần, nhưng cần theo dõi việc thu hồi các khoản phải thu từ công ty con và đối tác.'),
('VMC_2024_consolidated', 'VMC', 2024, 'consolidated', 'Công ty có quan hệ giao dịch phức tạp với Tập đoàn mẹ (Tổng Công ty CP Xuất nhập khẩu và Xây dựng Việt Nam) và nhiều công ty thành viên. Các giao dịch mua bán, tạm ứng với các thành viên Ban điều hành có quy mô đáng kể, đặc biệt là các khoản tạm ứng lớn cho Phó Tổng Giám đốc Hoàng Anh Tuyên (hơn 31.8 tỷ) và Kế toán trưởng Trần Thị Hồng (21.6 tỷ). Điều này tiềm ẩn rủi ro về chiếm dụng vốn và thiếu minh bạch trong kiểm soát nội bộ.', 'Nợ vay và nợ thuê tài chính ngắn hạn chiếm tỷ trọng lớn (545.4 tỷ), chủ yếu từ BIDV và VietinBank. Áp lực trả nợ trong năm tới cao. Tài sản thế chấp chính là tiền gửi ngân hàng, máy móc, thiết bị và quyền thu từ dự án. Tuy nhiên, công ty có dòng tiền kinh doanh dương và khả năng trả nợ được đánh giá là ''có khả năng''.', 'Hàng tồn kho chủ yếu là Chi phí sản xuất, kinh doanh dở dang (324.4 tỷ) tập trung vào các dự án hạ tầng giao thông lớn (Cao tốc Bắc Nam, Cảng Long Thành). Đây là các dự án có thời gian triển khai dài, tiềm ẩn rủi ro về tiến độ, biến động giá nguyên vật liệu và việc thu hồi vốn. Không có dự phòng giảm giá hàng tồn kho.', 7, 'Doanh nghiệp có cơ cấu tài chính đòn bẩy cao, phụ thuộc lớn vào vốn vay ngắn hạn để tài trợ cho hoạt động sản xuất kinh doanh và đầu tư dài hạn. Các giao dịch với bên liên quan, đặc biệt là công ty mẹ và các cá nhân trong ban điều hành, phức tạp và có quy mô lớn, đặt ra nghi vấn về chất lượng quản trị. Hàng tồn kho dở dang là các dự án hạ tầng lớn, đòi hỏi nguồn vốn dài hạn và tiềm ẩn rủi ro dự án. Ý kiến kiểm toán chấp nhận toàn phần nhưng công ty đang trong quá trình thay đổi lớn về cơ sở sở hữu (công ty mẹ thoái vốn).'),
('VMC_2023_consolidated', 'VMC', 2023, 'consolidated', 'Giao dịch mua bán, cung cấp dịch vụ với công ty mẹ (Tổng Công ty Cổ phần Xuất nhập khẩu và Xây dựng Việt Nam) và các công ty cùng Tập đoàn có giá trị lớn (tổng doanh thu bán cho bên liên quan đạt 706 tỷ VND, chiếm khoảng 60% doanh thu thuần). Các giao dịch này có tính chất thương mại thông thường, tuy nhiên sự phụ thuộc lớn vào công ty mẹ và Tập đoàn tạo ra rủi ro về tập trung khách hàng và thiếu độc lập kinh doanh. Có khoản cho vay không lãi suất (0%) cho công ty con cũ (Công ty Cổ phần Vimeco Cơ khí và Thương mại) là điểm cần lưu ý về quản trị dòng tiền.', 'Tổng nợ vay và nợ thuê tài chính cuối năm 2023 là 547.932.433.315 VND, trong đó nợ ngắn hạn chiếm phần lớn (514.842.367.136 VND). Tỷ lệ nợ vay/vốn chủ sở hữu ở mức cao (1.55 lần). Các khoản vay chủ yếu từ BIDV và VietinBank với lãi suất dao động từ 6,5% đến 11%/năm, áp lực chi phí lãi vay lớn (50,6 tỷ VND trong năm). Tài sản đảm bảo bao gồm tiền gửi ngân hàng, máy móc, thiết bị. Áp lực trả nợ ngắn hạn là đáng kể.', 'Hàng tồn kho cuối kỳ có giá trị 325.582.153.885 VND, giảm so với đầu năm (374.438.339.963 VND). Phần lớn là chi phí sản xuất kinh doanh dở dang (chiếm 98.8%) liên quan đến các dự án xây dựng lớn (Long Thành, Nội Bài, Đại lộ Hòa Bình). Các dự án này có thời gian triển khai dài, tiềm ẩn rủi ro về tiến độ, chi phí phát sinh và khả năng thu hồi vốn. Công ty chưa trích lập dự phòng giảm giá hàng tồn kho.', 6, 'Công ty hoạt động trong lĩnh vực xây lắp và sản xuất bê tông, có doanh thu tăng trưởng tốt (27.6%) nhưng lợi nhuận sau thuế tăng chậm (68.6%) do chi phí tài chính tăng mạnh (99.5%). Sức khỏe tài chính có áp lực nợ vay lớn, dòng tiền từ hoạt động kinh doanh âm (-56 tỷ VND). Phụ thuộc lớn vào các giao dịch với công ty mẹ và Tập đoàn. Ban lãnh đạo có biến động trong năm. Khả năng hoạt động liên tục được kiểm toán xác nhận nhưng cần theo dõi sát diễn biến nợ và tiến độ các dự án xây dựng dở dang.'),
('VMC_2025_consolidated', 'VMC', 2025, 'consolidated', 'Rủi ro cao. Doanh thu bán hàng cho bên liên quan (Tổng Công ty Cổ phần Xuất nhập khẩu và Xây dựng Việt Nam) chiếm khoảng 75% tổng doanh thu (611 tỷ/817 tỷ đồng). Khoản phải thu từ Tổng Công ty này lên tới 136,6 tỷ đồng và khoản người mua trả trước 109,1 tỷ đồng, tạo sự phụ thuộc lớn vào một bên liên quan có cùng thành viên quản lý chủ chốt. Đặc biệt đáng lo ngại là khoản vay dài hạn 30,8 tỷ đồng từ Công ty Cổ phần Vinaconex Bắc Ninh (công ty liên kết) với lãi suất 0%/năm, cho thấy giao dịch không theo giá thị trường. Có khoản vay cá nhân 1 tỷ đồng không lãi suất từ Ông Đoàn Trung Thành. Tổng cộng các khoản tạm ứng cá nhân cho cán bộ nhân viên lên tới 97,2 tỷ đồng, một số cá nhân có số dư lớn (ông Phạm Văn Vi 12,8 tỷ, ông Bùi Doãn Đức 11,5 tỷ).', 'Áp lực nợ vay cao. Tỷ lệ nợ vay/Vốn chủ sở hữu ở mức 1,58 lần (547,3 tỷ/347,2 tỷ). Nợ vay ngắn hạn chiếm phần lớn (506,9 tỷ/547,3 tỷ), áp lực thanh toán trong 12 tháng tới rất lớn. Chi phí lãi vay năm 2025 là 39,9 tỷ đồng, trong khi dòng tiền thuần từ hoạt động kinh doanh chỉ đạt 34,2 tỷ đồng. Lãi suất vay ngân hàng dao động 6,3%-8,8%/năm. Tài sản đảm bảo chủ yếu là hợp đồng tiền gửi ngân hàng, máy móc thiết bị và tài sản hình thành từ vốn vay. Nợ thuê tài chính (BIDV-Sumi Trust) lãi suất 6,5%-7,4%/năm có tổng nợ gốc và lãi phải trả 11,2 tỷ đồng. Có khoản vay cá nhân không lãi suất 1 tỷ đồng cho thấy dấu hiệu giao dịch không bình thường.', 'Rủi ro trung bình. Hàng tồn kho dở dang (chi phí sản xuất kinh doanh dở dang) chiếm 266,6 tỷ đồng trên tổng hàng tồn kho 271,1 tỷ đồng (98,3%), tập trung vào các dự án hạ tầng giao thông trọng điểm quốc gia (Cao tốc Bắc Nam, Cảng hàng không quốc tế Long Thành, Cao tốc Tuyên Quang - Hà Giang). Không có dự phòng giảm giá hàng tồn kho được trích lập. Doanh thu xây lắp giảm mạnh 44% so với năm trước, cho thấy tiến độ thi công có thể bị ảnh hưởng bởi thiếu hụt nguồn lực tài chính. Dự án Long Thành chiếm tỷ trọng lớn (41,3 tỷ) và mới bắt đầu triển khai (tăng từ 4,7 tỷ lên 41,3 tỷ trong năm). Rủi ro đọng vốn nếu dự án chậm tiến độ hoặc tranh chấp hợp đồng.', 6, 'Doanh nghiệp đang trong giai đoạn khó khăn tài chính. Lợi nhuận sau thuế năm 2025 âm 9,65 tỷ đồng (năm trước lãi 3,21 tỷ). Doanh thu giảm 27% do thiếu vắng các dự án trọng điểm đã hoàn thành. Tỷ lệ nợ vay/VCSH cao 1,58 lần, trong đó nợ ngắn hạn chiếm 93% tổng nợ vay. Dòng tiền từ hoạt động kinh doanh chỉ đạt 34,2 tỷ, không đủ bù đắp nghĩa vụ nợ ngắn hạn. Phụ thuộc lớn vào Tổng Công ty Cổ phần Xuất nhập khẩu và Xây dựng Việt Nam (cùng thành viên quản lý) cho 75% doanh thu. Nhiều giao dịch với bên liên quan phức tạp, bao gồm vay không lãi suất từ công ty liên kết, khoản tạm ứng cá nhân lớn cho ban lãnh đạo. Lợi nhuận từ thanh lý tài sản cố định (11,2 tỷ) là nguồn thu quan trọng bù đắp lỗ kinh doanh, cho thấy doanh nghiệp có thể phải bán tài sản để duy trì hoạt động. Điểm sáng là các dự án hạ tầng giao thông lớn đang triển khai, nếu hoàn thành đúng tiến độ sẽ cải thiện đáng kể tình hình tài chính.');
INSERT OR REPLACE INTO `financial_insights` (`id`, `ticker`, `year`, `report_type`, `related_party_risk`, `debt_risk`, `inventory_risk`, `governance_risk_score`, `overall_analysis`) VALUES
('VMC_2023_parent', 'VMC', 2023, 'parent', 'Giao dịch với các bên liên quan có quy mô lớn, đặc biệt với công ty mẹ và công ty con. Có các khoản cho vay không lãi suất cho công ty con, nhưng chưa thấy dấu hiệu bất thường rõ rệt.', 'Nợ vay và thuê tài chính chiếm tỷ trọng cao trong tổng tài sản. Lãi suất vay biến động từ 6.5% đến 11%/năm, áp lực chi phí lãi vay lớn. Có tài sản thế chấp là hợp đồng tiền gửi và tài sản cố định.', 'Hàng tồn kho chủ yếu là chi phí sản xuất kinh doanh dở dang và dự án xây dựng, có nguy cơ đọng vốn nếu dự án chậm tiến độ.', 4, 'Doanh nghiệp có mối quan hệ mật thiết với công ty mẹ và các công ty con, nợ vay ở mức cao, nhưng hoạt động kinh doanh có doanh thu tăng. Cần theo dõi rủi ro thanh khoản và tiến độ dự án.'),
('VMC_2022_consolidated', 'VMC', 2022, 'consolidated', 'Giao dịch với các bên liên quan, đặc biệt là Tổng Công ty Cổ phần Xuất nhập khẩu và Xây dựng Việt Nam (công ty mẹ) và các công ty cùng Tập đoàn, có quy mô lớn. Doanh thu bán hàng cho công ty mẹ chiếm tỷ trọng cao trong tổng doanh thu, điều này có thể tạo ra rủi ro về tính công bằng và độc lập trong giao dịch. Tuy nhiên, chưa phát hiện dấu hiệu bất thường rõ ràng như mua bán giá bất hợp lý hay cho vay không lãi suất.', 'Tổng nợ vay và nợ thuê tài chính ngắn hạn là 494.148 triệu VND, nợ dài hạn là 54.673 triệu VND, tổng nợ khoảng 548.821 triệu VND. Tỷ lệ nợ/Vốn chủ sở hữu khoảng 1,56 lần, cho thấy đòn bẩy tài chính tương đối cao. Áp lực trả nợ ngắn hạn lớn, với lãi suất vay ngân hàng từ 7,4% đến 9%/năm. Các khoản nợ được đảm bảo bằng tài sản như tiền gửi, máy móc, xe ô tô và cổ phần của công ty con, nhưng vẫn cần theo dõi sát khả năng thanh toán.', 'Hàng tồn kho cuối kỳ là 374.438 triệu VND, tăng mạnh so với đầu năm (186.454 triệu VND), chủ yếu là chi phí sản xuất kinh doanh dở dang và các dự án xây dựng. Các dự án như Hạ tầng Khu đô thị, Công trình San nền Cảng HKQT Long Thành có giá trị lớn, có nguy cơ đọng vốn nếu dự án chậm tiến độ hoặc khó thu hồi. Tuy nhiên, chưa có dự phòng giảm giá hàng tồn kho, cho thấy đánh giá rủi ro ở mức thấp.', 4, 'Công ty Cổ phần Vimeco có tình hình tài chính ổn định với doanh thu tăng trưởng. Tuy nhiên, đòn bẩy tài chính cao và áp lực nợ vay ngắn hạn lớn là những rủi ro cần chú ý. Hoạt động kinh doanh chủ yếu dựa vào xây lắp và sản xuất bê tông, với sự phụ thuộc lớn vào nhóm công ty liên quan. Ban lãnh đạo đã thực hiện một số thay đổi về chính sách kế toán (khấu hao) và tái cấu trúc vốn. Triển vọng trung hạn phụ thuộc vào khả năng quản lý nợ và tiến độ các dự án xây dựng.'),
('VMC_2021_parent', 'VMC', 2021, 'parent', 'Công ty có quan hệ giao dịch sâu rộng với hệ sinh thái Tổng Công ty Vinaconex (công ty mẹ) với doanh thu bán hàng 109,5 tỷ VND và phải thu ngắn hạn 156,4 tỷ VND từ Tổng Công ty mẹ cho dự án Bắc An Khánh, chiếm 30% tổng phải thu khách hàng. Các giao dịch được thực hiện theo hợp đồng, không tính lãi và không có tài sản đảm bảo, nhưng chưa trích lập dự phòng nợ phải thu khó đòi cho các khoản phải thu từ bên liên quan. Khoản phải thu khác ngắn hạn từ bên liên quan 13,6 tỷ VND (trong đó 13,4 tỷ VND là lãi chậm trả ứng vốn dự án Bắc An Khánh từ công ty mẹ) cho thấy dự án này còn tồn đọng thanh toán lớn. Tổng cộng phải thu từ bên liên quan chiếm tỷ trọng cao trong tổng tài sản ngắn hạn, tạo rủi ro tập trung tín dụng.', 'Tổng nợ vay là 252,5 tỷ VND, trong đó vay ngắn hạn 237,8 tỷ VND (tăng 12,3% so với đầu năm) và vay dài hạn 14,6 tỷ VND. Tỷ lệ nợ vay/Vốn chủ sở hữu ở mức 0,73 lần – ở ngưỡng trung bình. Chi phí lãi vay năm nay 16,5 tỷ VND, tăng 17,4% so với năm trước. Lãi suất vay ngắn hạn từ 6%-6,8%/năm và dài hạn từ 8%-10%/năm. Tài sản thế chấp chủ yếu là tiền gửi ngân hàng, máy móc thiết bị, xe trộn bê tông và trụ sở công ty. Tuy nhiên, tiền mặt cuối năm chỉ còn 16,9 tỷ VND (giảm 56,7% so với đầu năm) trong khi nợ ngắn hạn đến hạn trả lớn, đặt áp lực thanh khoản đáng kể. Lưu chuyển tiền thuần từ hoạt động kinh doanh âm 10,2 tỷ VND.', 'Hàng tồn kho tăng 23,5% lên 160 tỷ VND, chủ yếu do chi phí sản xuất kinh doanh dở dang tăng 25,6% lên 154,2 tỷ VND, phản ánh quy mô hoạt động xây lắp và sản xuất bê tông mở rộng. Giá vốn hàng bán tăng nhanh hơn doanh thu (21,5% so với 19,5%) khiến biên lợi nhuận gộp co lại từ 5,4% xuống 3,8%. Công ty không trích lập dự phòng giảm giá hàng tồn kho cuối năm (đầu năm có 328 triệu VND), cho thấy đánh giá hàng tồn kho có giá trị thuần có thể thực hiện được. Tuy nhiên, tỷ lệ hàng tồn kho dở dang chiếm 96% tổng tồn kho cho thấy vốn bị đọng trong quá trình sản xuất thi công, phụ thuộc vào tiến độ nghiệm thu và thanh toán từ chủ đầu tư.', 5, 'Công ty Cổ phần Vimeco là công ty con của Tổng Công ty Vinaconex, hoạt động chính trong lĩnh vực xây lắp và sản xuất bê tông. Năm 2021, doanh thu thuần đạt 756,6 tỷ VND (tăng 19,5%), lợi nhuận sau thuế 3,6 tỷ VND (tăng 9,7%). Tuy nhiên, biên lợi nhuận gộp co lại đáng kể (3,8% so với 5,4% năm trước) cho thấy áp lực cạnh tranh hoặc chi phí nguyên vật liệu tăng. Tiền mặt giảm mạnh 56,7%, dòng tiền hoạt động kinh doanh âm 10,2 tỷ VND trong khi nợ vay tăng, tạo áp lực thanh khoản. Kiểm toán viên Ernst & Young Việt Nam đưa ra ý kiến chấp nhận toàn phần. Hội đồng Quản trị có biến động nhân sự vào ngày 29/3/2021 (thay đổi Chủ tịch và một số thành viên). Rủi ro chính tập trung vào: (1) phụ thuộc lớn vào doanh thu và phải thu từ công ty mẹ Vinaconex, (2) áp lực thanh khoản ngắn hạn khi tiền mặt giảm mạnh, (3) biên lợi nhuận gộp mỏng trong ngành xây lắp cạnh tranh. Công ty vẫn duy trì được hoạt động kinh doanh tăng trưởng, tài sản thế chấp cho vay đa dạng, và được hưởng lợi từ hệ sinh thái Vinaconex.'),
('VMC_2021_consolidated', 'VMC', 2021, 'consolidated', 'Công ty có mối quan hệ kinh doanh mật thiết với công ty mẹ là Tổng Công ty Cổ phần Xuất nhập khẩu và Xây dựng Việt Nam (Vinaconex) và nhiều công ty con/liên kết trong cùng hệ thống. Doanh thu từ bên liên quan chiếm tỷ trọng lớn (134,3 tỷ VND, khoảng 17,5% tổng doanh thu), tăng mạnh so với năm trước (43,9 tỷ VND). Khoản phải thu ngắn hạn từ công ty mẹ lên tới 156,3 tỷ VND, là khoản mục chiếm dụng vốn lớn. Đặc biệt, có khoản phải thu lãi chậm trả ứng vốn dự án Bắc An Khánh từ công ty mẹ là 13,3 tỷ VND, cho thấy dòng tiền giữa các bên liên quan phức tạp. Các giao dịch mua bán, cho thuê với công ty trong cùng Tổng Công ty diễn ra thường xuyên với giá trị đáng kể. Tuy nhiên, chưa ghi nhận trích lập dự phòng nợ phải thu khó đòi nào cho các khoản phải thu từ bên liên quan.', 'Tổng nợ vay của Công ty là 266,3 tỷ VND (ngắn hạn 251,3 tỷ và dài hạn 15,0 tỷ). Nợ vay ngắn hạn chiếm tỷ trọng áp đảo (94,4%), tạo áp lực đáo hạn liên tục trong năm 2022. Các khoản vay cá nhân ngắn hạn với lãi suất cao 0,8%/tháng (tương đương 9,6%/năm) và chỉ có tín chấp cho thấy doanh nghiệp đang tìm kiếm nguồn vốn bổ sung với chi phí cao. Nợ ngân hàng ngắn hạn tập trung chủ yếu tại BIDV (khoảng 194,8 tỷ VND), lãi suất dao động 6-6,8%/năm. Nợ dài hạn có lãi suất cao hơn (7,2-10%/năm) với tài sản thế chấp chủ yếu là xe ô tô, máy móc trộn bê tông và trạm trộn bê tông, cùng trụ sở công ty. Chi phí lãi vay năm 2021 là 17,4 tỷ VND (tăng so với năm trước 15,3 tỷ VND). Tỷ lệ nợ/vốn chủ sở hữu ở mức 0,76 lần, ở mức trung bình nhưng cấu trúc nợ ngắn hạn quá lớn tạo rủi ro thanh khoản.', 'Hàng tồn kho tăng từ 157,2 tỷ VND lên 186,4 tỷ VND (tăng 18,6%), chủ yếu do chi phí sản xuất kinh doanh dở dang tăng từ 150,0 tỷ lên 180,2 tỷ VND. Dự phòng giảm giá hàng tồn kho không được trích lập (giá trị 0 VND tại cuối năm). Có khoản chi phí sản xuất kinh doanh dở dang dài hạn 9,0 tỷ VND liên quan đến dự án san nền lô E9 đường Phạm Hùng đã tồn tại từ trước và đang trong quá trình chờ hoàn trả từ Sở Tài chính Hà Nội và các nhà đầu tư thứ cấp. Dự án bất động sản Khu đô thị Cao Xanh – Hà Khánh D (24,5 tỷ VND) đã bị thu hồi từ năm 2012, hiện đang chờ hoàn thiện thủ tục pháp lý để nhận hoàn trả. Việc không trích lập dự phòng cho các khoản tồn kho dở dang kéo dài và đầu tư vào dự án đã bị thu hồi là điểm đáng lưu ý.', 6, 'Công ty Cổ phần Vimeco là doanh nghiệp xây lắp và sản xuất bê tông thuộc hệ sinh thái Vinaconex. Năm 2021, doanh thu đạt 765,9 tỷ VND (tăng 19,1%), lợi nhuận sau thuế đạt 3,6 tỷ VND (tăng 8,5%). Tuy nhiên, Công ty đối mặt với một số rủi ro: (1) Phụ thuộc lớn vào công ty mẹ Vinaconex về doanh thu và nguồn vốn, các khoản phải thu từ bên liên quan chiếm tỷ trọng cao; (2) Cấu trúc nợ vay ngắn hạn chiếm tỷ trọng áp đảo (94,4% tổng nợ vay) với các khoản vay cá nhân lãi suất cao tạo áp lực thanh khoản; (3) Hàng tồn kho dở dang tăng nhanh, trong đó có các khoản đầu tư vào dự án đã bị thu hồi từ nhiều năm trước chưa được xử lý dứt điểm; (4) Hội đồng Quản trị có sự thay đổi lớn trong năm 2021 với nhiều thành viên bổ nhiệm/miễn nhiệm cùng ngày 29/3/2021, cho thấy biến động quản trị. Công ty có tỷ suất lợi nhuận gộp thấp (4,8%), chủ yếu phụ thuộc vào hoàn nhập dự phòng bán hàng (-17,5 tỷ VND) để cải thiện kết quả kinh doanh. Triển vọng trung hạn ở mức trung bình, cần theo dõi tiến độ thu hồi các khoản phải thu từ bên liên quan và xử lý hàng tồn kho dở dang.'),
('VMC_2020_parent', 'VMC', 2020, 'parent', 'Công ty có giao dịch lớn với công ty mẹ (Tổng Công ty Cổ phần Xuất nhập khẩu và Xây dựng Việt Nam) và các công ty trong cùng Tổng Công ty, đặc biệt là các khoản phải thu từ công ty mẹ lên đến hơn 149 tỷ VND (dự án Bắc An Khánh) và các khoản trả trước cho công ty con. Các giao dịch này không có lãi suất và không có tài sản đảm bảo, tiềm ẩn rủi ro chiếm dụng vốn. Tuy nhiên, các giao dịch này chủ yếu thuộc hoạt động cốt lõi (xây lắp, mua bán vật liệu) nên mức độ rủi ro ở mức trung bình.', 'Áp lực nợ vay lớn với tổng nợ vay ngắn hạn hơn 211 tỷ VND và dài hạn hơn 14,5 tỷ VND. Nợ vay chủ yếu từ các ngân hàng thương mại với lãi suất dao động từ 6% đến 10%/năm, một khoản vay cá nhân tín chấp lãi suất 6,8%. Nhiều khoản vay được đảm bảo bằng tài sản cố định (máy móc, ô tô, bất động sản) và tiền gửi ngân hàng. Tỷ lệ nợ/Vốn chủ sở hữu ở mức khoảng 0.64 lần (689/353), cho thấy đòn bẩy tài chính tương đối cao. Thời gian đáo hạn nợ ngắn hạn tập trung trong năm 2021 tạo áp lực thanh toán.', 'Hàng tồn kho dở dang lớn (hơn 122 tỷ VND) bao gồm nhiều dự án xây dựng hạ tầng, khoan cọc nhồi, tường vây... Giá trị dự phòng giảm giá hàng tồn kho chỉ có 327 triệu VND, tỷ lệ trích lập rất thấp so với tổng giá trị. Một số dự án đã kéo dài nhiều năm (ví dụ: dự án Hạ tầng khu Cao Ngạn, Thái Nguyên) và có thể tiềm ẩn rủi ro đọng vốn nếu dự án bị đình trệ hoặc không thu hồi được chi phí.', 7, 'Công ty Vimeco có cấu trúc tài chính với áp lực nợ vay đáng kể, đặc biệt là nợ ngắn hạn. Hàng tồn kho dở dang lớn với tỷ lệ dự phòng thấp tạo rủi ro về thanh khoản và giá trị thực. Hoạt động kinh doanh có mối liên hệ mật thiết với công ty mẹ và các đơn vị trong cùng Tổng Công ty, tiềm ẩn rủi ro về giao dịch không minh bạch và chiếm dụng vốn. Tuy nhiên, Công ty vẫn duy trì được hoạt động kinh doanh và có lợi nhuận sau thuế. Triển vọng phụ thuộc vào khả năng thu hồi công nợ từ công ty mẹ và tiến độ các dự án xây dựng dở dang.'),
('VMC_2020_consolidated', 'VMC', 2020, 'consolidated', 'Giao dịch với công ty mẹ (Tổng Công ty Xuất nhập khẩu và Xây dựng Việt Nam) và các công ty con trong cùng Tổng Công ty có quy mô lớn, chiếm tỷ trọng đáng kể trong doanh thu và phải thu. Các khoản phải thu ngắn hạn từ công ty mẹ lên tới hơn 150 tỷ VNĐ. Mặc dù được giải thích là hoạt động kinh doanh thông thường, song rủi ro tập trung nợ và chiếm dụng vốn từ bên liên quan là đáng kể. Cần giám sát chặt chẽ thời gian thu hồi và điều kiện tín dụng.', 'Tổng nợ vay (ngắn và dài hạn) khoảng 236,4 tỷ VNĐ, tập trung vào các ngân hàng lớn với lãi suất từ 6-10%. Tài sản thế chấp chủ yếu là tiền gửi ngân hàng, máy móc, thiết bị và bất động sản (trụ sở Công ty). Áp lực trả nợ ngắn hạn cao (hơn 221,8 tỷ VNĐ nợ ngắn hạn) trong bối cảnh doanh thu và lợi nhuận giảm mạnh. Tỷ lệ nợ/Vốn chủ sở hữu ở mức an toàn (khoảng 0,66 lần) nhưng dòng tiền từ hoạt động kinh doanh âm, tạo áp lực lên khả năng thanh toán.', 'Hàng tồn kho chủ yếu là chi phí sản xuất kinh doanh dở dang (150 tỷ VNĐ), bao gồm nhiều dự án xây dựng hạ tầng, giao thông. Một số dự án có thể bị đình trệ hoặc chậm tiến độ (dự án Hạ tầng khu Cao Ngạn Thái Nguyên, Cao tốc Đà Nẵng – Quảng Ngãi). Dự phòng giảm giá chỉ trích lập 327 triệu VNĐ cho toàn bộ hàng tồn kho, mức trích lập thấp so với giá trị và rủi ro của các dự án dở dang kéo dài.', 6, 'Doanh nghiệp hoạt động trong ngành xây lắp và sản xuất công nghiệp, chịu ảnh hưởng nặng nề từ đại dịch COVID-19 với doanh thu và lợi nhuận sụt giảm mạnh. Cơ cấu tài chính còn an toàn về tỷ lệ nợ, nhưng dòng tiền kinh doanh âm cho thấy áp lực thanh khoản. Mối quan hệ mật thiết với Tổng Công ty mẹ tạo cả cơ hội lẫn rủi ro về chiếm dụng vốn. Hàng tồn kho dở dang lớn cần được theo dõi tiến độ chặt chẽ. Ý kiến kiểm toán là chấp nhận toàn phần, không có nghi ngờ lớn về khả năng hoạt động liên tục. Triển vọng ngắn hạn còn nhiều thách thức.'),
('VMC_2018_consolidated', 'VMC', 2018, 'consolidated', 'Công ty có nhiều giao dịch lớn với công ty mẹ (Tổng Công ty Cổ phần Xuất nhập khẩu và Xây dựng Việt Nam) và các công ty trong cùng Tập đoàn Vinaconex, bao gồm bán hàng, mua hàng và thanh toán cổ tức. Giá trị giao dịch bán hàng với bên liên quan chiếm khoảng 7% doanh thu thuần. Các giao dịch này thuộc hoạt động kinh doanh thông thường nhưng quy mô đáng kể, cần giám sát chặt chẽ.', 'Tỷ lệ nợ phải trả trên vốn chủ sở hữu cao (2.77 lần), áp lực trả nợ đáng kể. Tổng nợ vay ngắn hạn và dài hạn là 319.4 tỷ VND, lãi suất vay dao động từ 6% đến 11%/năm. Công ty đã thế chấp nhiều tài sản cố định (trị giá còn lại khoảng 129 tỷ VND) để đảm bảo cho các khoản vay. Áp lực chi phí lãi vay lớn (28.7 tỷ VND trong năm).', 'Hàng tồn kho giảm mạnh từ 440.6 tỷ xuống 212.6 tỷ VND, chủ yếu do giảm chi phí sản xuất kinh doanh dở dang. Tuy nhiên, vẫn còn nhiều dự án xây dựng dở dang lớn với thời gian triển khai kéo dài, đặc biệt dự án Soliel Ánh Dương Đà Nẵng (42.5 tỷ VND) và dự án HSVC 1 PP4 Cái Mép Vũng Tàu (17 tỷ VND). Công ty không trích lập dự phòng giảm giá hàng tồn kho.', 7, 'Công ty có cấu trúc tài chính đòn bẩy cao với nợ vay lớn, áp lực trả nợ và chi phí lãi vay đáng kể. Hoạt động kinh doanh đa ngành (xây lắp, sản xuất công nghiệp, bất động sản) nhưng doanh thu và lợi nhuận giảm mạnh so với năm trước. Hàng tồn kho giảm nhưng còn nhiều dự án dở dang kéo dài. Ban lãnh đạo có biến động nhân sự. Công ty có mối quan hệ phức tạp với các công ty trong Tập đoàn Vinaconex, tiềm ẩn rủi ro về giao dịch liên kết.'),
('VMC_2019_parent', 'VMC', 2019, 'parent', 'Rủi ro cao với giao dịch bên liên quan phức tạp trong tập đoàn Vinaconex. Công ty có khoản phải thu lớn với Ban Điều hành thi công giai đoạn 1 Dự án Bắc An Khánh (109.8 tỷ VND) và Tổng Công ty mẹ (70 tỷ VND). Công ty con Vimeco Cơ khí và Thương mại hoạt động kinh doanh liên tục lỗ trong 2 năm nhưng vẫn duy trì đầu tư và phát sinh giao dịch mua bán lớn (mua hàng 33.2 tỷ, bán hàng 6.5 tỷ). Người mua trả tiền trước cho Tổng Công ty mẹ lên tới 88.1 tỷ VND, cho thấy sự phụ thuộc và chiếm dụng vốn lớn.', 'Nợ vay ngân hàng tập trung tại 4 ngân hàng lớn (BIDV, MB, VietinBank) với tổng nợ ngắn hạn 242.2 tỷ VND và dài hạn 26.7 tỷ VND. Chi phí lãi vay năm nay là 22.5 tỷ VND, chiếm tỷ trọng đáng kể trong cơ cấu chi phí. Tỷ lệ nợ phải trả/Vốn chủ sở hữu ở mức 2.47 lần (909 tỷ/368 tỷ), mức cao. Tài sản thế chấp bao gồm tiền gửi có kỳ hạn 48 tỷ VND và phương tiện vận tải, máy móc thiết bị thi công với giá trị còn lại 40.6 tỷ VND. Áp lực trả nợ ngắn hạn lớn với 19.7 tỷ VND nợ dài hạn đến hạn trong 12 tháng tới.', 'Hàng tồn kho chủ yếu là chi phí sản xuất kinh doanh dở dang (119.3 tỷ VND/123.9 tỷ VND) với nhiều dự án xây dựng dở dang lớn. Dự án Cảng Cái Mép Vũng Tàu chiếm 57.3 tỷ VND, tăng mạnh so với năm trước (18 tỷ). Dự án Cao Xanh - Hà Khánh D trị giá 24.5 tỷ đã bị thu hồi đất từ năm 2012, đang chờ hoàn trả. Công ty không trích lập dự phòng giảm giá hàng tồn kho nào. Rủi ro đọng vốn tại các dự án xây dựng dở dang kéo dài, đặc biệt dự án bị thu hồi đất.', 7, 'Năm 2019, doanh thu sụt giảm 24.6% từ 1,521.7 tỷ xuống 1,146.3 tỷ VND. Biên lợi nhuận gộp giảm mạnh từ 9.4% xuống 3.97%. Công ty lỗ ròng từ hoạt động kinh doanh (-5.65 tỷ) nhưng có lợi nhuận trước thuế 13.5 tỷ VND nhờ thu nhập từ thanh lý TSCĐ (19.7 tỷ). Lợi nhuận sau thuế giảm 89.7% từ 93.3 tỷ xuống 9.6 tỷ VND. Cơ cấu tài chính có đòn bẩy cao (nợ/VCSH = 2.47 lần). Giao dịch với bên liên quan phức tạp, công ty con hoạt động lỗ. Ban lãnh đạo có nhiều thay đổi lớn trong năm (thay đổi Chủ tịch HĐQT, Tổng Giám đốc). Công ty đã thanh toán cổ tức 60 tỷ VND trong năm. Điểm rủi ro quản trị ở mức 7/10 do giao dịch bên liên quan phức tạp, nợ vay lớn, và nhiều thay đổi nhân sự cấp cao.'),
('VMC_2018_parent', 'VMC', 2018, 'parent', 'Công ty có mối quan hệ phức tạp với nhiều công ty trong Tập đoàn Vinaconex và công ty mẹ. Giao dịch mua bán với các bên liên quan có giá trị lớn (bán hàng 99 tỷ, mua hàng 27 tỷ). Các khoản phải thu từ Ban Điều hành Dự án Bắc An Khánh (109 tỷ) và Tổng Công ty mẹ (53 tỷ) chiếm tỷ trọng lớn, tiềm ẩn rủi ro chiếm dụng vốn. Các khoản trả trước cho công ty con Vimeco Cơ khí cũng ở mức cao (13.6 tỷ).', 'Tỷ lệ nợ phải trả trên vốn chủ sở hữu cao (1.138/419 = ~2.7 lần). Nợ vay và nợ thuê tài chính ngắn hạn là 255 tỷ, nợ dài hạn là 44.8 tỷ (phần phải trả sau 12 tháng). Tổng nghĩa vụ nợ vay là ~300 tỷ. Công ty chủ yếu vay tại các ngân hàng lớn (VietinBank, BIDV, MB) với lãi suất ngắn hạn 6-7%/năm và dài hạn 8.5-11%/năm. Áp lực trả nợ cả gốc và lãi là đáng kể, đặc biệt khi dòng tiền từ hoạt động kinh doanh âm 83.7 tỷ trong năm.', 'Hàng tồn kho giảm mạnh từ 407 tỷ xuống 180 tỷ, chủ yếu do giảm chi phí sản xuất kinh doanh dở dang (từ 400 tỷ xuống 168 tỷ). Tuy nhiên, giá trị tồn kho dở dang vẫn lớn, tập trung vào nhiều dự án xây dựng bất động sản và hạ tầng (Dự án Soliel Ánh Dương 42.5 tỷ, Công trình khác 96 tỷ). Nhiều dự án đã kéo dài qua nhiều năm (ví dụ dự án Cao Xanh - Hà Khánh D từ 2012). Không trích lập dự phòng giảm giá hàng tồn kho.', 7, 'Doanh nghiệp có quy mô tài sản lớn nhưng hoạt động kinh doanh chính (xây lắp, bất động sản) suy giảm mạnh so với năm trước. Tình hình tài chính có nhiều điểm rủi ro: tỷ lệ đòn bẩy nợ cao, dòng tiền kinh doanh âm, nhiều khoản phải thu lớn với các bên liên quan trong tập đoàn có nguy cơ chiếm dụng vốn, hàng tồn kho dở dang nhiều dự án cũ tiềm ẩn rủi ro. Ban lãnh đạo có nhiều biến động trong năm. Ý kiến kiểm toán chấp nhận toàn phần nhưng nhấn mạnh một số vấn đề về khả năng thu hồi đầu tư và dự án.'),
('VMC_2017_consolidated', 'VMC', 2017, 'consolidated', 'Giao dịch với công ty mẹ (Tổng Công ty Vinaconex) và các công ty liên quan có quy mô lớn, chủ yếu là bán hàng hóa/dịch vụ xây lắp, bất động sản và mua nguyên vật liệu. Các khoản phải thu từ bên liên quan không có đảm bảo, không tính lãi, theo hợp đồng. Rủi ro ở mức trung bình do đây là hoạt động kinh doanh chính trong tập đoàn.', 'Nợ vay tập trung vào các ngân hàng thương mại lớn (Vietcombank, BIDV, VietinBank, MB). Lãi suất vay ngắn hạn dao động 6%-9.25%/năm, dài hạn 7.9%-12%/năm. Tổng nợ vay (ngắn+dài hạn) ~398.4 tỷ VNĐ, tài sản thế chấp chính là bất động sản (giá trị còn lại ~136.5 tỷ VNĐ) và tiền gửi có kỳ hạn (48 tỷ VNĐ). Tỷ lệ nợ/vốn chủ sở hữu là 3.4 lần, áp lực trả nợ ngắn hạn tương đối lớn.', 'Hàng tồn kho chủ yếu là chi phí sản xuất kinh doanh dở dang (456.6 tỷ VNĐ), bao gồm nhiều dự án bất động sản lớn. Dự án Cao Xanh - Hà Khánh D đã bị thu hồi đất nhưng công ty tin tưởng thu hồi được 24.5 tỷ VNĐ. Dự án CT4 có giá trị lớn (243.8 tỷ VNĐ). Không có trích lập dự phòng giảm giá hàng tồn kho. Rủi ro đọng vốn vào dự án dở dang là đáng kể.', 4, 'Doanh nghiệp có kết quả kinh doanh đột biến năm 2017 (lợi nhuận sau thuế tăng 8 lần) nhờ doanh thu bất động sản lớn. Tuy nhiên, đòn bẫy tài chính cao, hàng tồn kho dở dang lớn và phụ thuộc vào các dự án bất động sản, xây lắp. Cơ cấu tài chính tiềm ẩn rủi ro thanh khoản ngắn hạn. Ban lãnh đạo có sự thay đổi trong năm. Ý kiến kiểm toán chấp nhận toàn phần.');
INSERT OR REPLACE INTO `financial_insights` (`id`, `ticker`, `year`, `report_type`, `related_party_risk`, `debt_risk`, `inventory_risk`, `governance_risk_score`, `overall_analysis`) VALUES
('VMC_2019_consolidated', 'VMC', 2019, 'consolidated', 'Giao dịch với các bên liên quan chủ yếu là bán hàng và mua hàng với công ty mẹ và các công ty trong cùng tập đoàn. Giá trị giao dịch lớn nhưng thuộc hoạt động kinh doanh thông thường. Chưa có dấu hiệu bất thường hay chuyển giá, tuy nhiên cần theo dõi quy mô giao dịch so với doanh thu.', 'Nợ vay ngắn hạn và dài hạn chủ yếu từ các ngân hàng lớn như BIDV, VietinBank, MB Bank. Tổng nợ phải trả chiếm tỷ trọng cao trên tổng tài sản. Công ty đã thế chấp tiền gửi có kỳ hạn và tài sản cố định để đảm bảo khoản vay. Lãi suất vay không được tiết lộ cụ thể, áp lực trả nợ ngắn hạn ở mức trung bình.', 'Hàng tồn kho bao gồm nguyên vật liệu và chi phí sản xuất kinh doanh dở dang. Nhiều dự án xây dựng dở dang có giá trị lớn, tuy nhiên không có thông tin về trích lập dự phòng giảm giá. Rủi ro đọng vốn vào các dự án chậm tiến độ cần được đánh giá thêm.', 4, 'Công ty có cơ cấu tài chính với nợ vay chiếm tỷ trọng đáng kể, hoạt động kinh doanh có lợi nhuận gộp thấp. Ý kiến kiểm toán là chấp nhận toàn phần, không có nghi ngờ về khả năng hoạt động liên tục. Tuy nhiên, các giao dịch với bên liên quan và số lượng lớn dự án dở dang đòi hỏi sự giám sát chặt chẽ. Triển vọng trung hạn phụ thuộc vào khả năng thu hồi công nợ và hoàn thành các dự án.'),
('VMC_2016_consolidated', 'VMC', 2016, 'consolidated', 'Công ty có mạng lưới giao dịch bên liên quan phức tạp với công ty mẹ (Tổng Công ty CP Xuất nhập khẩu và Xây dựng Việt Nam) và nhiều công ty liên quan trong hệ sinh thái Vinaconex. Doanh thu bán hàng cho công ty mẹ chiếm tỷ trọng lớn (28,8% tổng doanh thu). Các khoản phải thu từ bên liên quan lớn, không tính lãi và không có đảm bảo. Tuy nhiên, các giao dịch chủ yếu phục vụ hoạt động xây lắp và sản xuất công nghiệp cốt lõi, chưa thấy dấu hiệu chuyển giá bất thường rõ ràng.', 'Nợ vay ngắn hạn và dài hạn tổng cộng đạt 445.447.123.122 VND, chiếm tỷ trọng cao trên tổng tài sản (gần 20%). Tỷ lệ nợ/Vốn chủ sở hữu là 1,83 lần (2.007.645.299.122 / 243.127.790.146), áp lực trả nợ ở mức cao. Các khoản vay chủ yếu từ ngân hàng lớn (VietinBank, BIDV, MB) với lãi suất biến động 5,5%-12%/năm. Tài sản thế chấp chủ yếu là tài sản cố định hữu hình (nguyên giá 526 tỷ, giá trị còn lại 138,8 tỷ) và tiền gửi có kỳ hạn. Áp lực chi phí lãi vay năm 2016 là 24,46 tỷ, tăng so với năm trước.', 'Hàng tồn kho dở dang chiếm tỷ trọng tuyệt đối (779/786 tỷ VND), tăng mạnh 66% so với đầu năm. Bao gồm nhiều dự án xây dựng quy mô lớn (Dự án CT4 trị giá 546,7 tỷ). Dự án Khu đô thị Cao Xanh - Hà Khánh D (24,5 tỷ) bị thu hồi đất từ 2012 nhưng chưa được hoàn trả, tiềm ẩn rủi ro đọng vốn. Không có trích lập dự phòng giảm giá hàng tồn kho. Việc tăng mạnh hàng tồn kho dở dang đòi hỏi nguồn vốn lưu động lớn.', 7, 'Công ty có quy mô tài sản lớn (2.250 tỷ) tăng trưởng mạnh (75%) trong năm, chủ yếu do tăng hàng tồn kho dở dang và khoản phải thu. Năng lực tài chính bị suy giảm với lợi nhuận sau thuế giảm 7,7% trong khi nợ vay tăng gần gấp đôi. Tỷ lệ đòn bẩy tài chính cao, áp lực trả nợ lớn. Hoạt động kinh doanh phụ thuộc lớn vào hệ sinh thái Vinaconex. Kiểm toán đưa ra ý kiến chấp nhận toàn phần nhưng nhấn mạnh các rủi ro về nợ vay, hàng tồn kho dở dang và giao dịch bên liên quan.'),
('VMC_2017_parent', 'VMC', 2017, 'parent', 'Giao dịch với công ty mẹ và các công ty liên quan có giá trị lớn, chủ yếu là mua bán hàng hóa/dịch vụ thông thường thuộc hoạt động kinh doanh cốt lõi. Các khoản phải thu từ công ty mẹ không tính lãi, không đảm bảo, có thể ảnh hưởng đến dòng tiền. Tuy nhiên, chưa thấy dấu hiệu chuyển giá hay rút ruột rõ ràng.', 'Tổng nợ phải trả chiếm tỷ lệ cao (tỷ lệ nợ/vốn chủ sở hữu ~3.4 lần), áp lực trả nợ ngắn hạn lớn. Các khoản vay chủ yếu từ ngân hàng thương mại với lãi suất 6%-12%/năm, được đảm bảo bằng tài sản cố định và đầu tư đáo hạn. Cơ cấu nợ ngắn hạn chiếm tỷ trọng lớn, rủi ro tái tài trợ cao.', 'Hàng tồn kho giảm mạnh chủ yếu do chi phí sản xuất kinh doanh dở dang giảm, tuy nhiên vẫn còn nhiều dự án xây dựng dở dang có giá trị lớn, trong đó dự án Cao Xanh – Hà Khánh D đã bị thu hồi đất, tiềm ẩn rủi ro không thu hồi được vốn. Không trích lập dự phòng giảm giá hàng tồn kho, có thể gây đọng vốn nếu dự án chậm tiến độ hoặc khó bán.', 6, 'Doanh nghiệp có doanh thu và lợi nhuận tăng trưởng mạnh trong năm 2017, chủ yếu từ hoạt động bất động sản. Tuy nhiên, cơ cấu tài chính có đòn bẩy nợ cao, hàng tồn kho dở dang lớn với một dự án gặp rủi ro pháp lý. Giao dịch với bên liên quan phức tạp nhưng chưa phát hiện bất thường nghiêm trọng. Ban lãnh đạo có sự thay đổi trong năm. Điểm rủi ro quản trị ở mức cao do áp lực nợ và rủi ro từ dự án bất động sản.'),
('VMC_2015_consolidated', 'VMC', 2015, 'consolidated', 'Giao dịch với công ty mẹ và các bên liên quan có quy mô lớn, chiếm tỷ trọng đáng kể trong doanh thu và phải thu. Các khoản phải thu từ bên liên quan không có đảm bảo, không chịu lãi, tiềm ẩn rủi ro chiếm dụng vốn. Phát hành cổ phiếu cho công ty mẹ cũng có thể ảnh hưởng đến cơ cấu sở hữu.', 'Nợ vay ngắn hạn và dài hạn từ nhiều ngân hàng thương mại với lãi suất biến động, tổng nợ phải trả chiếm tỷ lệ cao trên tổng tài sản (khoảng 80%). Áp lực trả nợ lớn, đặc biệt nợ ngắn hạn đáo hạn trong 12 tháng. Tài sản thế chấp chủ yếu là tài sản cố định hữu hình, giảm tính thanh khoản.', 'Hàng tồn kho chủ yếu là chi phí sản xuất kinh doanh dở dang, tập trung vào các dự án bất động sản và xây dựng. Dự án Cao Xanh – Hà Khánh D đã bị thu hồi đất nhưng chưa trích lập dự phòng, tiềm ẩn nguy cơ mất vốn. Các dự án khác có tiến độ xây dựng kéo dài, có thể tích tụ chi phí mà không tạo doanh thu kịp thời.', 7, 'Doanh nghiệp có doanh thu tăng trưởng nhưng biên lợi nhuận gộp thấp (khoảng 6.7%), chịu áp lực chi phí lãi vay lớn. Cấu trúc tài chính rủi ro cao với nợ vay chiếm tỷ trọng lớn, trong khi hàng tồn kho dở dang nhiều và có dự án không khả thi. Kiểm toán có ý kiến nhấn mạnh về điều chỉnh số liệu từ Kiểm toán Nhà nước, cho thấy vấn đề quản trị tài chính. Triển vọng đầu tư cần thận trọng.'),
('VMA_2024_consolidated', 'VMA', 2024, 'consolidated', 'Giao dịch với Tập đoàn Công nghiệp Than - Khoáng sản Việt Nam và các đơn vị thành viên chiếm tỷ trọng lớn trong cả doanh thu (226,5 tỷ) và mua hàng (13,1 tỷ). Đây là hoạt động kinh doanh cốt lõi thuộc chuỗi giá trị nội bộ Tập đoàn, tuy nhiên cần theo dõi khả năng thanh toán và điều khoản tín dụng giữa các bên để tránh rủi ro chiếm dụng vốn kéo dài.', 'Nợ vay tập trung chủ yếu vào một ngân hàng (Vietcombank Chi nhánh Cẩm Phả) với tổng dư nợ 12,856 tỷ VND, trong đó nợ ngắn hạn chiếm tỷ trọng cao (11,427 tỷ). Lãi suất biến động theo thông báo của Ngân hàng. Tỷ lệ nợ/VCSH là 2.36 lần, áp lực trả nợ ngắn hạn ở mức trung bình. Tài sản đảm bảo chủ yếu là tín chấp và tài sản hình thành từ vốn vay.', 'Hàng tồn kho tăng gần gấp đôi từ 17,061 tỷ lên 33,653 tỷ, chủ yếu do chi phí sản xuất kinh doanh dở dang tăng mạnh (từ 10,400 tỷ lên 16,741 tỷ). Điều này cho thấy có thể có dự án sản xuất kéo dài hoặc tích tụ chi phí, cần đánh giá tiến độ và khả năng chuyển hóa thành doanh thu. Không có trích lập dự phòng giảm giá hàng tồn kho.', 4, 'Doanh nghiệp có ý kiến kiểm toán chấp nhận toàn phần, cấu trúc cổ đông rõ ràng với sự chi phối của Tập đoàn TKV. Hoạt động kinh doanh phụ thuộc lớn vào nội bộ Tập đoàn. Tình hình tài chính có một số điểm cần lưu ý: nợ vay ngắn hạn tăng mạnh, hàng tồn kho dở dang tích tụ tăng nhanh, dòng tiền từ hoạt động kinh doanh âm (-1.9 tỷ). Tuy nhiên, lợi nhuận vẫn dương và doanh nghiệp duy trì được hoạt động sản xuất kinh doanh. Triển vọng phụ thuộc vào tiến độ giải quyết tồn kho và thanh toán công nợ trong Tập đoàn.'),
('VMA_2025_consolidated', 'VMA', 2025, 'consolidated', 'Các giao dịch với bên liên quan chủ yếu là mua bán dịch vụ, vật tư trong nội bộ Tập đoàn Công nghiệp Than - Khoáng sản Việt Nam, quy mô lớn nhưng phục vụ sản xuất kinh doanh chính. Chưa thấy dấu hiệu chuyển giá hoặc giao dịch bất thường, tuy nhiên sự phụ thuộc vào công ty mẹ và các đơn vị thành viên có thể tạo rủi ro về tính độc lập trong kinh doanh.', 'Nợ vay ngắn hạn và dài hạn chủ yếu từ các ngân hàng thương mại lớn với lãi suất thị trường. Tổng nợ vay khoảng 43,7 tỷ VNĐ, chiếm tỷ trọng đáng kể trên tổng tài sản 181,6 tỷ VNĐ. Tuy nhiên, nợ vay có tài sản đảm bảo và mục đích rõ ràng cho đầu tư tài sản cố định, rủi ro thanh toán ở mức trung bình do dòng tiền hoạt động kinh doanh dương.', 'Hàng tồn kho giá trị khoảng 39 tỷ VNĐ, không trích lập dự phòng giảm giá, bao gồm nguyên liệu, công cụ và chi phí sản xuất dở dang. Tồn kho dở dang lớn phản ánh hoạt động sửa chữa ô tô và thiết bị, tính thanh khoản cao do tiêu thụ nhanh trong chu kỳ kinh doanh 12 tháng. Dự án xây dựng cơ bản dở dang nhỏ, rủi ro đọng vốn thấp.', 4, 'Công ty có cấu trúc tài chính ổn định với tăng trưởng doanh thu và lợi nhuận tích cực. Hoạt động kinh doanh chính tập trung vào sửa chữa ô tô và thiết bị, có mối quan hệ mật thiết với Tập đoàn mẹ. Tuy nhiên, nợ vay tăng nhanh để tài trợ đầu tư tài sản cố định cần được giám sát. Ban lãnh đạo nhất quán, kiểm toán không có ngoại trừ, quản trị rủi ro ở mức chấp nhận được. Triển vọng trung hạn khả quan nhờ nhu cầu dịch vụ sửa chữa từ ngành than và khoáng sản.'),
('VMA_2023_consolidated', 'VMA', 2023, 'consolidated', 'Giao dịch với bên liên quan (chủ yếu là các đơn vị thành viên Tập đoàn Than - Khoáng sản Việt Nam) chiếm tỷ trọng lớn trong doanh thu và công nợ phải thu. Tuy nhiên, giao dịch thuộc hoạt động sản xuất kinh doanh cốt lõi (sửa chữa, chế tạo xe) và là khách hàng truyền thống. Các khoản phải thu lớn nhưng được theo dõi chi tiết. Rủi ro ở mức trung bình do phụ thuộc vào nhóm khách hàng liên quan.', 'Nợ vay chủ yếu từ một ngân hàng thương mại lớn (VietinBank) với quy mô tương đối nhỏ so với tổng tài sản và vốn chủ sở hữu (tỷ lệ nợ/VCSH ~0.12). Áp lực lãi vay thấp (tổng chi phí lãi vay năm 2023 chỉ 800 triệu VND). Tuy nhiên, nợ ngắn hạn (lưu động) chiếm tỷ trọng lớn trong cơ cấu nợ, đòi hỏi khả năng quay vòng vốn nhanh.', 'Hàng tồn kho giảm mạnh so với đầu năm, chủ yếu do giảm nguyên vật liệu và sản phẩm dở dang. Tuy nhiên, cơ cấu hàng tồn kho vẫn còn một tỷ lệ đáng kể là sản phẩm dở dang (trên 60% giá trị), cho thấy thời gian chu kỳ sản xuất có thể dài. Dự phòng giảm giá hàng tồn kho là 0, không có thông tin cụ thể về thời gian lưu kho.', 5, 'Doanh nghiệp hoạt động trong ngành sửa chữa, chế tạo xe ô tô, phụ thuộc lớn vào Tập đoàn mẹ và các công ty thành viên. Tình hình tài cơ bản lành mạnh, tỷ lệ đòn bẩy thấp. Dòng tiền từ hoạt động kinh doanh năm 2023 âm do tăng mạnh công nợ phải thu, cho thấy áp lực về vốn lưu động. Lợi nhuận duy trì ổn định. Rủi ro tập trung vào tính thanh khoản của khoản phải thu lớn và sự phụ thuộc vào nhóm khách hàng liên quan.'),
('VMA_2021_consolidated', 'VMA', 2021, 'consolidated', 'Doanh thu từ các bên liên quan (các công ty cùng Tập đoàn Công nghiệp Than - Khoáng sản Việt Nam) chiếm tỷ trọng lớn trong tổng doanh thu, tập trung vào bán hàng cho các công ty than. Phải thu từ các công ty cùng Tập đoàn còn cao, đặc biệt Công ty CP Than Hà Lầm (10.7 tỷ), Công ty CP Than Cọc Sáu (8.9 tỷ). Các giao dịch này là hoạt động kinh doanh thông thường trong tập đoàn, nhưng cần theo dõi khả năng thu hồi và rủi ro chiếm dụng vốn.', 'Công ty không có nợ vay ngân hàng hay trái phiếu. Nợ phải trả chủ yếu là phải trả người bán ngắn hạn (75.4 tỷ) và dự phòng bảo hành sản phẩm (13.9 tỷ). Tỷ lệ nợ/VCSH cao (2.07 lần) do nợ ngắn hạn lớn, tạo áp lực thanh toán ngắn hạn. Tuy nhiên, công ty có tài sản ngắn hạn (112.3 tỷ) lớn hơn nợ ngắn hạn (104.9 tỷ), đảm bảo khả năng thanh toán.', 'Hàng tồn kho tăng nhẹ so với đầu năm, chủ yếu là chi phí sản xuất kinh doanh dở dang (9.36 tỷ). Dự phòng giảm giá hàng tồn kho là 0, cho thấy công ty đánh giá hàng tồn kho không có nguy cơ giảm giá. Sản phẩm dở dang chiếm tỷ trọng lớn, cần theo dõi tiến độ sản xuất để tránh đọng vốn.', 4, 'Công ty có hoạt động kinh doanh ổn định với doanh thu 349 tỷ và lợi nhuận sau thuế 4.7 tỷ. Cơ cấu tài chính lành mạnh, không có nợ vay dài hạn, nợ ngắn hạn được kiểm soát bằng tài sản ngắn hạn. Tuy nhiên, công ty phụ thuộc lớn vào doanh thu từ các công ty cùng Tập đoàn TKV và có phải thu từ các bên liên quan lớn. Ban lãnh đạo nhất quán, công ty tuân thủ tốt các chuẩn mực kế toán. Triển vọng trung hạn ổn định nhưng cần cải thiện khả năng thu hồi công nợ.'),
('VMA_2020_consolidated', 'VMA', 2020, 'consolidated', 'Công ty có nhiều giao dịch mua bán với các bên liên quan trong cùng Tập đoàn Công nghiệp Than - Khoáng sản Việt Nam, với tổng giá trị lớn. Các giao dịch chủ yếu phục vụ hoạt động sản xuất kinh doanh cốt lõi, chưa thấy dấu hiệu chuyển giá bất thường hay rút vốn ra ngoài. Tuy nhiên, sự tập trung vào nhóm liên quan có thể tạo rủi ro nếu có thay đổi trong mối quan hệ kinh doanh.', 'Công ty không có nợ vay ngân hàng hay trái phiếu tại thời điểm kết thúc năm tài chính, nên áp lực trả nợ là không đáng kể. Các khoản phải trả người bán chiếm tỷ trọng lớn, nhưng đây là nợ thương mại thông thường và được quản lý chặt chẽ. Rủi ro thanh khoản thấp do công ty duy trì tiền mặt và tương đương tiền ở mức an toàn.', 'Hàng tồn kho chủ yếu là nguyên liệu và chi phí sản xuất dở dang, với dự phòng giảm giá chỉ áp dụng cho nguyên liệu vật liệu (243 triệu VND). Tỷ lệ trích lập dự phòng thấp cho thấy hàng tồn kho được đánh giá cao, không có dấu hiệu ứ đọng nghiêm trọng. Tuy nhiên, công ty cần theo dõi tiến độ sử dụng nguyên liệu và sản xuất dở dang để tránh tích tụ chi phí.', 3, 'Công ty Cổ phần Công nghiệp Ô tô - Vinacomin có tình hình tài chính ổn định với lợi nhuận tăng nhẹ, không có nợ vay và hoạt động kinh doanh cốt lõi vững chắc. Giao dịch với bên liên quan quy mô lớn nhưng trong khuôn khổ Tập đoàn, ý kiến kiểm toán chấp nhận toàn phần cho thấy quản trị minh bạch. Rủi ro thấp, triển vọng đầu tư an toàn trong trung hạn.'),
('VMA_2019_consolidated', 'VMA', 2019, 'consolidated', 'Giao dịch với các bên liên quan chủ yếu là trong cùng Tập đoàn Công nghiệp Than - Khoáng sản Việt Nam, bao gồm bán hàng và mua hàng, phục vụ hoạt động sản xuất kinh doanh cốt lõi. Các giao dịch có giá trị lớn nhưng nằm trong chuỗi cung ứng thông thường, chưa thấy dấu hiệu rút ruột hay chuyển giá bất thường.', 'Công ty không có nợ vay ngân hàng tại thời điểm cuối năm, nhưng nợ phải trả người bán rất lớn (97.6 tỷ VNĐ) và nợ ngắn hạn vượt tài sản ngắn hạn. Áp lực thanh toán ngắn hạn cao, phụ thuộc vào việc quản lý dòng tiền từ hoạt động kinh doanh và thu hồi nợ phải thu.', 'Hàng tồn kho chủ yếu là nguyên vật liệu và chi phí sản xuất dở dang, không có dự phòng giảm giá. Tuy nhiên, chi phí sản xuất dở dang chiếm tỷ trọng cao (61.6% tổng tồn kho), có thể tích tụ nếu chu kỳ sản xuất kéo dài hoặc đơn hàng chậm, gây rủi ro đọng vốn.', 5, 'Doanh nghiệp có doanh thu tăng trưởng 16.1% so với năm trước, biên lợi nhuận gộp ổn định ở mức 8.7%. Cơ cấu tài chính có rủi ro thanh khoản do nợ ngắn hạn cao, không có nợ vay ngân hàng nhưng áp lực từ các khoản phải trả lớn. Hoạt động kinh doanh phụ thuộc nhiều vào Tập đoàn mẹ và các công ty con trong hệ thống. Ban lãnh đạo cam kết hoạt động liên tục, nhưng cần cải thiện quản lý vốn lưu động để giảm thiểu rủi ro. Triển vọng trung hạn phụ thuộc vào khả năng thu hồi nợ và kiểm soát hàng tồn kho.');
INSERT OR REPLACE INTO `financial_insights` (`id`, `ticker`, `year`, `report_type`, `related_party_risk`, `debt_risk`, `inventory_risk`, `governance_risk_score`, `overall_analysis`) VALUES
('VMA_2018_consolidated', 'VMA', 2018, 'consolidated', 'Công ty có mối quan hệ thương mại mật thiết với Tập đoàn Công nghiệp Than - Khoáng sản Việt Nam (TKV) - cổ đông lớn nhất nắm 36% vốn. Các giao dịch với các công ty con/liên kết trong Tập đoàn TKV chiếm tỷ trọng rất lớn trong doanh thu (hơn 90%) và phải thu khách hàng. Các khoản phải thu lớn từ Công ty CP than Cọc Sáu (19.744 tỷ VND), Công ty CP than Hà Tu (9.693 tỷ VND), Công ty CP than Hà Lầm (7.291 tỷ VND), Công ty CP Cơ khí Mạo Khê (14.391 tỷ VND) phản ánh đặc thù kinh doanh trong hệ sinh thái Tập đoàn. Rủi ro tín dụng tập trung đáng kể vào nhóm khách hàng liên quan đến hoạt động khai thác than, tuy nhiên các giao dịch có tính thương mại rõ ràng, phục vụ hoạt động sản xuất kinh doanh cốt lõi. Không phát hiện dấu hiệu bất thường về chuyển giá hay rút vốn.', 'Tại ngày 31/12/2018, Công ty không còn nợ vay ngân hàng (cả ngắn hạn và dài hạn đều = 0 VND) do đã trả hết nợ trong năm. Trong năm 2018, Công ty đã phát sinh và trả nợ gốc vay tổng cộng 105.968.112.170 VND từ Vietcombank (80.236 tỷ) và BIDV (23.252 tỷ), cho thấy khả năng xoay vòng vốn tốt. Chi phí lãi vay trong năm chỉ 410.049.832 VND, giảm mạnh so với năm 2017 (655.265.182 VND). Khoản nợ dài hạn còn lại chủ yếu là Quỹ phát triển khoa học công nghệ (2.010 tỷ VND) và Dự phòng bảo hành sản phẩm (7.026 tỷ VND). Tỷ lệ Nợ phải trả/Vốn chủ sở hữu là 2.87 lần, trong đó phần lớn là phải trả người bán ngắn hạn (80.382 tỷ VND) - mang tính chất nợ thương mại. Áp lực trả nợ ngân hàng thấp.', 'Hàng tồn kho giảm từ 15.561 tỷ VND (đầu năm) xuống 11.917 tỷ VND (cuối năm) nhờ cải thiện quản lý. Thành phần chính là Chi phí sản xuất kinh doanh dở dang (6.298 tỷ VND) chiếm 52,8% và Thành phẩm (2.718 tỷ VND) chiếm 22,8%. Dự phòng giảm giá hàng tồn kho cuối năm = 0 (đã hoàn nhập 255.146.007 VND trích năm trước). Công ty có Chi phí XDCB dở dang 76.801.800 VND cho dự án xây dựng sân cầu lông, quy mô nhỏ và không đáng lo ngại. Hàng tồn kho chủ yếu là sản phẩm sửa chữa, chế tạo ô tô và thiết bị ngành than, có tính thanh khoản tương đối do phục vụ nhu cầu sản xuất kinh doanh trong Tập đoàn. Rủi ro đọng vốn ở mức trung bình thấp.', 4, 'Công ty Cổ phần Công nghiệp Ô tô - Vinacomin là doanh nghiệp hoạt động trong lĩnh vực sản xuất, lắp ráp, sửa chữa ô tô và thiết bị ngành than, trực thuộc hệ sinh thái Tập đoàn Công nghiệp Than - Khoáng sản Việt Nam (TKV). Cổ đông lớn bao gồm TKV (36%) và Công ty CP kín ''Công ty Ngoại thương Kamaz'' (38%). Năm 2018, doanh thu thuần đạt 348.257 tỷ VND (tăng 15% so với năm trước), lợi nhuận sau thuế 4.265 tỷ VND (tăng 5,7%). Biên lợi nhuận gộp 8,53% - ở mức trung bình trong ngành sản xuất cơ khí. Công ty có cấu trúc tài chính tương đối lành mạnh: không nợ vay ngân hàng cuối kỳ, tỷ lệ nợ/VCSH chủ yếu do nợ thương mại. Tuy nhiên, doanh thu phụ thuộc lớn vào Tập đoàn TKV (>90%) tạo rủi ro tập trung tín dụng. Lợi nhuận trên mỗi cổ phiếu (EPS) đạt 1.580 VND/cp, tăng từ 1.495 VND năm 2017. Công ty trả cổ tức 800 VND/cp (tỷ suất ~8% mệnh giá) cho năm 2017. Triển vọng trung hạn phụ thuộc vào tình hình hoạt động của ngành than và nhu cầu sửa chữa, chế tạo thiết bị của Tập đoàn TKV.'),
('VMA_2017_consolidated', 'VMA', 2017, 'consolidated', 'Công ty có nhiều giao dịch mua bán với các công ty trong cùng Tập đoàn Than - Khoáng sản Việt Nam, giá trị lớn, tập trung vào mua nguyên vật liệu (than) và bán sản phẩm sửa chữa, chế tạo. Các khoản phải thu với bên liên quan chiếm tỷ trọng cao (hơn 88 tỷ VND trên tổng phải thu hơn 101 tỷ VND) nhưng là hoạt động kinh doanh thông thường trong chuỗi giá trị của tập đoàn. Chưa thấy dấu hiệu bất thường như cho vay không lãi suất hay chuyển giá.', 'Nợ phải trả chủ yếu là phải trả người bán ngắn hạn (hơn 78 tỷ VND) phát sinh từ hoạt động mua hàng thông thường. Không có thông tin chi tiết về nợ vay ngân hàng hay trái phiếu. Tổng nợ phải trả trên vốn chủ sở hữu cao (khoảng 2.94 lần) do nợ thương mại lớn, nhưng công ty có tài sản ngắn hạn (hơn 119 tỷ VND) cao hơn nợ ngắn hạn (hơn 103 tỷ VND), đảm bảo khả năng thanh toán. Nợ dài hạn rất nhỏ (Quỹ phát triển khoa học công nghệ hơn 1.4 tỷ VND).', 'Hàng tồn kho tăng từ 13.3 tỷ VND lên 15.3 tỷ VND, chủ yếu do chi phí sản xuất kinh doanh dở dang tăng. Có hàng tồn kho ứ động kém phẩm chất 302 triệu VND. Dự phòng giảm giá hàng tồn kho giảm nhẹ. Hàng tồn kho chủ yếu là nguyên vật liệu và thành phẩm phục vụ sửa chữa, chế tạo, luân chuyển tương đối tốt, rủi ro đọng vốn ở mức trung bình thấp.', 4, 'Công ty có kết quả kinh doanh năm 2017 giảm so với 2016 (doanh thu giảm 21%, lợi nhuận sau thuế tăng nhẹ 1.4%). Cơ cấu tài chính tương đối an toàn với tỷ lệ thanh toán nhanh đạt 1.0 lần. Hoạt động kinh doanh phụ thuộc lớn vào Tập đoàn mẹ, nhưng đây là đặc thù ngành. Ban lãnh đạo nhất quán, công ty được kiểm toán chấp nhận toàn phần. Triển vọng trung hạn ổn định nhưng tăng trưởng hạn chế do phụ thuộc vào ngành than.'),
('VMA_2016_consolidated', 'VMA', 2016, 'consolidated', 'Công ty có giao dịch mua bán rất lớn với các công ty trong cùng Tập đoàn Công nghiệp Than - Khoáng sản Việt Nam (TKV). Tổng giá trị bán hàng cho các bên liên quan lên tới hơn 360 tỷ VNĐ, chiếm phần lớn doanh thu. Tuy nhiên, đây là giao dịch thương mại thông thường trong chuỗi cung ứng của tập đoàn, chưa thấy rõ dấu hiệu chuyển giá hay rút vốn bất thường. Rủi ro tập trung vào sự phụ thuộc quá lớn vào một nhóm khách hàng liên quan.', 'Nợ phải trả chiếm tỷ trọng cao (gần 89 tỷ VNĐ nợ phải trả trên tổng tài sản 118 tỷ). Nợ ngắn hạn chiếm phần lớn (gần 88 tỷ), chủ yếu là phải trả người bán và các khoản phải nộp Nhà nước. Không có thông tin chi tiết về nợ vay ngân hàng, lãi suất hay tài sản thế chấp, nhưng áp lực thanh toán ngắn hạn là đáng kể. Tỷ lệ nợ/vốn chủ sở hữu ở mức cao (gần 3 lần).', 'Hàng tồn kho giảm mạnh từ 19.5 tỷ xuống 13.3 tỷ, chủ yếu do giảm nguyên vật liệu. Công ty đã trích lập dự phòng giảm giá hàng tồn kho 285 triệu VNĐ cho nguyên vật liệu. Hàng tồn kho chủ yếu là nguyên liệu, vật liệu và chi phí sản xuất dở dang, không có bất động sản hay dự án xây dựng dài hạn. Rủi ro đọng vốn ở mức vừa phải.', 7, 'Công ty có mối quan hệ kinh doanh chặt chẽ và phụ thuộc lớn vào Tập đoàn TKV, tạo ra rủi ro tập trung khách hàng. Cơ cấu tài chính đòn bẩy cao với nợ phải trả chiếm phần lớn nguồn vốn, gây áp lực lên khả năng thanh khoản ngắn hạn. Hoạt động kinh doanh có lợi nhuận nhưng biên lợi nhuận gộp chỉ khoảng 10%. Kiểm toán đưa ra ý kiến chấp nhận toàn phần. Ban lãnh đạo có sự nhất quán nhưng cơ cấu sở hữu liên quan đến tập đoàn lớn đặt ra thách thức về tính độc lập trong quản trị.'),
('VMA_2015_consolidated', 'VMA', 2015, 'consolidated', 'Công ty có giao dịch mua bán hàng hóa và dịch vụ lớn với nhiều công ty trong Tập đoàn Công nghiệp Than - Khoáng sản Việt Nam (TKV). Tổng giá trị giao dịch mua và bán lên tới hàng trăm tỷ đồng, đặc biệt phải thu từ Tập đoàn CN Than khoáng sản Việt Nam chiếm tỷ trọng lớn (68.485.931.313 VND). Điều này tiềm ẩn rủi ro bị chiếm dụng vốn nếu Tập đoàn gặp khó khăn thanh toán. Tuy nhiên, đây là hoạt động nội bộ tập đoàn phục vụ sản xuất kinh doanh cốt lõi.', 'Công ty không có nợ vay ngân hàng rõ ràng trong thuyết minh. Nợ phải trả chủ yếu là nợ phải trả người bán ngắn hạn (55.845.208.165 VND) và các khoản phải nộp Nhà nước, phải trả người lao động. Tỷ lệ nợ phải trả trên tổng tài sản ở mức cao (khoảng 73,5%), chủ yếu là nợ ngắn hạn tạo áp lực thanh toán. Công ty có quỹ phát triển khoa học công nghệ 480 triệu VND là nợ dài hạn duy nhất nhưng không có thông tin về lãi suất và tài sản đảm bảo.', 'Hàng tồn kho giảm từ 21.832.885.543 VND đầu năm xuống 19.487.517.801 VND cuối năm. Dự phòng giảm giá hàng tồn kho đầu năm (1.305.996.057 VND) đã được hoàn nhập, cho thấy hàng tồn kho đã được xử lý. Chi phí sản xuất kinh doanh dở dang chiếm tỷ trọng lớn (12.435.472.116 VND), cần theo dõi tiến độ sản xuất để tránh đọng vốn quá lâu.', 5, 'Công ty hoạt động trong lĩnh vực cơ khí, sản xuất ô tô thuộc Tập đoàn TKV. Doanh thu và lợi nhuận tăng trưởng tốt (doanh thu thuần tăng 14,4%, lợi nhuận sau thuế tăng 15,5%). Tuy nhiên, áp lực nợ phải trả ngắn hạn lớn, đặc biệt là nợ phải trả người bán và khoản phải thu từ Tập đoàn TKV chiếm tỷ trọng cao. Hàng tồn kho được kiểm soát tốt. Ý kiến kiểm toán chấp nhận toàn phần. Công ty có cơ cấu cổ đông rõ ràng với Tập đoàn TKV và Công ty Ngoại thương Kamaz là cổ đông lớn. Triển vọng trung hạn phụ thuộc vào tình hình hoạt động của Tập đoàn TKV và ngành than.'),
('VLW_2025_consolidated', 'VLW', 2025, 'consolidated', 'Các giao dịch với bên liên quan chủ yếu là chi trả cổ tức cho cổ đông lớn và mua nước sạch từ công ty liên kết. Giao dịch mua nước sạch từ Công ty Cổ phần Nước và Môi trường Cửu Long có giá trị lớn (8,3 tỷ VND) nhưng phản ánh hoạt động sản xuất kinh doanh cốt lõi. Chưa có dấu hiệu giao dịch bất thường hay rút vốn.', 'Nợ vay dài hạn chiếm tỷ trọng đáng kể trong tổng tài sản, với lãi suất thấp (0.3% và 7%/năm) và thời gian đáo hạn trải dài. Tuy nhiên, tổng nợ phải trả (133 tỷ VND) so với vốn chủ sở hữu (493 tỷ VND) cho thấy tỷ lệ nợ/vốn ở mức hợp lý (khoảng 0.27 lần). Áp lực trả nợ ngắn hạn (10.3 tỷ VND) được kiểm soát tốt do có dòng tiền hoạt động kinh doanh mạnh.', 'Hàng tồn kho chủ yếu là nguyên vật liệu, công cụ dụng cụ và chi phí sản xuất dở dang, không có dự án bất động sản. Giá trị tồn kho ổn định và không trích lập dự phòng giảm giá, cho thấy rủi ro đọng vốn thấp.', 4, 'Công ty có nền tảng tài chính vững chắc với doanh thu và lợi nhuận ổn định từ hoạt động cốt lõi cấp nước. Cấu trúc vốn an toàn, dòng tiền hoạt động kinh doanh dồi dào (60 tỷ VND) đủ để phục vụ đầu tư và trả nợ. Ban lãnh đạo nhất quán và không có giao dịch bên liên quan bất thường. Tuy nhiên, doanh nghiệp phụ thuộc vào chính sách giá nước do nhà nước phê duyệt và đầu tư vào các công ty liên kết cần được theo dõi. Triển vọng trung hạn tích cực.'),
('VLW_2023_consolidated', 'VLW', 2023, 'consolidated', 'Các giao dịch với bên liên quan chủ yếu là chi trả cổ tức cho các cổ đông lớn (Địa phương, doanh nghiệp nhà nước) và giao dịch mua bán nước sạch với công ty liên kết Công ty Cổ phần Nước và Môi trường Cửu Long có giá trị lớn (7.4 tỷ đồng) nhưng thuộc hoạt động kinh doanh cốt lõi. Không phát hiện dấu hiệu rút vốn, chuyển giá hay giao dịch bất thường.', 'Nợ vay ở mức rất thấp so với vốn chủ sở hữu (tỷ lệ nợ/VCSH ~0.056). Phần lớn nợ vay là vay ưu đãi từ Ngân hàng Phát triển Việt Nam với lãi suất cực thấp 0.3%/năm, thời hạn dài, tài sản đảm bảo là tài sản cố định. Áp lực trả nợ ngắn hạn và dài hạn đều thấp.', 'Hàng tồn kho chủ yếu là nguyên vật liệu phục vụ sản xuất nước sạch, có giá trị tương đối nhỏ và không trích lập dự phòng. Các dự án xây dựng dở dang (bể chứa, tuyến ống, mở rộng nhà máy) đang trong quá trình triển khai, có mô tả chi tiết và tiến độ bình thường, rủi ro đọng vốn thấp.', 3, 'Công ty có sức khỏe tài chính rất lành mạnh, hoạt động kinh doanh chính (cấp nước) ổn định với biên lợi nhuận gộp cao (~65%). Cơ cấu cổ đông rõ ràng, nợ vay thấp và được ưu đãi, ban lãnh đạo nhất quán, công tác quản trị minh bạch. Triển vọng đầu tư trung và dài hạn tích cực.'),
('VLW_2022_consolidated', 'VLW', 2022, 'consolidated', 'Giao dịch với các bên liên quan chủ yếu là chi trả cổ tức cho cổ đông lớn và giao dịch mua bán nước sạch với công ty liên kết. Các giao dịch này mang tính chất kinh doanh thông thường, không thấy dấu hiệu bất thường hay chuyển giá.', 'Nợ vay chỉ có một khoản vay dài hạn từ Ngân hàng Phát triển Việt Nam với lãi suất ưu đãi 0,3%/năm cho dự án đầu tư. Tài sản thế chấp là tài sản cố định hữu hình. Tỷ lệ nợ trên tổng tài sản và vốn chủ sở hữu ở mức thấp, áp lực trả nợ không đáng kể.', 'Hàng tồn kho bao gồm nguyên vật liệu, công cụ dụng cụ, chi phí sản xuất dở dang và thành phẩm. Không có trích lập dự phòng giảm giá. Các dự án xây dựng dở dang đang trong tiến độ triển khai, chưa thấy dấu hiệu đình trệ hay chậm tiến độ.', 3, 'Doanh nghiệp có sức khỏe tài chính tốt với lợi nhuận tăng trưởng ổn định, tỷ suất lợi nhuận gộp cao. Nợ vay thấp và có ưu đãi lãi suất. Cơ cấu cổ đông rõ ràng, quản trị minh bạch. Tuy nhiên, doanh nghiệp phụ thuộc vào hoạt động sản xuất kinh doanh nước sạch và có giao dịch với công ty liên kết nhưng không đáng lo ngại. Triển vọng đầu tư trung và dài hạn tích cực.'),
('VLW_2024_consolidated', 'VLW', 2024, 'consolidated', 'Giao dịch với bên liên quan minh bạch và mang tính hoạt động cốt lõi: mua nước sạch từ công ty liên kết Cửu Long (7.55 tỷ VNĐ) phục vụ sản xuất kinh doanh, nhận cổ tức từ hai công ty liên kết (tổng 2.4 tỷ VNĐ). Chi trả cổ tức cho hai cổ đông lớn UBND tỉnh Vĩnh Long (51%) và Xây lắp - Điện Biwase (33.65%) với tổng 39.68 tỷ VNĐ. Có khoản phải trả ngắn hạn cho Công ty Cửu Long 662 triệu VNĐ. Không phát hiện giao dịch bất thường, cho vay không lãi suất hay chuyển giá.', 'Tổng nợ vay 57.3 tỷ VNĐ trên vốn chủ sở hữu 476.7 tỷ VNĐ, tỷ lệ nợ/vốn chủ sở hữu chỉ 0.12 lần - rất an toàn. Khoản vay NHPT lãi suất ưu đãi 0.3%/năm đáo hạn tháng 3/2028, khoản vay Quỹ ĐTPT tỉnh lãi suất 7%/năm kỳ hạn 10 năm. Tổng chi phí lãi vay năm 2024 chỉ 64.7 triệu VNĐ. Thời gian trả nợ được phân bổ đều (10.3 tỷ trong năm 1, 10.3 tỷ năm 2, 23 tỷ năm 3-5, 13.7 tỷ sau năm 5). Áp lực trả nợ thấp.', 'Hàng tồn kho 11.98 tỷ VNĐ giảm từ 18.64 tỷ đầu năm, chủ yếu là nguyên vật liệu (9.3 tỷ), không trích lập dự phòng giảm giá. Hàng tồn kho luân chuyển tốt, giảm 35.7% so với đầu năm. Chi phí xây dựng cơ bản dở dang 44.7 tỷ VNĐ tăng mạnh từ 18.8 tỷ đầu năm, tập trung vào dự án mở rộng nhà máy nước Vũng Liêm, đang triển khai tích cực với tiến độ giải ngân 72.7 tỷ trong năm, rủi ro đọng vốn thấp.', 3, 'Công ty Cổ phần Cấp nước Vĩnh Long (VLW) là doanh nghiệp Nhà nước cổ phần hóa với 51% vốn thuộc UBND tỉnh Vĩnh Long, hoạt động trong lĩnh vực cấp nước đặc quyền. Năng lực tài chính rất lành mạnh: tỷ lệ nợ/vốn chủ sở hữu chỉ 0.12 lần, biên lợi nhuận gộp ~64%, dòng tiền hoạt động kinh doanh thuần đạt 98.2 tỷ VNĐ, chi phí lãi vay cực thấp (64.7 triệu). Công ty đang mở rộng đầu tư hạ tầng cấp nước (dự án Vũng Liêm 43 tỷ), tăng trưởng doanh thu thuần 4.4%. Ý kiến kiểm toán chấp nhận toàn phần. Có thay đổi nhân sự ban lãnh đạo (Tổng Giám đốc mới bổ nhiệm tháng 2/2025). Cổ tức năm 2023 tỷ lệ 16.22%, dự kiến tối thiểu 9% năm 2024. Triển vọng đầu tư ổn định, phù hợp nhà đầu tư tìm kiếm cổ tức bền vững.'),
('VLW_2021_consolidated', 'VLW', 2021, 'consolidated', 'Giao dịch với công ty liên kết chủ yếu là mua nước sạch và nhận cổ tức, phù hợp với hoạt động kinh doanh cốt lõi. Các giao dịch với cổ đông lớn là chi trả cổ tức theo quy định, không có dấu hiệu bất thường hay chuyển giá.', 'Nợ vay chủ yếu từ Ngân hàng Phát triển Việt Nam với lãi suất ưu đãi 0.3%/năm, được đảm bảo bằng tài sản cố định. Tỷ lệ nợ trên tổng tài sản thấp, áp lực trả nợ không cao do lịch trả nợ được phân bổ đều đặn.', 'Hàng tồn kho bao gồm nguyên vật liệu và thành phẩm có tính thanh khoản tốt, không trích lập dự phòng giảm giá. Chi phí xây dựng dở dang liên quan đến các dự án cấp nước đang triển khai đúng tiến độ, rủi ro đọng vốn thấp.', 2, 'Doanh nghiệp có kết quả kinh doanh tăng trưởng ổn định, tỷ suất lợi nhuận gộp cao trên 64%. Cơ cấu tài chính lành mạnh với nợ vay thấp, dòng tiền từ hoạt động kinh doanh dương mạnh. Ban lãnh đạo nhất quán và công tác kiểm toán đạt ý kiến chấp nhận toàn phần. Triển vọng đầu tư trung hạn khả quan.'),
('VLW_2020_consolidated', 'VLW', 2020, 'consolidated', 'Giao dịch mua nước sạch với Công ty CP nước và Môi trường Cửu Long (công ty liên kết) có giá trị lớn (hơn 7,8 tỷ VND) nhưng thuộc hoạt động kinh doanh cốt lõi và có giá trị giảm so với năm trước. Công ty cũng nhận cổ tức từ các công ty liên kết này. Số dư nợ phải trả với đối tượng này đã giảm mạnh. Nhìn chung, giao dịch có vẻ minh bạch, chưa phát hiện dấu hiệu chuyển giá bất thường.', 'Công ty có cơ cấu nợ vay tập trung vào một chủ nợ duy nhất là Ngân hàng Phát triển Việt Nam (ngân hàng nhà nước) với lãi suất vay ưu đãi rất thấp (0.3%/năm cho khoản vay trong hạn). Tổng nợ vay (ngắn và dài hạn) chiếm tỷ trọng nhỏ trên tổng tài sản (khoảng 8%). Áp lực trả nợ thấp, thời gian ân hạn dài (36 tháng). Tài sản thế chấp là tài sản hình thành từ vốn vay, không có tài sản thế cá nhân.', 'Hàng tồn kho chủ yếu là nguyên vật liệu và thành phẩm (nước sạch), luân chuyển nhanh, không có dự phòng giảm giá. Dự án xây dựng dở dang (chi phí XDCB dở dang) tập trung vào các công trình hạ tầng cấp nước chiến lược, tiến độ triển khai bình thường, không có dấu hiệu đọng vốn kéo dài.', 3, 'Doanh nghiệp có nền tảng tài chính vững chắc, là đơn vị cấp nước chủ lực của tỉnh Vĩnh Long với thị phần ổn định. Hoạt động kinh doanh cốt lõi tạo dòng tiền tốt, tỷ suất lợi nhuận gộp cao (trên 64%). Công ty có mức độ đòn bẩy tài chính rất thấp, thanh khoản dồi dào và quản trị rủi ro tốt. Ý kiến kiểm toán là chấp nhận toàn phần. Triển vọng đầu tư an toàn và ổn định, phù hợp với nhà đầu tư thận trọng.');
INSERT OR REPLACE INTO `financial_insights` (`id`, `ticker`, `year`, `report_type`, `related_party_risk`, `debt_risk`, `inventory_risk`, `governance_risk_score`, `overall_analysis`) VALUES
('VLW_2017_consolidated', 'VLW', 2017, 'consolidated', 'Các giao dịch với bên liên quan chủ yếu là mua nước sạch từ Công ty CP Nước và Môi trường Cửu Long và nhận cổ tức từ các công ty liên kết. Giá trị giao dịch mua nước sạch chiếm tỷ trọng nhỏ trong tổng doanh thu, còn giao dịch cổ tức là thu nhập từ đầu tư. Chưa thấy dấu hiệu bất thường hay chiếm dụng vốn lớn.', 'Nợ vay主要集中于Ngân hàng Phát triển Việt Nam với lãi suất ưu đãi 0.3%/năm cho các khoản vay dài hạn, tài sản thế chấp là tài sản hình thành từ vốn vay. Tổng nợ vay là 55.7 tỷ VNĐ, tỷ lệ nợ trên vốn chủ sở hữu khoảng 0.19 lần, áp lực trả nợ thấp do dòng tiền kinh doanh mạnh.', 'Hàng tồn kho bao gồm nguyên liệu, vật liệu và thành phẩm phục vụ sản xuất kinh doanh nước sạch, không có dự phòng giảm giá. Các dự án xây dựng dở dang như hồ chứa nước thô Vũng Liêm đang trong giai đoạn triển khai, chi phí tăng mạnh nhưng chưa có dấu hiệu đình trệ hay chậm tiến độ.', 3, 'Doanh nghiệp có sức khỏe tài chính tốt với biên lợi nhuận gộp cao (khoảng 56%), doanh thu tăng trưởng mạnh, nợ vay thấp và chủ yếu là nợ ưu đãi. Hoạt động kinh doanh cốt lõi ổn định, ban lãnh đạo nhất quán và không có giao dịch đáng ngờ với bên liên quan. Triển vọng đầu tư trung hạn khả quan do ngành cấp nước có nhu cầu ổn định.'),
('VLS_2025_consolidated', 'VLS', 2025, 'consolidated', 'Giao dịch mua bán hàng hóa với Công ty Cổ phần Thép tổng hợp (cổ đông lớn) có giá trị lớn (mua 292.8 tỷ VND, bán 145.9 tỷ VND). Công ty cũng mua hàng từ Công ty Cổ phần Thép Long Giang (cùng người quản lý) với giá trị 12.1 tỷ VND. Mặc dù giao dịch tập trung vào hoạt động kinh doanh cốt lõi, nhưng quy mô lớn với bên liên quan có thể tiềm ẩn rủi ro chuyển giá hoặc ưu đãi không công bằng. Cần theo dõi chặt chẽ tính minh bạch và điều kiện thị trường.', 'Tổng nợ vay ngắn hạn đạt 384.6 tỷ VND, chiếm tỷ trọng cao trên tổng tài sản, tạo áp lực thanh toán lớn. Lãi suất vay đa dạng và biến động theo thời điểm giải ngân, với một số khoản vay có lãi suất cố định như 7.9%/năm và 6.6%/năm. Tài sản thế chấp chủ yếu là bất động sản, tài sản cố định và tiền gửi có kỳ hạn. Áp lực chi phí lãi vay cao (26.0 tỷ VND trong năm) ảnh hưởng đến lợi nhuận.', 'Hàng tồn kho tăng mạnh từ 55.0 tỷ VND lên 158.6 tỷ VND, tập trung vào nguyên vật liệu (126.0 tỷ VND) và thành phẩm (25.0 tỷ VND). Chi phí xây dựng cơ bản dở dang (dự án xưởng mạ kẽm) trị giá 30.3 tỷ VND, cho thấy đầu tư mở rộng sản xuất. Tuy nhiên, mức tồn kho cao có thể dẫn đến đọng vốn và rủi ro giảm giá nếu nhu cầu thị trường giảm. Công ty không trích lập dự phòng giảm giá hàng tồn kho.', 5, 'Doanh nghiệp có sự tăng trưởng mạnh về doanh thu (tăng 73% so với năm trước) và lợi nhuận sau thuế (tăng gần 38 lần). Tuy nhiên, cấu trúc tài chính đòn bẩy cao với nợ vay lớn, đặc biệt là nợ ngắn hạn, gây áp lực thanh toán và chi phí lãi vay. Hàng tồn kho tăng nhanh có thể phản ánh tích trữ nguyên liệu để sản xuất nhưng cũng tiềm ẩn rủi ro. Ban lãnh đạo có giao dịch lớn với bên liên quan nhưng vẫn nằm trong hoạt động kinh doanh. Kiểm toán đưa ra ý kiến chấp nhận toàn phần, không có nghi ngờ về khả năng hoạt động liên tục. Triển vọng phụ thuộc vào khả năng quản lý dòng tiền và kiểm soát chi phí.'),
('VLS_2024_consolidated', 'VLS', 2024, 'consolidated', 'Giao dịch với Công ty Cổ phần Thép tổng hợp (cổ đông lớn) có giá trị rất lớn, đặc biệt là mua hàng hóa hơn 110 tỷ đồng. Công ty cũng bán hàng cho Công ty Cổ phần Long Giang (liên quan đến thành viên HĐQT). Các giao dịch này thuộc hoạt động kinh doanh cốt lõi nhưng cần đánh giá tính độc lập và giá cả thị trường. Có khoản vay cá nhân với Chủ tịch HĐQT và tạm ứng lớn cho thành viên HĐQT, tuy nhiên đã được hoàn trả trong năm.', 'Tổng nợ vay tài chính (ngắn hạn và dài hạn) đạt 306,5 tỷ VND, trong đó nợ ngắn hạn chiếm tỷ trọng cao (62%). Công ty sử dụng đòn bẩy tài chính lớn, chủ yếu vay từ các ngân hàng thương mại lớn (BIDV, Vietcombank, MB, VietinBank, Shinhan). Lãi suất vay dài hạn là 7.9%/năm, các khoản ngắn hạn lãi suất theo thỏa thuận. Áp lực trả nợ ngắn hạn đáng kể, cần theo dõi dòng tiền hoạt động kinh doanh. Tài sản thế chấp bao gồm quyền sử dụng đất, nhà xưởng, máy móc, hàng hóa và hợp đồng tiền gửi.', 'Hàng tồn kho tăng nhẹ từ 52 tỷ lên 55 tỷ đồng, chủ yếu là nguyên vật liệu (75%) và thành phẩm (21%). Không trích lập dự phòng giảm giá. Hàng tồn kho là thép và nguyên liệu sản xuất, chịu rủi ro biến động giá nguyên liệu đầu vào và thị trường bất động sản xây dựng. Dự án nhà máy sản xuất ống thép có chi phí dở dang rất nhỏ (39 triệu) so với tổng vốn đầu tư 322.8 tỷ, cho thấy dự án có thể đang trong giai đoạn đầu hoặc đã hạch toán phần lớn vào tài sản cố định.', 5, 'Công ty có quy mô vốn chủ sở hữu 245 tỷ đồng, tăng trưởng doanh thu mạnh (gấp đôi năm trước) đạt 600 tỷ, nhưng biên lợi nhuận gộp chỉ khoảng 4.5%, thấp hơn nhiều so với mặt bằng chung ngành thép. Lợi nhuận sau thuế giảm mạnh từ 3.17 tỷ xuống 306 triệu đồng do chi phí lãi vay tăng vọt (từ 10.7 tỷ lên 18.8 tỷ) và thuế TNDN tăng. Tỷ lệ nợ/Vốn chủ sở hữu đạt ~1.23 lần, áp lực tài chính cao. Công ty có mối quan hệ kinh doanh phức tạp với các bên liên quan, đặc biệt là cổ đông lớn và thành viên HĐQT. Ban lãnh đạo có sự thay đổi nhiều vị trí Tổng Giám đốc trong năm. Triển vọng ngắn hạn phụ thuộc vào khả năng kiểm soát chi phí tài chính và biến động giá nguyên liệu.'),
('VLP_2024_consolidated', 'VLP', 2024, 'consolidated', 'Giao dịch với Phòng quản lý đô thị TP. Vĩnh Long (doanh thu 18.5 tỷ VND, chiếm 34.4% doanh thu thuần) là giao dịch dịch vụ công ích thông thường, phù hợp với ngành nghề kinh doanh chính. Bên liên quan là cơ quan nhà nước cùng chủ sở hữu (UBND tỉnh Vĩnh Long chiếm 81.24% vốn). Phải thu từ bên liên quan tăng mạnh từ 2.5 tỷ lên 6.0 tỷ VND, cần theo dõi khả năng thu hồi. Tuy nhiên, chưa phát hiện dấu hiệu giao dịch bất thường hay chuyển giá.', 'Doanh nghiệp không có nợ vay ngân hàng hay trái phiếu. Tổng nợ phải trả chỉ 4.7 tỷ VND, chiếm 9.4% tổng tài sản và 9.4% vốn chủ sở hữu. Nợ chủ yếu là phải trả người lao động (1.7 tỷ), thuế phải nộp (934 triệu) và quỹ khen thưởng phúc lợi (1.05 tỷ) - đây là các khoản nợ thương mại thông thường. Áp lực trả nợ rất thấp, công ty có vị thế tiền mặt mạnh với 8.5 tỷ tiền và tương đương tiền cùng 9 tỷ đầu tư nắm giữ đến đáo hạn tại ngân hàng BIDV.', 'Hàng tồn kho ở mức rất thấp chỉ 325.9 triệu VND, giảm 36.6% so với đầu năm (514.2 triệu). Doanh nghiệp chủ yếu hoạt động trong lĩnh vực dịch vụ công ích (thu gom rác, vệ sinh môi trường) nên không có hàng tồn kho lớn. Không trích lập dự phòng giảm giá hàng tồn kho. Rủi ro đọng vốn vào hàng tồn kho không đáng kể.', 3, 'Công ty Cổ phần Công trình Công cộng Vĩnh Long có cấu trúc tài chính lành mạnh với tỷ lệ nợ rất thấp (9.4%), không vay nợ ngân hàng, thanh khoản tốt với hơn 17.5 tỷ VND tiền mặt và đầu tư ngắn hạn. Biên lợi nhuận gộp đạt 19.88% cho thấy hiệu quả kinh doanh tích cực. Tuy nhiên, doanh thu giảm mạnh 33.8% so với năm trước (từ 80.9 tỷ xuống 53.8 tỷ VND) là điểm đáng lưu ý, phản ánh sự sụt giảm quy mô hợp đồng dịch vụ công ích. Công ty chịu sự chi phối lớn của UBND tỉnh Vĩnh Long (81.24% vốn), hoạt động kinh doanh phụ thuộc nhiều vào hợp đồng với cơ quan nhà nước. Ý kiến kiểm toán chấp nhận toàn phần, không có vấn đề về hoạt động liên tục. Công ty hưởng ưu đãi thuế TNDN 10% từ hoạt động xã hội hóa lĩnh vực môi trường.'),
('VLP_2023_consolidated', 'VLP', 2023, 'consolidated', 'Giao dịch với Phòng Quản lý Đô Thị Thành phố Vĩnh Long chiếm tỷ trọng lớn trong doanh thu (khoảng 61% doanh thu thuần năm 2023), tạo ra rủi ro tập trung khách hàng cao. Tuy nhiên, mối quan hệ này mang tính chất dịch vụ công ích, có giảm giá dịch vụ nhưng không có dấu hiệu bất thường rõ rệt.', 'Doanh nghiệp không có nợ vay ngân hàng hay nợ thuê tài chính. Các khoản nợ phải trả chủ yếu là phải trả người bán và thuế, chiếm tỷ trọng thấp so với tổng tài sản và vốn chủ sở hữu. Áp lực thanh toán nợ ngắn hạn thấp, tính thanh khoản tốt.', 'Hàng tồn kho có giá trị nhỏ (tỷ lệ thấp so với tổng tài sản), không có dự phòng giảm giá. Hàng tồn kho bao gồm nguyên vật liệu và chi phí sản xuất dở dang, luân chuyển nhanh. Dự án xây dựng dở dang chủ yếu là mua sắm tài sản cố định, không có rủi ro đọng vốn lớn.', 3, 'Doanh nghiệp có cấu trúc tài chính lành mạnh, không có nợ vay, tỷ lệ nợ thấp. Dòng tiền hoạt động kinh doanh dương mạnh, tạo ra lượng tiền mặt lớn. Tuy nhiên, doanh thu phụ thuộc nhiều vào một khách hàng là cơ quan nhà nước (Phòng Quản lý Đô Thị). Ban lãnh đạo ổn định, không có giao dịch đáng ngờ với bên liên quan. Triển vọng kinh doanh ổn định trong trung hạn.'),
('VLP_2025_consolidated', 'VLP', 2025, 'consolidated', 'Giao dịch với các cơ quan nhà nước (Chi cục Môi trường, Phòng quản lý đô thị) chiếm tỷ trọng lớn trong doanh thu (khoảng 36.7%). Đây là hoạt động cung cấp dịch vụ công ích cốt lõi, thanh toán qua ngân sách nhà nước nên rủi ro thu hồi thấp. Tuy nhiên, phụ thuộc lớn vào một nhóm khách hàng liên quan.', 'Công ty không có nợ vay ngân hàng hay trái phiếu. Nợ ngắn hạn chủ yếu là phải trả người bán và thuế, không chịu áp lực lãi vay. Tỷ lệ nợ/VCSH rất thấp (khoảng 0.1 lần), cấu trúc tài chính an toàn.', 'Hàng tồn kho có giá trị nhỏ (372 triệu VND), chủ yếu là nguyên vật liệu và chi phí sản xuất dở dang, không có dự án bất động sản. Không trích lập dự phòng giảm giá. Rủi ro đọng vốn thấp.', 3, 'Doanh nghiệp hoạt động trong lĩnh vực dịch vụ công cộng, doanh thu ổn định nhưng lợi nhuận giảm mạnh năm 2025 do phát sinh khoản chi phí khác lớn (truy thu tiền thuê đất). Cơ cấu tài chính lành mạnh, không nợ vay, thanh khoản tốt (tiền gửi có kỳ hạn 10 tỷ). Ban lãnh đạo nhất quán, kiểm toán chấp nhận toàn phần. Rủi ro quản trị thấp.'),
('VLP_2022_consolidated', 'VLP', 2022, 'consolidated', NULL, NULL, NULL, 3, 'Văn bản chỉ chứa hợp đồng kiểm toán và thông tin công bố, không có dữ liệu tài chính chi tiết. Công ty đã chọn đơn vị kiểm toán cho năm 2022, cho thấy quy trình quản trị bình thường.'),
('VLP_2021_consolidated', 'VLP', 2021, 'consolidated', 'Giao dịch với Phòng quản lý đô thị TP. Vĩnh Long (cùng chủ sở hữu) chiếm tỷ trọng lớn trong doanh thu thuần (khoảng 69%). Đây là khách hàng chính cung cấp dịch vụ thu gom rác, vệ sinh môi trường. Mặc dù giao dịch là hoạt động kinh doanh cốt lõi và có giảm trừ doanh thu, nhưng sự phụ thuộc vào một bên liên quan duy nhất tạo ra rủi ro về doanh thu nếu có thay đổi trong chính sách hoặc hợp đồng.', 'Công ty không có nợ vay tài chính, nợ ngắn hạn chủ yếu là các khoản phải trả thông thường với tỷ lệ nợ/Vốn chủ sở hữu thấp (0,23 lần). Không có áp lực trả nợ vay, chi phí lãi vay không phát sinh. Rủi ro nợ vay thấp.', 'Hàng tồn kho có giá trị nhỏ, chủ yếu là nguyên liệu và chi phí sản xuất dở dang cho dịch vụ. Không có dự phòng giảm giá. Hàng tồn kho luân chuyển tốt do hoạt động kinh doanh chính là dịch vụ, không tích tụ hàng hóa. Rủi ro hàng tồn kho thấp.', 4, 'Doanh thu và lợi nhuận giảm mạnh trong năm 2021, một phần do ảnh hưởng của dịch COVID-19. Công ty có cấu trúc tài chính an toàn, không nợ vay, nhưng phụ thuộc lớn vào khách hàng liên quan là Phòng quản lý đô thị TP. Vĩnh Long. Ban lãnh đạo có sự thay đổi, ý kiến kiểm toán chấp nhận toàn phần nhưng có nhấn mạnh việc trình bày lại số liệu. Triển vọng phụ thuộc vào diễn biến dịch bệnh và hợp đồng với bên liên quan.'),
('VLP_2019_consolidated', 'VLP', 2019, 'consolidated', 'Giao dịch với Phòng quản lý đô thị TP. Vĩnh Long có giá trị lớn nhưng là khách hàng chính trong hoạt động cung cấp dịch vụ môi trường. Mối quan hệ thuộc diện đại diện vốn nhà nước, giao dịch công khai và không có dấu hiệu bất thường về giá hay điều kiện thanh toán.', 'Công ty không có nợ vay ngân hàng hay trái phiếu. Các khoản phải trả chủ yếu là phải trả người bán và chi phí phải trả ngắn hạn, quy mô nhỏ và được thanh toán nhanh. Áp lực trả nợ là không đáng kể.', 'Hàng tồn kho bao gồm nguyên vật liệu và chi phí sản xuất dở dang với giá trị thấp (dưới 200 triệu VND), không có dự phòng giảm giá. Rủi ro đọng vốn và mất giá là thấp.', 3, 'Công ty có tình hình tài chính lành mạnh, không nợ vay, dòng tiền hoạt động kinh doanh dương. Doanh thu tăng trưởng ổn định, tập trung vào dịch vụ môi trường có ưu đãi thuế. Ban lãnh đạo nhất quán, công ty có cổ đông chi phối là nhà nước. Rủi ro quản trị và tài chính ở mức thấp.'),
('VLP_2020_consolidated', 'VLP', 2020, 'consolidated', 'Giao dịch với Phòng quản lý đô thị TP. Vĩnh Long (cùng chủ sở hữu) chiếm tỷ trọng lớn trong doanh thu thuần (khoảng 82%), tạo rủi ro tập trung khách hàng và phụ thuộc vào cơ quan nhà nước. Các giao dịch lương thưởng với người quản lý ở mức hợp lý, không có dấu hiệu bất thường.', 'Doanh nghiệp không có nợ vay ngân hàng hay trái phiếu, áp lực trả nợ thấp. Nợ phải trả ngắn hạn chủ yếu là phải trả người lao động và thuế, không đáng lo ngại.', 'Hàng tồn kho nguyên vật liệu có giá trị thấp, không có dự phòng giảm giá. Chi phí xây dựng dở dang là mua sắm tài sản, rủi ro đọng vốn thấp.', 3, 'Doanh nghiệp có tình hình tài chính lành mạnh, không nợ vay, thanh khoản tốt. Doanh thu và lợi nhuận tăng trưởng ổn định. Tuy nhiên, rủi ro lớn nhất là phụ thuộc vào khách hàng duy nhất là Phòng quản lý đô thị TP. Vĩnh Long (cùng chủ sở hữu). Triển vọng trung hạn ổn định.');
INSERT OR REPLACE INTO `financial_insights` (`id`, `ticker`, `year`, `report_type`, `related_party_risk`, `debt_risk`, `inventory_risk`, `governance_risk_score`, `overall_analysis`) VALUES
('VLP_2018_consolidated', 'VLP', 2018, 'consolidated', 'Doanh thu tập trung cao vào một bên liên quan là Phòng quản lý đô thị TP. Vĩnh Long (chiếm khoảng 53.7% doanh thu thuần). Công ty phụ thuộc lớn vào cơ quan nhà nước, điều này tạo rủi ro về sự thay đổi trong chính sách hoặc ngân sách của đối tác.', 'Công ty không có nợ vay ngân hàng hay nợ thuê tài chính. Các khoản nợ phải trả chủ yếu là nợ thương mại ngắn hạn (phải trả người bán, thuế, phải nộp nhà nước). Tỷ lệ nợ trên vốn chủ sở hữu rất thấp (khoảng 0.21 lần), áp lực trả nợ không đáng kể.', 'Hàng tồn kho có giá trị nhỏ và chủ yếu là nguyên vật liệu, chi phí dở dang. Không trích lập dự phòng giảm giá hàng tồn kho. Rủi ro đọng vốn thấp.', 4, 'Doanh nghiệp hoạt động trong lĩnh vực dịch vụ môi trường và xây dựng công trình công ích, có sự tăng trưởng về doanh thu và lợi nhuận. Cấu trúc tài chính lành mạnh, không có nợ vay và dòng tiền từ hoạt động kinh doanh dương. Tuy nhiên, công ty phụ thuộc lớn vào một khách hàng là cơ quan nhà nước. Ban lãnh đạo và cơ cấu cổ đông ổn định, với cổ đông nhà nước chi phối.'),
('VLP_2017_consolidated', 'VLP', 2017, 'consolidated', 'Báo cáo ghi nhận ''Thông tin về các bên liên quan: không có'' về giao dịch bất thường. Tuy nhiên, Công ty có chi phí thù lao HĐQT, BKS hơn 1,1 tỷ đồng và lương ban lãnh đạo hơn 1,1 tỷ đồng trong năm, thuộc mức bình thường cho doanh nghiệp nhà nước chuyển đổi. Không phát hiện dấu hiệu rút vốn hay giao dịch chiếm dụng bất thường với bên liên quan.', 'Công ty không có bất kỳ khoản vay ngân hàng hay nợ thuê tài chính nào (cả ngắn hạn và dài hạn đều bằng 0). Các khoản nợ phải trả chủ yếu là phải trả người bán ngắn hạn với tổng số hơn 1,6 tỷ đồng và phải trả người lao động hơn 4,7 tỷ đồng. Áp lực trả nợ vay gần như không tồn tại, rủi ro nợ vay rất thấp.', 'Hàng tồn kho chỉ có giá trị 249 triệu đồng, rất nhỏ so với tổng tài sản 50,9 tỷ đồng. Bao gồm nguyên vật liệu (41 triệu) và chi phí SXKD dở dang (208 triệu) gồm công trình trồng hoa trang trí và lắp đặt đèn trang trí. Không trích lập dự phòng giảm giá, không có hàng tồn kho hư hỏng. Rủi ro đọng vốn từ hàng tồn kho không đáng kể.', 5, 'Công ty CP Công trình công cộng Vĩnh Long là doanh nghiệp có vốn nhà nước chi phối (~81%), hoạt động trong lĩnh vực dịch vụ công ích và xây lắp. Điểm đáng lưu ý nhất là Kiểm toán viên đã đưa ra ý kiến KIỂM TOÁN NGOẠI TRỪ do không thể xác nhận khoản phải thu khách hàng 29,9 tỷ đồng từ Phòng quản lý đô thị TP Vĩnh Long và khoản phải trả 1,2 tỷ đồng cho Công ty Phương Thảo. Rủi ro tín dụng tập trung vào một khách hàng lớn là cơ quan nhà nước. Tuy nhiên, Công ty có cơ cấu tài chính lành mạnh: không nợ vay ngân hàng, tỷ suất lợi nhuận gộp cao (~31,1%), dòng tiền hoạt động kinh doanh tuy âm nhưng do đặc thù thu chi lớn, và Công ty khẳng định khả năng hoạt động liên tục. Lợi nhuận sau thuế đạt 7,37 tỷ đồng, tăng vốn chủ sở hữu từ 33,9 tỷ lên 35,4 tỷ đồng.'),
('VLG_2025_consolidated', 'VLG', 2025, 'consolidated', 'Giao dịch với các bên liên quan (công ty mẹ, cùng tổng công ty, công ty liên kết) có quy mô lớn, chiếm tỷ trọng đáng kể trong doanh thu và chi phí. Các giao dịch này chủ yếu thuộc hoạt động mua bán nguyên vật liệu, cung cấp dịch vụ logistics trong hệ thống, chưa thấy dấu hiệu chuyển giá bất thường nhưng mức độ phụ thuộc vào hệ sinh thái là điểm cần lưu ý.', 'Công ty không có nợ vay dài hạn, nợ phải trả ngắn hạn chủ yếu là phải trả người bán (92.171 tỷ đồng) và các khoản phải trả khác, áp lực thanh toán ngắn hạn cao. Tuy nhiên, công ty có lượng tiền mặt và đầu tư ngắn hạn lớn (46.246 tỷ đồng) nên khả năng thanh toán vẫn được đảm bảo.', 'Hàng tồn kho dở dang chỉ có một dự án xây dựng cảng nội địa ICD Lào Cai với giá trị 1.241 tỷ đồng, tiến độ triển khai chậm, đang trong giai đoạn điều chỉnh hồ sơ. Rủi ro đọng vốn ở mức trung bình do dự án có quy mô lớn và thời gian triển khai kéo dài.', 5, 'Doanh nghiệp có kết quả kinh doanh sụt giảm mạnh trong năm 2025 do không còn ghi nhận khoản lợi nhuận lớn từ hoàn trả dự án như năm trước. Cơ cấu tài chính an toàn không có nợ vay dài hạn, thanh khoản tốt. Tuy nhiên, công ty có mức độ phụ thuộc lớn vào các giao dịch nội bộ trong hệ thống Tổng Công ty Hàng hải Việt Nam. Quản trị có một số thay đổi nhân sự cấp cao trong năm.'),
('VLG_2024_consolidated', 'VLG', 2024, 'consolidated', 'Giao dịch với bên liên quan chiếm tỷ trọng đáng kể trong hoạt động kinh doanh (doanh thu bán hàng ~13,6 tỷ VNĐ, mua hàng ~15,2 tỷ VNĐ). Các bên liên quan chủ yếu là công ty trong cùng hệ thống Vietnam Maritime Corporation (công ty mẹ). Các giao dịch thuộc hoạt động kinh doanh cốt lõi logistics và vận tải biển, chưa thấy dấu hiệu chuyển giá hay rút vốn bất thường. Tuy nhiên, công ty có khoản phải thu từ Vinalines Hoa Lac Logistics (324 triệu VNĐ) và khoản phải trả lớn cho VIMC Hai Phong Warehousing (3,29 tỷ VNĐ).', 'Công ty không có nợ vay ngân hàng hay trái phiếu, chỉ có nợ phải trả thương mại (37,4 tỷ VNĐ) với các đối tác kinh doanh thông thường. Tỷ lệ nợ ngắn hạn/Vốn chủ sở hữu ~0,29 lần, ở mức rất an toàn. Không có áp lực chi phí lãi vay. Công ty có khoản đặt cọc dài hạn 10 tỷ VNĐ theo Thông tư 05/2014/TT-BCT liên quan đến hàng tạm nhập tái xuất.', 'Công ty hoạt động trong lĩnh vực logistics dịch vụ nên không có hàng tồn kho truyền thống (nguyên vật liệu, thành phẩm). Dự án xây dựng dở dang duy nhất là dự án mở rộng ICD Lao Cai với giá trị nhỏ (1,24 tỷ VNĐ), đang trong giai đoạn chuẩn bị đầu tư. Dự án Cai Lan Port lớn trước đó đã được xử lý, công ty đã nhận bồi thường 35,28 tỷ VNĐ và hoàn trả tiền đặt cọc cho đối tác hợp tác kinh doanh.', 3, 'Doanh nghiệp có cấu trúc tài chính lành mạnh với lợi nhuận sau thuế tăng 184% so với năm trước (từ 10 tỷ lên 28,5 tỷ VNĐ). Công ty không có nợ vay, tỷ lệ nợ phải trả/VCSH thấp. Tuy nhiên, biên lợi nhuận gộp thấp (~4%) và lợi nhuận chủ yếu đến từ thu nhập khác (bồi thường dự án Cai Lan 35,28 tỷ VNĐ), điều này không bền vững. Hoạt động kinh doanh cốt lõi logistics có tăng trưởng doanh thu 27% nhưng lợi nhuận gộp mỏng. Ban lãnh đạo có biến động nhân sự trong năm 2024 (nhiều thành viên HĐQT, BKS bị miễn nhiệm và bổ sung mới). Kiểm toán viên đưa ra ý kiến chấp nhận toàn phần.'),
('VLG_2023_consolidated', 'VLG', 2023, 'consolidated', NULL, NULL, NULL, 3, NULL),
('VLG_2022_consolidated', 'VLG', 2022, 'consolidated', 'Công ty có cấu trúc sở hữu tập trung với Tổng công ty Hàng hải Việt Nam - CTCP nắm giữ 56.72% cổ phần. Giao dịch với các công ty cùng Tổng công ty và công ty liên kết có giá trị lớn: doanh thu từ bên liên quan đạt 17.87 tỷ VND (7.9% doanh thu), mua hàng từ bên liên quan đạt 17.42 tỷ VND. Đặc biệt, khoản phải thu từ Công ty TNHH Vinalines Honda Logistics Việt Nam giảm mạnh từ 2.47 tỷ xuống 995 triệu VND. Có khoản đặt cọc 5 tỷ VND từ Công ty CP Tập đoàn Việt Phát và các khoản phải trả 10 tỷ VND cho Công ty TNHH Happy Land Việt Nhật và 3 tỷ VND cho Công ty TNHH Tổ chức nhà quốc gia Quảng Ninh liên quan đến dự án Cái Lân - đã có Nghị quyết HĐQT về việc hoàn trả. Tổng thể, giao dịch với bên liên quan phức tạp nhưng chưa phát hiện dấu hiệu chuyển giá bất thường.', 'Nợ ngắn hạn tại ngày 31/12/2022 là 60.25 tỷ VND giảm so với mức 87.81 tỷ VND đầu kỳ, phản ánh công ty đã tích cực giảm đòn bẩy. Vay ngân hàng ngắn hạn giảm mạnh từ 14.55 tỷ xuống 7.15 tỷ VND chỉ còn duy nhất khoản vay tại IVB với lãi suất thả nổi, thời hạn 5.5 tháng. Tuy nhiên, tỷ lệ nợ/VCSH vẫn ở mức 0.43 lần - mức an toàn. Lãi vay phải trả trong năm 811.6 triệu VND giảm mạnh so với 2.4 tỷ VND năm trước. Chi phí lãi vay ngắn hạn phải trả cuối kỳ chỉ 29.6 triệu VND. Áp lực trả nợ ngắn hạn ở mức kiểm soát được.', 'Hàng tồn kho chủ yếu là chi phí xây dựng cơ bản dở dang với giá trị 35.24 tỷ VND, tăng so với đầu kỳ 31.56 tỷ VND. Dự án lớn nhất là Khu dịch vụ hậu cần cảng Cái Lân (34 tỷ VND) đã triển khai từ 2009 đến nay (13 năm) nhưng chưa hoàn thành, công ty đã dừng hợp tác kinh doanh với 2 đối tác và đang tìm kiếm đối tác mới theo chỉ đạo của Tổng công ty - cho thấy dự án bị đình trệ lâu dài, tiềm ẩn rủi ro đọng vốn và phải trích lập dự phòng giảm giá. Dự án ICD Lào Cai (1.24 tỷ VND) đã hoàn thành giai đoạn I, II nhưng giai đoạn III, IV đang chờ điều chỉnh hồ sơ. Dự án kho tại Láng Hòa Lạc đã được chuyển giao cho công ty liên kết và chuyển sang theo dõi dưới dạng phải thu.', 7, 'Năm 2022 là năm hoạt động kinh doanh suy giảm nghiêm trọng của VIMC Logistics: doanh thu giảm 63.7% (từ 622.3 tỷ xuống 225.9 tỷ VND), lợi nhuận gộp âm 2.13 tỷ VND, lỗ thuần từ HĐKD 16.08 tỷ VND và lỗ ròng sau thuế 22.77 tỷ VND. Nguyên nhân chính là do hoàn thành quyết toán các hợp đồng dịch vụ vận chuyển dự án điện gió lớn trong năm 2021. Chi phí quản lý doanh nghiệp tăng đột biến lên 15.74 tỷ VND do trích lập dự phòng nợ phải thu khó đòi 10.48 tỷ VND. Tiền mặt giảm 61.6% từ 37.8 tỷ xuống 14.5 tỷ VND. Tổng tài sản giảm 22.2% xuống 199 tỷ VND. Dự án Cái Lân triển khai 13 năm vẫn chưa hoàn thành, tiềm ẩn rủi ro lớn. Ban lãnh đạo có nhiều biến động với việc thay đổi Chủ tịch HĐQT và Tổng Giám đốc trong năm. Triển vọng ngắn hạn kém tích cực, cần theo dõi sát khả năng phục hồi kinh doanh và xử lý các dự án dở dang kéo dài.'),
('VLG_2021_consolidated', 'VLG', 2021, 'consolidated', 'Công ty có nhiều giao dịch với các bên liên quan thuộc cùng Tổng công ty Hàng hải Việt Nam, bao gồm mua bán dịch vụ logistics, nguyên vật liệu và nhận cổ tức từ công ty liên kết. Giá trị giao dịch lớn (doanh thu bán hàng 35,3 tỷ, mua hàng 25,1 tỷ) nhưng chủ yếu phục vụ hoạt động kinh doanh cốt lõi, chưa thấy dấu hiệu chuyển giá hay rút vốn bất thường.', 'Nợ vay ngắn hạn giảm mạnh từ 43,3 tỷ (01/01/2021) xuống 14,5 tỷ (31/12/2021), cho thấy áp lực trả nợ giảm. Các khoản vay đều là ngắn hạn (5,5-6 tháng) với lãi suất thả nổi, được thế chấp bằng tài sản. Tỷ lệ nợ/vốn chủ sở hữu ở mức thấp (~0,09 lần), thanh khoản tốt với tiền mặt 37,8 tỷ.', 'Công ty không có hàng tồn kho vật chất truyền thống. Các dự án xây dựng dở dang (chi phí xây dựng cơ bản dở dang) có tổng giá trị 31,6 tỷ, tập trung vào dự án cảng Cái Lân (30,8 tỷ). Dự án này đã triển khai từ 2009, hiện đang tìm đối tác hợp tác kinh doanh, có nguy cơ đọng vốn kéo dài nếu không thoái vốn hoặc hợp tác thành công.', 4, 'Công ty có kết quả kinh doanh tăng mạnh năm 2021 (doanh thu tăng 225%, lợi nhuận tăng 149%) nhờ khai thác dự án điện gió và dịch vụ logistics. Cấu trúc tài chính lành mạnh với nợ vay thấp, thanh khoản tốt. Rủi ro chính là dự án cảng Cái Lân dở dang nhiều năm và phụ thuộc lớn vào giao dịch với công ty mẹ/cùng tổng công ty. Ban lãnh đạo có biến động (Tổng Giám đốc miễn nhiệm). Ý kiến kiểm toán chấp nhận toàn phần.'),
('VLG_2020_consolidated', 'VLG', 2020, 'consolidated', 'Doanh nghiệp có nhiều giao dịch mua bán, dịch vụ với các công ty trong cùng Tổng công ty Hàng Hải Việt Nam (VIMC) và công ty liên kết (Vinalines Honda Logistics). Các giao dịch này chiếm tỷ trọng đáng kể trong doanh thu và giá vốn, nhưng đều thuộc hoạt động cốt lõi logistics. Tuy nhiên, sự phụ thuộc vào nhóm công ty mẹ có thể tạo rủi ro tập trung khách hàng/nhà cung cấp và ảnh hưởng đến tính độc lập trong kinh doanh.', 'Nợ vay ngắn hạn giảm từ 50.8 tỷ xuống còn 43.3 tỷ VND, chủ yếu vay từ hai ngân hàng thương mại lớn (Vietcombank, VIB) với lãi suất thả nổi. Tỷ lệ nợ vay ngắn hạn/Vốn chủ sở hữu là 0.26 lần, ở mức an toàn. Tuy nhiên, toàn bộ nợ đều đáo hạn dưới 1 năm, tạo áp lực tái tục vay thường xuyên. Tài sản thế chấp là tài sản cố định hữu hình có giá trị còn lại khoảng 48.6 tỷ VND.', 'Hàng tồn kho dở dang (chi phí xây dựng cơ bản dở dang) chiếm 31.5 tỷ VND, tập trung vào dự án bất động sản hậu cần cảng Cái Lân đã kéo dài từ 2009. Dự án này hiện chưa có dòng tiền thuần, đang tìm kiếm đối tác, tiềm ẩn rủi ro đọng vốn và suy giảm giá trị. Các dự án ICD Lào Cai và kho Láng Hòa Lạc quy mô nhỏ hơn.', 5, 'Công ty hoạt động trong lĩnh vực logistics, là công ty con của Tổng công ty Hàng Hải Việt Nam (nhà nước). Năm 2020, doanh thu giảm mạnh do tạm dừng nghiệp vụ tạm nhập tái xuất, nhưng lợi nhuận sau thuế tăng nhờ giảm chi phí và thu nhập cổ tức từ công ty liên kết. Nợ vay ngắn hạn ở mức kiểm soát, thanh khoản tốt. Rủi ro lớn nhất nằm ở hàng tồn kho dở dang là các dự án bất động sản kéo dài, chưa phát sinh doanh thu. Ban lãnh đạo có sự thay đổi lớn trong năm 2020. Ý kiến kiểm toán là chấp nhận toàn phần.'),
('VLG_2019_consolidated', 'VLG', 2019, 'consolidated', 'Công ty có quan hệ giao dịch lớn với nhiều đơn vị thuộc Tổng Công ty Hàng Hải Việt Nam (công ty mẹ). Đáng chú ý: (1) Phải trả Công ty Dịch vụ Hàng Hải Vinalines Hải Phòng lên tới 13.686.666.012 đồng, chiếm 14,7% tổng nợ phải trả ngắn hạn - liên quan đến chi phí thuê kho bãi tại khu vực 16,2ha đang lỗ nặng; (2) Phải thu Công ty TNHH Vinalines Honda Logistics Việt Nam (công ty liên kết) chiếm 7.284.574.158 đồng, quy mô lớn so với lợi nhuận sau thuế chỉ 2,3 tỷ đồng; (3) Giao dịch với Công ty mẹ liên quan đến cổ tức và chi phí dịch vụ. Các giao dịch này phần lớn mang tính thương mại, nằm trong chuỗi hoạt động logistics hàng hải, nhưng rủi ro tập trung tín dụng lớn vào các đơn vị trong Tập đoàn.', 'Tổng nợ vay ngắn hạn 50.801.848.357 đồng tại hai ngân hàng lớn (Vietcombank và VIB), tất cả là nợ ngắn hạn, không còn nợ dài hạn. Chi phí lãi vay 3.226.634.112 đồng chiếm tỷ trọng đáng kể so với lợi nhuận trước thuế 3.195.897.867 đồng. Tỷ lệ nợ vay/VCSH khoảng 0,31 lần ở mức an toàn. Tuy nhiên, việc tất cả nợ đều ngắn hạn với lãi suất thả nổi tạo rủi ro tái cấp vốn và biến động lãi suất. Tài sản thế chấp bao gồm xe đầu kéo, sơ mi ro mooc và quyền sử dụng đất.', 'Công ty không có hàng tồn kho trên bảng cân đối kế toán. Các dự án xây dựng cơ bản dở dang trị giá 31.490.671.406 đồng (tương đương 11,8% tổng tài sản), trong đó dự án Cảng Cái Lân chiếm 97,5%. Dự án kho bãi Container Logistics Quảng Ninh đã được xử lý giảm toàn bộ trong năm. Các dự án dở dang này chưa tạo ra doanh thu, tiềm ẩn rủi ro đọng vốn kéo dài nếu tiến độ triển khai không đảm bảo.', 6, 'Công ty Vinalines Logistics Việt Nam đang trải qua giai đoạn kinh doanh khó khăn với doanh thu giảm 51,4% và lợi nhuận sau thuế giảm 85,1% so với năm trước. Nguyên nhân chính là sụt giảm dịch vụ hàng tạm nhập tái xuất, kho ngoại quan đối với khách hàng Trung Quốc và lỗ 8,3 tỷ đồng tại kho bãi 16,2ha mới thuê lại. Lợi nhuận khác trước thuế từ hợp tác kinh doanh năm 2018 (10,6 tỷ đồng) không còn lặp lại. Công ty có cấu trúc tài sản lớn với tổng tài sản 267 tỷ đồng nhưng hiệu quả sinh lời thấp - biên lợi nhuận gộp chỉ 1,02%. Nợ vay ngắn hạn 50,8 tỷ đồng tạo áp lực chi phí lãi vay ăn mòn lợi nhuận. Dự án Cảng Cái Lân chiếm tỷ trọng lớn trong tài sản dở dang. Công ty thuộc hệ thống Tổng Công ty Hàng Hải Việt Nam (Tổng công ty nhà nước), chịu ảnh hưởng lớn từ định hướng chiến lược của Tập đoàn. Triển vọng phụ thuộc vào khả năng khai thác hiệu quả kho bãi mới và phục hồi dịch vụ TNTX.'),
('VLG_2018_consolidated', 'VLG', 2018, 'consolidated', 'Công ty có nhiều giao dịch với các bên liên quan như công ty mẹ, công ty liên kết và các đơn vị cùng tập đoàn, chủ yếu là mua bán dịch vụ logistics và vận tải. Các giao dịch được thực hiện theo giá thị trường, nhưng cần lưu ý các khoản phải thu lớn từ công ty liên kết (6.77 tỷ VND) và áp lực trả cổ tức cho công ty mẹ.', 'Nợ vay tập trung tại hai ngân hàng lớn (VCB và VIB) với lãi suất biến đổi và tài sản thế chấp rõ ràng (bất động sản, quyền sử dụng đất). Tỷ lệ nợ phải trả trên tổng tài sản là 36%, ở mức an toàn. Công ty có khả năng thanh toán nợ ngắn hạn nhờ tiền mặt tăng mạnh.', 'Công ty không có hàng tồn kho, nhưng có nhiều dự án xây dựng dở dang với tổng giá trị hơn 31.23 tỷ VND. Dự án Cảng Cái Lân đang chờ tìm kiếm đối tác, có nguy cơ chậm tiến độ và tích tụ chi phí. Các dự án khác chưa có thông tin tiến độ cụ thể.', 3, 'Công ty có tình hình tài chính ổn định với lợi nhuận sau thuế 15.37 tỷ VND, tăng nhẹ so với năm trước. Doanh thu giảm do hoạt động tạm nhập tái xuất giảm, nhưng biên lợi nhuận gộp cải thiện. Nợ vay giảm, tiền mặt tăng mạnh nhờ hoạt động kinh doanh tạo tiền tốt. Công ty có cơ cấu cổ đông rõ ràng, ban lãnh đạo nhất quán và kiểm toán unqualified. Tuy nhiên, công ty phụ thuộc vào hoạt động logistics và bất động sản, cần theo dõi tiến độ các dự án xây dựng.');
PRAGMA foreign_keys = ON;
